import React, { useState, useMemo, useEffect, useRef } from "react";

type ExamType = "mid1" | "mid2" | "final";
type Filter = "all" | "mid1" | "mid2" | "final";
type Screen = "home" | "quiz" | "score" | "review";

type Question = {
  id: string;
  exam: ExamType;
  lecture: string;
  q: string;
  options: string[];
  answer: number;
  explanation: string;
};

const MID1_QUESTIONS: Question[] = [
  {id:"mid11",exam:"mid1",lecture:"Introduction to Pharmacology",q:"What does pharmacokinetics (PK) refer to?",options:["What the drug does to the body","Mechanism of drug action","What the body does to the drug (Absorption, Distribution, Metabolism, Excretion)","Drug toxicity"],answer:2,explanation:"Pharmacokinetics = \"what the body does to the drug.\" It describes how the body absorbs, distributes, metabolizes, and excretes a drug (ADME). Pharmacodynamics is what the drug does to the body (mechanism of action, effects)."},
  {id:"mid12",exam:"mid1",lecture:"Introduction to Pharmacology",q:"Pharmacodynamics deals with:",options:["Absorption","Elimination","Metabolism","Mechanism of action"],answer:3,explanation:"Pharmacodynamics (PD) = \"what the drug does to the body\" — it deals with drug mechanisms of action, receptor binding, and the resulting pharmacological effects."},
  {id:"mid13",exam:"mid1",lecture:"Introduction to Pharmacology",q:"A drug marketed under its non-proprietary name is referred to as its:",options:["Chemical name","Generic name","Brand name","Trade name"],answer:1,explanation:"Every drug has three names. The chemical name describes the molecule's structure. The generic (non-proprietary/INN) name is the official approved name used universally. The brand (proprietary/trade) name is the manufacturer's commercial name. Generic drugs must have the same active ingredient and bioequivalence as the brand."},
  {id:"mid14",exam:"mid1",lecture:"Introduction to Pharmacology",q:"Generic drugs must have:",options:["Same active ingredient and bioequivalence","Same brand name","Same price","Same packaging"],answer:0,explanation:"By regulatory definition, a generic drug must contain the same active pharmaceutical ingredient and demonstrate bioequivalence (same rate and extent of absorption) as the branded reference product. Price and packaging may differ."},
  {id:"mid15",exam:"mid1",lecture:"Introduction to Pharmacology",q:"Phase I clinical trials primarily assess:",options:["Marketing","Efficacy","Comparison with placebo","Safety"],answer:3,explanation:"Clinical trials progress through four phases: - Phase I: First in human — small group of healthy volunteers — assesses safety, tolerability, dosing, pharmacokinetics. - Phase II: Efficacy in small patient group. - Phase III: Large RCT comparing to standard treatment. - Phase IV: Post-marketing surveillance."},
  {id:"mid16",exam:"mid1",lecture:"Introduction to Pharmacology",q:"Which drug category is absolutely contraindicated in ALL stages of pregnancy?",options:["Category A","Category B","Category C","Category X"],answer:3,explanation:"FDA pregnancy categories: - A: Adequate studies show no risk. - B: Animal studies show no risk; no adequate human studies. - C: Animal studies show adverse effects; no adequate human studies. - D: Evidence of human fetal risk, but benefits may outweigh risks. - X: Evidence of fetal abnormalities; risks clearly outweigh any benefit — absolutely contraindicated in all stages of pregnancy."},
  {id:"mid17",exam:"mid1",lecture:"Introduction to Pharmacology",q:"OTC (over-the-counter) drugs are:",options:["Can be obtained without a prescription","Only available by prescription","Experimental drugs","Controlled substances"],answer:0,explanation:"OTC drugs are safe and effective for use without medical supervision and can be purchased directly by the patient without a prescription. They differ from prescription-only medications which require a doctor's authorization."},
  {id:"mid18",exam:"mid1",lecture:"Introduction to Pharmacology",q:"Which of the following is an example of a genetic factor that affects drug response?",options:["Acetylation status","Drug physical properties","Renal failure","Lipid solubility of drug"],answer:0,explanation:"Pharmacogenetics studies how genetic variation affects drug response. Acetylation status (fast vs. slow acetylators) is a classic genetic polymorphism affecting metabolism of drugs like isoniazid. Renal failure is a pathological (not genetic) factor; drug physical properties and lipid solubility are drug-related factors."},
  {id:"mid19",exam:"mid1",lecture:"Introduction to Pharmacology",q:"Which of the following is the unwanted reaction NOT related to absorption or pharmacodynamics of drugs?",options:["Pharmaceutical interaction","Pharmacodynamic interaction","Pharmacokinetic interaction","None of the above"],answer:0,explanation:"Pharmaceutical (incompatibility) interactions occur outside the body — e.g., two drugs forming a precipitate when mixed in the same IV bag. These are not related to absorption or pharmacodynamic mechanisms."},
  {id:"mid110",exam:"mid1",lecture:"Drug Dosage Forms",q:"A solid dosage form that produces a high local drug concentration in the oral cavity is:",options:["Lozenge","Tablet","Capsule","Powder"],answer:0,explanation:"A lozenge (also called troche) is a flat, round, or rectangular solid dosage form that is held in the mouth and slowly dissolved. It is designed to produce a high local drug concentration in the oral cavity and throat (e.g., antiseptics, throat lozenges)."},
  {id:"mid111",exam:"mid1",lecture:"Drug Dosage Forms",q:"Which of the following best describes a lozenge?",options:["Capsule containing powder","Flat/round/rectangular tablet held in the mouth until dissolved","Effervescent tablet dissolved in water","Sustained-release tablet"],answer:1,explanation:"Lozenges are solid dosage forms that are held in the mouth (not swallowed) and dissolve slowly to produce a local effect in the oral cavity/pharynx. They are flat, round, or rectangular in shape."},
  {id:"mid112",exam:"mid1",lecture:"Drug Dosage Forms",q:"Ointments are classified as which type of dosage form?",options:["Solid","Liquid","Semi-solid","Gaseous"],answer:2,explanation:"Semi-solid dosage forms include ointments (W/O emulsions — greasy, more occlusive), creams (O/W emulsions — less greasy), gels, pastes, and suppositories. They are applied to skin or mucous membranes."},
  {id:"mid113",exam:"mid1",lecture:"Drug Dosage Forms",q:"Enteric-coated capsules dissolve in the:",options:["Stomach","Mouth","Intestine","Blood"],answer:2,explanation:"Enteric-coated formulations have a special coating that resists the acidic environment of the stomach and only dissolves in the alkaline environment of the small intestine. This protects acid-labile drugs (e.g., omeprazole) or drugs that irritate the gastric mucosa."},
  {id:"mid114",exam:"mid1",lecture:"Drug Dosage Forms",q:"Transdermal patches are mainly used for:",options:["Immediate effect","Diagnostic purpose","Sustained systemic effect","Local GI effect"],answer:2,explanation:"Transdermal patches deliver drugs through the skin into the systemic circulation in a slow, sustained manner, avoiding first-pass metabolism. Examples include nitroglycerin (angina), scopolamine (motion sickness), and nicotine (smoking cessation)."},
  {id:"mid115",exam:"mid1",lecture:"Drug Dosage Forms",q:"To prolong the duration of action of a drug, which modification is used?",options:["Increase vascularity of absorbing area","Reduction of solubility of the drug","Administration in aqueous solution","None"],answer:1,explanation:"Reducing the solubility of a drug (e.g., using a depot/suspension formulation for IM injection, or sustained-release tablet) slows dissolution and absorption, thereby prolonging the duration of action. Increasing vascularity would actually speed up absorption."},
  {id:"mid116",exam:"mid1",lecture:"Routes of Drug Administration",q:"A patient with extensive first-pass metabolism would benefit most from which route?",options:["Oral","Sublingual","Rectal","Intramuscular"],answer:1,explanation:"The sublingual route places the drug under the tongue where it is absorbed directly into the systemic circulation via sublingual veins, bypassing the portal circulation and hepatic first-pass metabolism. Nitroglycerin is the classic example — it has >90% first-pass extraction if swallowed, but is effective sublingually."},
  {id:"mid117",exam:"mid1",lecture:"Routes of Drug Administration",q:"The main advantage of the sublingual route is:",options:["Slow absorption","Local effect only","Prolonged duration","Bypasses first-pass metabolism"],answer:3,explanation:"Sublingual absorption occurs via the rich submucosal venous network that drains directly into the superior vena cava, circumventing hepatic first-pass metabolism. Additional advantages: rapid onset, drug action can be terminated by spitting out the tablet."},
  {id:"mid118",exam:"mid1",lecture:"Routes of Drug Administration",q:"A patient with severe post-operative pain requires morphine. Which route provides 100% bioavailability and the most rapid onset?",options:["Oral","Sublingual","Intravenous (IV)","Intramuscular"],answer:2,explanation:"IV administration gives 100% bioavailability (drug is directly placed into systemic circulation). It produces the most rapid onset of action, allows precise dose titration, and is preferred for emergencies, severe pain, unconscious patients, and drugs with extensive first-pass metabolism (e.g., morphine has significant first-pass if given orally)."},
  {id:"mid119",exam:"mid1",lecture:"Routes of Drug Administration",q:"Which route of administration is most suitable in emergencies?",options:["Intravenous","Oral","Rectal","Topical"],answer:0,explanation:"IV is the route of choice in emergencies because it: - Has 100% bioavailability - Provides immediate action - Allows rapid dose titration - Can be used in unconscious patients"},
  {id:"mid120",exam:"mid1",lecture:"Routes of Drug Administration",q:"Which route to administer oxytocin if it needs to be titrated according to patient's need?",options:["IM","IV infusion","IV bolus","Subcutaneous"],answer:1,explanation:"For drugs requiring titration (dose adjusted in real-time according to patient response), IV infusion is ideal because the rate can be increased or decreased instantly, and the drug effect is immediate. Oxytocin for labor induction is a classic example where the infusion rate is adjusted based on uterine contractions."},
  {id:"mid121",exam:"mid1",lecture:"Routes of Drug Administration",q:"Intramuscular (IM) injections are contraindicated in patients receiving:",options:["Anticoagulants","Steroids","Insulin","Antibiotics"],answer:0,explanation:"IM injections are contraindicated in anticoagulated patients because the needle insertion into a highly vascular muscle can cause bleeding into the muscle tissue (hematoma). Anticoagulants (warfarin, heparin) impair clotting, making this a significant risk."},
  {id:"mid122",exam:"mid1",lecture:"Routes of Drug Administration",q:"Which of the following properties allows a drug to cross the blood-brain barrier (BBB)?",options:["Lipid-soluble (lipophilic) and unionized","Hydrophilic and ionized","High molecular weight","High plasma protein binding"],answer:0,explanation:"The BBB is formed by tight junctions between cerebral capillary endothelial cells with no fenestrations. Only drugs that are: - Lipid-soluble (lipophilic) - Unionized (non-polar) - Small molecular weight - Not highly protein-bound ...can cross it by passive diffusion. Hydrophilic and ionized drugs are excluded."},
  {id:"mid123",exam:"mid1",lecture:"Routes of Drug Administration",q:"Some antibiotics are well absorbed but are NOT effective for brain infections because they have:",options:["High lipid solubility","Low bioavailability","High plasma protein binding","Rapid absorption"],answer:2,explanation:"Drugs that are highly protein-bound cannot cross the BBB because only the free (unbound) fraction can cross biological membranes. A highly protein-bound antibiotic may have good systemic absorption but inadequate CNS penetration because the bound drug is too large to cross and the free fraction is very small."},
  {id:"mid124",exam:"mid1",lecture:"Routes of Drug Administration",q:"Which combination of drug properties is LEAST likely to allow a drug to cross the placenta?",options:["Hydrophilic and high molecular weight","Hydrophilic and low molecular weight","Lipophilic and high molecular weight","Lipophilic and low molecular weight"],answer:0,explanation:"The placenta behaves like a lipid membrane. Drugs that easily cross the placenta are lipophilic, un-ionized, low molecular weight, and not highly protein bound. Therefore, hydrophilic + high molecular weight is the combination LEAST likely to cross and harm the fetus."},
  {id:"mid125",exam:"mid1",lecture:"Routes of Drug Administration",q:"An addict with tachycardia and tremor took one tablet of amphetamine. Amphetamine readily enters CNS and 50% is excreted unchanged. What explains the presentation?",options:["Reduced metabolism","Enhanced bioavailability","Enhanced penetration to CNS (lipophilicity)","Reduced elimination by kidney"],answer:2,explanation:"Amphetamine is highly lipophilic, allowing it to readily cross the BBB and enter the CNS. The CNS stimulation (dopamine/norepinephrine release) causes tachycardia, tremor, and agitation. The explanation is its lipophilic nature enabling enhanced CNS penetration."},
  {id:"mid126",exam:"mid1",lecture:"Pharmacodynamics",q:"Two drugs acting on the same receptor — Drug A has lower EC50 than Drug B, same Emax. Which is more potent?",options:["Drug B is more potent","Equal potency — same Emax","Drug A is more potent","Cannot be determined without Emax"],answer:2,explanation:"Potency is measured by the EC50 (the concentration producing 50% of the maximum effect). A lower EC50 = higher potency (you need less drug to produce the same effect). Both drugs have the same Emax (same efficacy). Drug A with lower EC50 is more potent."},
  {id:"mid127",exam:"mid1",lecture:"Pharmacodynamics",q:"ED50 — the dose producing 50% of the maximum effect — is a measure of:",options:["Mechanism of action","Therapeutic index","Potency","Efficacy"],answer:2,explanation:"ED50 (effective dose 50%) is the standard measure of potency. Lower ED50 = higher potency. Efficacy is measured by the Emax (maximum possible effect). The therapeutic index = TD50/ED50."},
  {id:"mid128",exam:"mid1",lecture:"Pharmacodynamics",q:"Drug A given at 5 mg decreases blood pressure the same as Drug B at 500 mg. What does this indicate?",options:["Drug A is more potent than Drug B by 100 times","Drug A produces a greater maximum effect than Drug B","Drug A has a higher therapeutic index than Drug B","Drug A is eliminated faster than Drug B"],answer:0,explanation:"Potency = dose needed to produce a given effect. Drug A needs 100× less drug → 100× more potent. This tells us nothing about maximum effect (efficacy) or safety margin."},
  {id:"mid129",exam:"mid1",lecture:"Pharmacodynamics",q:"2 mg of Drug A gives the same therapeutic effect as 200 mg of Drug B. Regarding potency:",options:["Information is not enough","Drug A is more potent than Drug B","Drug B is more potent than Drug A","Same potency"],answer:1,explanation:"Drug A requires 2 mg vs Drug B's 200 mg for the same effect → Drug A is 100× more potent. The therapeutic index is not relevant here — the question specifically asks about potency based on dose required for effect."},
  {id:"mid130",exam:"mid1",lecture:"Pharmacodynamics",q:"If an agonist can produce maximal effects and has high efficacy, it is called:",options:["Antagonist","Full agonist","Competitive antagonist","Partial agonist"],answer:1,explanation:"Drug classification by receptor interaction: - Full agonist: High affinity + high intrinsic activity/efficacy → produces MAXIMUM response (Emax) - Partial agonist: Affinity + INCOMPLETE intrinsic activity → cannot produce full Emax even at maximum doses - Antagonist: Affinity + NO intrinsic activity (efficacy = 0) → blocks without activating"},
  {id:"mid131",exam:"mid1",lecture:"Pharmacodynamics",q:"A partial agonist, when given alone, acts as an agonist. When given with a full agonist, what happens?",options:["Increases the effect of the full agonist","No change","Reduces the effect (acts as partial antagonist)","Doubles the effect"],answer:2,explanation:"Partial agonists have intermediate intrinsic activity. When given alone, they produce a submaximal response (agonist effect). When given together with a full agonist, they compete for the same receptor, displacing the full agonist and reducing the net response — this is why they act as functional antagonists in the presence of a full agonist."},
  {id:"mid132",exam:"mid1",lecture:"Pharmacodynamics",q:"A drug 'R' produces no response by itself but shifts the log dose-response curve of drug 'S' to the RIGHT in a PARALLEL manner WITHOUT decreasing maximal response. Drug 'R' is a:",options:["Inverse agonist","Noncompetitive antagonist","Partial agonist","Competitive antagonist"],answer:3,explanation:"The hallmark of a competitive (pharmacological) antagonist: - Binds the same receptor as the agonist - Produces no response alone (no intrinsic activity) - Causes a parallel rightward shift of the DRC - Does NOT decrease the Emax (surmountable — can be overcome by increasing agonist dose) A non-competitive antagonist also shifts right but decreases the Emax."},
  {id:"mid133",exam:"mid1",lecture:"Pharmacodynamics",q:"Competitive antagonist effect on dose-response curve:",options:["Parallel rightward shift, same Emax","Leftward shift","Decreased Emax only","No change in curve"],answer:0,explanation:"Competitive antagonists occupy the receptor reversibly, competing with the agonist. Increasing the agonist concentration can overcome the antagonism → same maximum effect (Emax) is achievable, but more agonist is needed (rightward shift = decreased apparent potency of agonist)."},
  {id:"mid134",exam:"mid1",lecture:"Pharmacodynamics",q:"If an agonist is given in increasing doses without producing any effect, which type of antagonism is most likely?",options:["Non-competitive antagonist","Competitive antagonist","Reversible antagonist","Irreversible antagonist"],answer:0,explanation:"A non-competitive antagonist binds to a different (allosteric) site or binds irreversibly, causing a decrease in Emax — meaning no matter how much agonist is given, the maximum effect cannot be achieved. The DRC flattens rather than shifts right."},
  {id:"mid135",exam:"mid1",lecture:"Pharmacodynamics",q:"Drugs act on the same organ but different receptors and cause effects OPPOSITE to each other. This is:",options:["Physiological (functional) antagonism","Chemical antagonism","Competitive antagonism","Pharmacological antagonism"],answer:0,explanation:"Physiological/functional antagonism = two drugs act on different receptors on the same tissue/organ but produce opposing effects. Example: histamine (bronchoconstriction via H1) vs. epinephrine (bronchodilation via β2) — they produce opposite effects on airways. This is different from pharmacological antagonism where both drugs bind the SAME receptor."},
  {id:"mid136",exam:"mid1",lecture:"Pharmacodynamics",q:"Which of the following best describes the concept of half-life (t½)?",options:["Time for complete elimination","Duration required for drug concentration to decrease by half","Time to peak effectiveness","Time for absorption"],answer:1,explanation:"The half-life (t½) is the time required for the plasma concentration (or total body amount) of a drug to decrease by 50% (one half). After 4-5 half-lives, ~97% of the drug is eliminated (considered complete elimination). t½ = 0.693 × Vd / Clearance."},
  {id:"mid137",exam:"mid1",lecture:"Pharmacodynamics",q:"The half-life of a drug is 3 hours. How long until it is completely eliminated?",options:["9 hr","12–15 hr (4–5 half-lives)","21 hr","4 hr"],answer:1,explanation:"A drug is considered completely eliminated after 4–5 half-lives (97–100%). For t½ = 3h: 4 × 3 = 12 hours to 5 × 3 = 15 hours. Therefore the answer is 12–15 hr."},
  {id:"mid138",exam:"mid1",lecture:"Pharmacodynamics",q:"Which of the following describes TACHYPHYLAXIS?",options:["Rapidly developing tolerance (acute tolerance occurring within minutes)","A synergism between two drugs","A drug with fast response","Drug interaction between similar drugs"],answer:0,explanation:"Tachyphylaxis = rapid, acute tolerance that develops within minutes to hours after administration. It is different from regular tolerance (which develops over days/weeks). Example: ephedrine loses effectiveness after repeated doses in quick succession."},
  {id:"mid139",exam:"mid1",lecture:"Pharmacodynamics",q:"Therapeutic index (TI) formula:",options:["ED50/TD50","TD50/ED50","LD50/ED50","EC50/TD50"],answer:1,explanation:"Therapeutic Index = TD50 / ED50 (or LD50/ED50 in animal studies). - TD50 = dose that is toxic in 50% of the population - ED50 = dose that is effective in 50% of the population - Larger TI = safer drug (e.g., penicillin has large TI) - Small TI = narrow safety margin (e.g., warfarin, digoxin, phenytoin — requires monitoring)"},
  {id:"mid140",exam:"mid1",lecture:"Pharmacodynamics",q:"Which parameter is used to indicate drug safety?",options:["Bioavailability","Intrinsic activity","Therapeutic index","Potency"],answer:2,explanation:"The therapeutic index measures the margin of safety between the therapeutic dose and the toxic dose. A wide TI means a drug can be dosed without much risk of toxicity; a narrow TI means doses must be carefully monitored."},
  {id:"mid141",exam:"mid1",lecture:"Pharmacodynamics",q:"A 14-year-old girl with allergic rhinitis is treated with loratadine (H₁ blocker). Which term best describes loratadine's BINDING to the H₁ receptor?",options:["Affinity","Potency","Maximal efficacy","Intrinsic activity"],answer:0,explanation:"Affinity = the tendency/ability of a drug to bind to a receptor (measured by Kd — dissociation constant; lower Kd = higher affinity). The question specifically asks about the characteristic of binding — this is affinity. Efficacy and intrinsic activity relate to what happens AFTER binding."},
  {id:"mid142",exam:"mid1",lecture:"Pharmacodynamics",q:"Which statement explains receptor affinity?",options:["Maximum response","Concentration of ligand that causes side effect","The measure of how tightly a ligand binds to a receptor","Fraction of dose reaching circulation"],answer:2,explanation:"Affinity is the strength of the drug-receptor interaction — how tightly the ligand binds. High affinity = drug binds even at low concentrations. It is quantified by the equilibrium dissociation constant (Kd); lower Kd = higher affinity."},
  {id:"mid143",exam:"mid1",lecture:"Pharmacodynamics",q:"A 9-year-old boy with asthma uses a β2-adrenoreceptor agonist by inhalation. What type of receptor is β2?",options:["G protein-coupled receptor (GPCR)","Intracellular receptor","Enzyme-linked receptor","Ligand-gated K⁺ channels"],answer:0,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. β2-adrenergic receptors belong to the G-protein coupled receptor (GPCR) family (also called 7-transmembrane receptors). They couple to Gs protein → activate adenylyl cyclase → ↑ cAMP → bronchodilation. Response time: seconds to minutes."},
  {id:"mid144",exam:"mid1",lecture:"Pharmacodynamics",q:"Which type of receptor is correctly associated with INSULIN?",options:["G protein-coupled receptor","Intracellular receptor","Enzyme-linked receptor (Receptor Tyrosine Kinase)","Ligand-gated receptor"],answer:2,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. The insulin receptor is a receptor tyrosine kinase (enzyme-linked receptor). When insulin binds, the receptor undergoes autophosphorylation and activates a kinase cascade. Response time: hours. This is distinct from GPCRs (muscarinic, β-adrenergic), ligand-gated channels (nicotinic), and nuclear receptors (steroids)."},
  {id:"mid145",exam:"mid1",lecture:"Pharmacodynamics",q:"Which one of the following is NOT a receptor?",options:["G-protein coupled receptor","Intercellular receptor","Enzyme-linked receptor","Plasma protein like albumin"],answer:3,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. Drug targets include receptors (GPCRs, ligand-gated channels, kinase-linked, nuclear), enzymes, ion channels, and carrier proteins. Plasma proteins like albumin are NOT receptors — they are transport/binding proteins that carry drugs in the blood. Binding to albumin inactivates the drug temporarily but produces no pharmacological effect."},
  {id:"mid146",exam:"mid1",lecture:"Pharmacodynamics",q:"An example of a G-protein coupled receptor:",options:["Nicotinic receptors (ligand-gated ion channel)","B2 adrenergic receptor","Insulin (enzyme-linked)","Steroid receptor (nuclear)"],answer:1,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. The four receptor types: 1. Ligand-gated ion channels (ionotropic): Nicotinic ACh receptor — milliseconds response 2. G-protein coupled receptors (metabotropic): Muscarinic ACh, β2-adrenergic, H1 histamine — seconds response 3. Kinase-linked receptors: Insulin, growth factor receptors — hours response 4. Nuclear receptors: Steroid hormones, thyroid hormone — hours response"},
  {id:"mid147",exam:"mid1",lecture:"Pharmacodynamics",q:"A study of three drugs: Drug A decreases receptor activity, Drug B increases receptor activity, Drug C antagonizes both A and B. What is Drug A?",options:["Inverse agonist","Partial agonist","Competitive antagonist","Irreversible antagonist"],answer:0,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. An inverse agonist has affinity for the receptor but produces the opposite effect to an agonist — it DECREASES baseline receptor activity below the constitutive level. Since Drug A decreases activity (opposite to Drug B which increases it) and Drug C blocks both, Drug A is an inverse agonist."},
  {id:"mid148",exam:"mid1",lecture:"Pharmacodynamics",q:"DRC graph showing four drugs — Drug D shows lower potency than Drugs A and C. Which statement is true?",options:["Drug A is less potent than C","Drug A has lower efficacy than B","Drug D shows lower potency than Drugs A and C","Drug D is best administered orally"],answer:2,explanation:"From a dose-response curve, potency is determined by the position of the curve along the x-axis (log concentration/dose). A curve that is further to the right indicates lower potency (more drug needed for same effect). Drug D being furthest right means lowest potency among A, C, and D."},
  {id:"mid149",exam:"mid1",lecture:"Pharmacodynamics",q:"What letter on the DRC graph represents PARTIAL AGONIST activity when given alone?",options:["A","B","C","D"],answer:1,explanation:"A partial agonist produces a submaximal response even at maximum concentrations — it cannot achieve the full Emax of a full agonist. On a DRC, it appears as a curve that plateaus at a lower maximum than the full agonist. Curve B reaching an intermediate plateau represents partial agonist behavior."},
  {id:"mid150",exam:"mid1",lecture:"Pharmacodynamics",q:"When two drugs bind to the same PLASMA PROTEIN binding site, what happens?",options:["Plasma concentration of displaced drug INCREASES → toxicity","Plasma concentration decreases → treatment failure","Plasma concentration increases → treatment failure","Plasma concentration decreases → toxic"],answer:0,explanation:"When two drugs compete for the same plasma protein binding site (e.g., albumin), the drug with higher affinity displaces the other. The displaced drug's free (unbound) plasma concentration suddenly increases → more drug available to act → risk of toxicity. Classic example: aspirin displaces warfarin from albumin → ↑ free warfarin → bleeding risk."},
  {id:"mid151",exam:"mid1",lecture:"Pharmacokinetics",q:"Bioavailability of a drug refers to:",options:["Ratio of oral to parenteral dose","Ratio of orally administered drug to that excreted in feces","Percentage of administered dose that reaches systemic circulation in unchanged form","Ratio of drug excreted unchanged to metabolites"],answer:2,explanation:"Bioavailability (F) = the fraction/percentage of an administered dose that reaches the systemic circulation in an unchanged (active) form. IV = 100% bioavailability. Oral bioavailability is <100% due to: incomplete absorption + first-pass metabolism."},
  {id:"mid152",exam:"mid1",lecture:"Pharmacokinetics",q:"What is the definition of bioavailability?",options:["Fraction of unchanged drug reaching systemic circulation","Proportion of drug reaching circulation in inactive form","Rate of drug absorption into the bloodstream","Volume in which the drug is distributed in the body"],answer:0,explanation:"Bioavailability is the fraction of unchanged (active) drug reaching systemic circulation, accounting for absorption and first-pass metabolism."},
  {id:"mid153",exam:"mid1",lecture:"Pharmacokinetics",q:"What is the expected effect of FIRST-PASS METABOLISM on bioavailability of an orally taken drug?",options:["Low bioavailability","High bioavailability","No effect","Variable"],answer:0,explanation:"After oral administration, drugs absorbed from the GI tract pass through the portal vein to the liver before reaching systemic circulation. The liver (and intestinal wall) metabolize a portion of the drug before it reaches its target — this is first-pass (presystemic) metabolism. The result is reduced bioavailability. Examples: morphine (first-pass >70%), nitroglycerin (>90%), propranolol."},
  {id:"mid154",exam:"mid1",lecture:"Pharmacokinetics",q:"A male patient with chronic liver AND renal disease is prescribed propranolol. What is the most appropriate dosing consideration?",options:["Extensive first-pass metabolism (dose must account for reduced metabolism)","Excreted by kidney — dose adjusted for kidney disease","Short half-life requiring once-daily dosing","Secreted in bile"],answer:0,explanation:"Propranolol is a drug with extensive first-pass metabolism in the liver. In a patient with chronic liver disease, first-pass metabolism is impaired → more drug reaches systemic circulation → risk of toxicity with usual oral doses. Additionally, reduced hepatic clearance prolongs its half-life. Dose reduction is required."},
  {id:"mid155",exam:"mid1",lecture:"Pharmacokinetics",q:"Majority of drugs cross biological membranes primarily by:",options:["Pinocytosis","Passive diffusion","Facilitated diffusion","Active transport"],answer:1,explanation:"Passive diffusion is the primary mechanism for most drugs to cross biological membranes. It follows a concentration gradient (high → low), requires no energy, and favors lipophilic, unionized, small molecular weight drugs. Active transport, facilitated diffusion, and pinocytosis account for a minority of drugs."},
  {id:"mid156",exam:"mid1",lecture:"Pharmacokinetics",q:"Diffusion of drugs across cell membranes is AFFECTED by:",options:["Exhibits saturation kinetics","Competitively inhibited by chemically related drugs","Dependent on metabolic activity","Affected by extent of ionization of drug molecules"],answer:3,explanation:"Passive diffusion of drugs across membranes depends on: - Lipid solubility (higher = more diffusion) - Degree of ionization (unionized form diffuses freely; ionized form cannot) - Molecular weight, concentration gradient Options A, B, C describe active transport (saturation, inhibition, energy-dependent)."},
  {id:"mid157",exam:"mid1",lecture:"Pharmacokinetics",q:"Which of the following defines DISTRIBUTION?",options:["The reversible movement of drug between blood and tissues","The irreversible elimination of drug","Drug metabolism in the liver","Excretion of unchanged drug"],answer:0,explanation:"Distribution is the reversible process by which a drug leaves the bloodstream and enters body tissues (and can return back to blood). It is quantified by the Volume of Distribution (Vd). Elimination is irreversible."},
  {id:"mid158",exam:"mid1",lecture:"Pharmacokinetics",q:"A drug with a LARGE volume of distribution (Vd) indicates:",options:["Drug stays in plasma","Excreted rapidly","Extensively distributed to tissues; low plasma concentration","Poorly absorbed"],answer:2,explanation:"Vd = Total Amount in Body / Plasma Concentration - Large Vd (e.g., >1 L/kg): Drug is extensively distributed to peripheral tissues → low plasma concentration relative to total body amount. The drug is \"hidden\" in tissues. - Small Vd: Drug stays mostly in plasma. Lipophilic drugs tend to have large Vd; drugs highly bound to plasma proteins tend to have small Vd."},
  {id:"mid159",exam:"mid1",lecture:"Pharmacokinetics",q:"Drugs that are HIGHLY BOUND to plasma proteins have:",options:["Large volume of distribution","High bioavailability","High renal clearance","Greater risk for drug interactions"],answer:3,explanation:"Highly plasma protein-bound drugs: - Have small Vd (not large — they stay in plasma) - Have low renal clearance (bound drug cannot be filtered) - Have low bioavailability is not directly related - Have greater risk for drug interactions because displacement from binding sites by another drug can suddenly increase the free (active) fraction → toxicity risk"},
  {id:"mid160",exam:"mid1",lecture:"Pharmacokinetics",q:"HIGH plasma protein binding makes a drug:",options:["Facilitate glomerular filtration","Minimize drug interaction","Long-acting (prolonged duration)","Increase Vd"],answer:2,explanation:"High protein binding: - Acts as a reservoir — bound drug is slowly released as free drug is eliminated → prolongs drug duration (longer-acting) - Bound drug is pharmacologically inactive - Bound drug cannot be filtered by the kidney → not easily excreted"},
  {id:"mid161",exam:"mid1",lecture:"Pharmacokinetics",q:"Drug A displaces Drug B from plasma proteins. What happens?",options:["Decreases effect of Drug B","Increases free fraction of Drug B → increases effect/risk of toxicity","No change","Increases protein binding of Drug B"],answer:1,explanation:"When Drug A displaces Drug B from plasma protein binding sites: - Drug B's free (unbound) fraction increases suddenly - Free drug = active drug - This can cause unexpected toxicity (e.g., aspirin displacing warfarin → ↑ free warfarin → ↑ bleeding risk)"},
  {id:"mid162",exam:"mid1",lecture:"Pharmacokinetics",q:"Which of the following is expected when warfarin (strongly protein-bound) is administered to a patient with SEVERE RENAL IMPAIRMENT?",options:["No significant change","Reduced efficacy of warfarin","Increased warfarin free level","Decreased warfarin free level"],answer:2,explanation:"In severe renal impairment: - Uremic toxins (retained waste products) accumulate in blood - These uremic compounds compete with warfarin for albumin binding sites - Warfarin is displaced from albumin → increased free (unbound) warfarin level → increased anticoagulant effect → bleeding risk"},
  {id:"mid163",exam:"mid1",lecture:"Pharmacokinetics",q:"Phase I metabolism involves:",options:["Oxidation, reduction, hydrolysis (non-synthetic reactions)","Conjugation only","Glucuronidation only","Synthesis reactions"],answer:0,explanation:"Drug metabolism occurs in two phases: - Phase I (non-synthetic): Oxidation, reduction, hydrolysis — primarily via CYP450 enzymes in the liver → makes drug more polar (water-soluble), often produces active or toxic metabolites - Phase II (synthetic): Conjugation reactions (glucuronidation, sulfation, acetylation) → produces highly polar, water-soluble, inactive metabolites ready for excretion"},
  {id:"mid164",exam:"mid1",lecture:"Pharmacokinetics",q:"What best describes BIOTRANSFORMATION?",options:["Converts lipid-soluble drug to a non-lipid-soluble metabolite","Converts the drug to a more lipid-soluble form","Increases drug binding affinity to its receptor","Prolongs drug half-life by reducing renal clearance"],answer:0,explanation:"Biotransformation converts lipophilic drugs to more polar (water-soluble) metabolites for renal excretion. Without this, lipophilic drugs would be reabsorbed endlessly in the renal tubule."},
  {id:"mid165",exam:"mid1",lecture:"Pharmacokinetics",q:"Regarding drug metabolism, which statement is CORRECT?",options:["Metabolism does not occur in plasma or kidneys","Prodrugs don't become active until they are metabolized","Enzyme induction increases drug toxicity potential","Most drugs are metabolized into active metabolites"],answer:1,explanation:"Prodrugs are pharmacologically inactive compounds that must undergo metabolic conversion to become active. Examples: codeine → morphine; enalapril → enalaprilat. This is a deliberate pharmaceutical strategy to improve bioavailability or targeting."},
  {id:"mid166",exam:"mid1",lecture:"Pharmacokinetics",q:"Rifampin induces CYP450 enzymes. What is the clinical consequence for a patient taking ORAL CONTRACEPTIVES?",options:["Increased estrogen levels","Contraceptive failure","No effect","Toxicity"],answer:1,explanation:"Rifampin is a potent CYP450 inducer — it increases the production of metabolizing enzymes. This leads to: - Faster metabolism of oral contraceptives - Reduced plasma levels of estrogen/progestin - Contraceptive failure (unintended pregnancy) This is Type F ADR (Failure of efficacy). Other CYP inducers: carbamazepine, phenytoin, tobacco."},
  {id:"mid167",exam:"mid1",lecture:"Pharmacokinetics",q:"In liver failure, which change is observed?",options:["Decreased drug half-life due to faster metabolism","Increased drug elimination via the kidney","Increased drug half-life and plasma accumulation","Decreased plasma drug concentration"],answer:2,explanation:"In liver failure: ↓ hepatic metabolism → ↑ half-life → drug accumulates in plasma. Also ↓ albumin synthesis → ↑ free drug fraction. Dosage reduction and monitoring are essential."},
  {id:"mid168",exam:"mid1",lecture:"Pharmacokinetics",q:"In liver failure, one of the following changes is observed: (Blackboard version)",options:["Microsomal enzyme activity is increased","Half-life of drug is reduced","Metabolism of drug is reduced","Increase in plasma protein binding"],answer:2,explanation:"Same as above — liver failure reduces the liver's ability to metabolize drugs → drug metabolism is reduced → drugs accumulate → toxicity risk. Half-life INCREASES (not decreases)."},
  {id:"mid169",exam:"mid1",lecture:"Pharmacokinetics",q:"Patient has hepatitis, cirrhosis, ascites — which drug must be carefully monitored?",options:["Erythromycin","Tobramycin","Penicillin G","Gentamicin"],answer:0,explanation:"Erythromycin is primarily metabolized by the liver (CYP3A4). In liver disease, its clearance is impaired → accumulation. Tobramycin, penicillin G, and gentamicin are renally excreted and do not require hepatic dose adjustment."},
  {id:"mid170",exam:"mid1",lecture:"Pharmacokinetics",q:"Zero-order kinetics:",options:["Constant AMOUNT of drug is eliminated per unit time (not dependent on concentration)","Constant fraction eliminated","Drug follows first-order kinetics","Half-life is constant"],answer:0,explanation:"Zero-order (saturation) kinetics: The elimination rate is constant regardless of concentration (enzymes are saturated). No constant t½. Drug accumulates non-linearly. Examples: phenytoin, ethanol, aspirin at high doses. First-order kinetics: Constant fraction eliminated per unit time → constant t½ → most drugs follow this."},
  {id:"mid171",exam:"mid1",lecture:"Pharmacokinetics",q:"Drug half-life increases in renal failure. What happens to renally excreted drugs?",options:["Faster elimination","No change","Renally excreted drugs accumulate → toxicity risk","Increased metabolism"],answer:2,explanation:"Renally excreted drugs depend on glomerular filtration and tubular secretion for elimination. In renal failure, filtration is impaired → reduced drug clearance → longer half-life → drug accumulation. This is especially important for drugs like digoxin, aminoglycosides, metformin (require dose reduction in renal failure)."},
  {id:"mid172",exam:"mid1",lecture:"Pharmacokinetics",q:"Which pathway is primarily used for drug elimination?",options:["Lungs (pulmonary excretion)","Kidney (renal excretion)","Bile/Feces","Skin/Sweat"],answer:1,explanation:"The kidney is the most important route of drug elimination — drugs and their metabolites are filtered at the glomerulus and excreted in urine. Other routes (bile/feces, lungs, skin) are secondary. Renal impairment therefore requires dose adjustment for renally-excreted drugs."},
  {id:"mid173",exam:"mid1",lecture:"Pharmacokinetics",q:"A highly polar drug given to a patient with renal failure would have:",options:["Reduced drug clearance","Accumulation of toxic metabolites only","Enhanced hepatic first-pass metabolism","Increased volume of distribution"],answer:0,explanation:"Polar drugs are renally excreted without significant reabsorption. In renal failure, GFR drops → reduced clearance → drug accumulates → increased toxicity risk."},
  {id:"mid174",exam:"mid1",lecture:"Pharmacokinetics",q:"Factors modifying drug ABSORPTION do NOT include:",options:["Rate of general circulation","Hepatic metabolism","Route of administration","Dissolution rate"],answer:1,explanation:"Hepatic metabolism is a factor affecting bioavailability (first-pass effect), but it occurs AFTER absorption — it does NOT modify the absorption process itself. Factors that modify absorption include: route of administration, drug solubility/dissolution, blood flow to absorption site, surface area, GI motility, pH."},
  {id:"mid175",exam:"mid1",lecture:"Pharmacokinetics",q:"Which patient-related factor affects DISTRIBUTION?",options:["Organ size and perfusion rate","Particle size","Dissolution","Formulation"],answer:0,explanation:"Distribution of a drug to tissues depends on patient factors including: - Organ size and blood perfusion (highly perfused organs like liver, kidney, brain receive drug first) - Plasma protein binding (patient-related — albumin levels) - Body composition (fat vs. lean mass) Particle size, dissolution, and formulation are drug-related factors affecting absorption, not distribution."},
  {id:"mid176",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"ADR Type A (Augmented) is best described as:",options:["Dose-independent, unpredictable","Dose-dependent, predictable, extension of pharmacological effect","Due to immune mechanism","Occurs only after long-term use"],answer:1,explanation:"Type A (Augmented) ADR: - Dose-dependent and predictable (an exaggeration of the drug's known pharmacological effect) - Most common type (>80% of all ADRs) - Preventable by dose reduction - Examples: Warfarin → bleeding, Beta-blockers → bradycardia, Insulin → hypoglycemia"},
  {id:"mid177",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A 60-year-old diabetic patient presents with sweating, dizziness, blood sugar 65. He took insulin before an unexpected encounter. What type of ADR is this?",options:["Type A","Type B","Type C","Type E"],answer:0,explanation:"Hypoglycemia from insulin is a Type A (Augmented) ADR — it is an extension of the pharmacological effect of insulin (lowering blood sugar), dose-dependent and predictable. The patient took the correct insulin but had an unexpected encounter (didn't eat), leading to hypoglycemia."},
  {id:"mid178",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A 67-year-old takes warfarin 12 mg/day (normal 5-10 mg/day) and presents with nasal bleeding. Type of ADR?",options:["Augmented (Type A)","Bizarre (Type B)","Chronic (Type C)","Delayed (Type D)"],answer:0,explanation:"Warfarin-induced bleeding at an above-normal dose is a Type A (Augmented) ADR — it is the direct, dose-dependent pharmacological extension of warfarin's anticoagulant effect. It is predictable and preventable."},
  {id:"mid179",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"Which is an example of an AUGMENTED adverse drug reaction?",options:["Bleeding and warfarin","Cushing syndrome and corticosteroids (Type C — chronic)","Anaphylaxis and penicillin (Type B — bizarre)","Peptic ulcer and NSAIDs (Type C — chronic)"],answer:0,explanation:"Warfarin-induced bleeding = Type A (dose-dependent extension of anticoagulant effect). Cushing syndrome from long-term corticosteroids = Type C (chronic). Anaphylaxis to penicillin = Type B (bizarre/immunological). NSAIDs peptic ulcer = Type C (chronic dose+time related)."},
  {id:"mid180",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A patient with rheumatoid arthritis takes NSAIDs. After 40 days, he develops vomiting, abdominal pain, and gastric ulcer. What type of ADR?",options:["Type A","Type C (Chronic)","Type B","Type F"],answer:1,explanation:"Type C (Chronic/Continuous) ADR: - Related to cumulative dose + time of administration - Develops with long-term use - Example: NSAIDs → peptic ulcer (COX-1 inhibition reduces prostaglandin-mediated gastric protection), Corticosteroids → Cushing's syndrome, Osteoporosis After 40 days of NSAID use → this is chronic, time-related → Type C."},
  {id:"mid181",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"Patient takes NSAIDs and gets gastric ulcer. Type of ADR?",options:["Type C","Type B","Type D","Type A"],answer:0,explanation:"Same as above — NSAID-induced gastric ulcer is Type C (Chronic) — develops with prolonged use, dose and time dependent."},
  {id:"mid182",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A patient takes an antibiotic for surgery. After succinylcholine (muscle relaxant) administration, the patient has temporary/prolonged paralysis. Type of ADR?",options:["Idiosyncratic (Type B)","Pseudoallergic","Allergic","Augmented"],answer:0,explanation:"Succinylcholine-induced prolonged paralysis is a Type B (Bizarre) ADR — specifically an idiosyncratic reaction due to a genetic variation in pseudocholinesterase (butyrylcholinesterase) enzyme. Normal individuals metabolize succinylcholine rapidly; patients with pseudocholinesterase deficiency (genetic) cannot → prolonged paralysis. It is not dose-dependent, not predictable in normal population."},
  {id:"mid183",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A newborn has a birth defect of the upper limb; the mother was taking thalidomide during pregnancy. Type of ADR?",options:["Type D (Delayed — teratogenesis)","Type C","Type B","Type F"],answer:0,explanation:"Type D (Delayed) ADR: Adverse effects that occur after treatment has ended, including: - Teratogenesis (birth defects — manifest after gestation) - Carcinogenesis - Other delayed effects Thalidomide caused phocomelia (limb defects) in infants whose mothers took it in the first trimester → classic Type D (teratogen)."},
  {id:"mid184",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"What is the mechanism of action of Co-trimoxazole (Sulfamethoxazole + Trimethoprim)?",options:["Inhibiting two sequential steps in the bacterial folate synthesis pathway","Inhibiting bacterial RNA polymerase","Inhibiting bacterial cell wall crosslinking","Inhibiting the 30S ribosomal subunit"],answer:0,explanation:"Double sequential blockade: sulfamethoxazole inhibits dihydropteroate synthase (step 1); trimethoprim inhibits dihydrofolate reductase (step 2) → synergistic inhibition of folate → ↓ DNA synthesis. Human cells use dietary folate and are spared."},
  {id:"mid185",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A drug taken in the first trimester causes limb defects. It is classified as:",options:["Category A","Category B","Teratogen (Category D or X)","Category C only"],answer:2,explanation:"A drug causing limb defects in the 1st trimester is a teratogen. Category D has evidence of fetal risk but benefits may outweigh risks in severe disease. Category X is absolutely contraindicated (risks always outweigh benefits). Either way, such a drug is a teratogen."},
  {id:"mid186",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"A 27-year-old becomes pregnant. She was taking warfarin (FDA Category D) and amoxicillin (FDA Category B). As her physician, what should you do?",options:["Keep warfarin, change amoxicillin to a different antibiotic","Keep amoxicillin, switch warfarin to a safer anticoagulant","Continue both drugs unchanged throughout pregnancy","Discontinue both drugs immediately without replacement"],answer:1,explanation:"Warfarin (Category D) causes embryopathy and fetal hemorrhage — must be replaced with LMWH heparin (does not cross placenta). Amoxicillin (Category B) is safe in pregnancy."},
  {id:"mid187",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"IDIOSYNCRASY is:",options:["A type of antagonism","A type B adverse effect (genetic/unusual reaction)","Normal pharmacological response","Tolerance"],answer:1,explanation:"Idiosyncrasy = a genetically-determined abnormal/unusual response to a drug. It is classified as a Type B (Bizarre) ADR. It is not dose-related, not predictable from pharmacology, and occurs in individuals with specific genetic variations (e.g., G6PD deficiency → hemolysis with primaquine; pseudocholinesterase deficiency → prolonged succinylcholine paralysis)."},
  {id:"mid188",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"An asthmatic patient is given a non-selective β-agonist to relieve bronchoconstriction. What adverse effect would you expect?",options:["Tachycardia","Bradycardia","Hypotension","Bronchoconstriction"],answer:0,explanation:"A non-selective β-agonist stimulates both: - β1 receptors (cardiac) → tachycardia and palpitations (unwanted) - β2 receptors (bronchial) → bronchodilation (desired effect) Selective β2-agonists (salbutamol) are preferred in asthma to avoid cardiac side effects."},
  {id:"mid189",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"Which of the following is a common adverse effect of AMPHETAMINES?",options:["Bradycardia","Somnolence","Constipation","Hypertension"],answer:3,explanation:"Amphetamines are sympathomimetics that release norepinephrine and dopamine. Their typical adverse effects reflect sympathetic stimulation: hypertension, tachycardia, hyperthermia, tremor, insomnia, agitation. NOT bradycardia or somnolence."},
    {id:"mid191",exam:"mid1",lecture:"Factors Affecting Drug Response & Adverse Drug Reactions (ADR)",q:"Which of the following is LEAST likely to pass through the placenta and harm the fetus?",options:["Hydrophilic and high molecular weight","Hydrophilic and low molecular weight","Lipophilic and high molecular weight","Lipophilic and low molecular weight"],answer:0,explanation:"The placental barrier behaves like a lipid membrane. Drugs that cross most easily are: lipophilic, low molecular weight, un-ionized, not highly protein-bound. Conversely, hydrophilic + high molecular weight = LEAST likely to cross the placenta and harm the fetus."},
    {id:"mid193",exam:"mid1",lecture:"Drug-Drug Interactions",q:"Warfarin taken with CIPROFLOXACIN causes:",options:["Hypoglycemia","No interaction","Reduced bleeding","Increased bleeding risk"],answer:3,explanation:"Ciprofloxacin is a CYP450 inhibitor (specifically CYP1A2 and partially CYP2C9). It inhibits the metabolism of warfarin → increased warfarin plasma levels → increased anticoagulant effect → bleeding risk. This is a pharmacokinetic (enzyme inhibition) drug interaction."},
  {id:"mid194",exam:"mid1",lecture:"Drug-Drug Interactions",q:"RIFAMPIN taken with ORAL CONTRACEPTIVES leads to:",options:["Increased estrogen levels","Contraceptive failure","No effect","Toxicity"],answer:1,explanation:"Already explained in Q66. Rifampin induces CYP3A4 → faster metabolism of estrogens/progestins → reduced plasma levels → contraceptive failure. This is Type F ADR (Failure of Efficacy)."},
    {id:"mid196",exam:"mid1",lecture:"Drug-Drug Interactions",q:"ANTACIDS reduce the absorption of:",options:["Insulin","Warfarin","Tetracycline","Heparin"],answer:2,explanation:"Antacids (containing Al³⁺, Mg²⁺, Ca²⁺) form insoluble chelate complexes with tetracycline, preventing its absorption from the GI tract. Tetracycline should be taken 2 hours before or 4-6 hours after antacids. This is a pharmaceutical/pharmacokinetic interaction."},
  {id:"mid197",exam:"mid1",lecture:"Drug-Drug Interactions",q:"A patient with cutaneous anthrax is prescribed ciprofloxacin. Which should he AVOID taking with ciprofloxacin?",options:["Alcohol","Grapefruit juice","Antacids","High-fat meals"],answer:2,explanation:"Antacids containing Al³⁺, Mg²⁺, or Ca²⁺ form insoluble chelates with ciprofloxacin → dramatically reduce absorption. They must be taken at least 2 hours apart. Ciprofloxacin is the drug of choice for anthrax."},
  {id:"mid198",exam:"mid1",lecture:"Drug-Drug Interactions",q:"A farmer develops excessive sweating, vomiting, and salivation after work. What is the antidote?",options:["PAM (pralidoxime) and atropine","Naloxone","N-acetylcysteine","Deferoxamine"],answer:0,explanation:"The symptoms (excessive secretions, vomiting, salivation = SLUDGE) are consistent with organophosphate (cholinergic) toxidrome from pesticide exposure. Organophosphates inhibit acetylcholinesterase → ACh accumulation. Treatment: - Atropine (muscarinic antagonist) — controls hypersecretions, bradycardia - Pralidoxime (2-PAM) — reactivates AChE if given early"},
  {id:"mid199",exam:"mid1",lecture:"Drug-Drug Interactions",q:"What is the drug that has to be reduced (dose-adjusted) with allopurinol?",options:["Mercaptopurine (6-MP)","Methotrexate","Cyclophosphamide","5-Fluorouracil"],answer:0,explanation:"Allopurinol inhibits xanthine oxidase, the enzyme responsible for metabolizing mercaptopurine (6-MP) and azathioprine. When given together, 6-MP is not metabolized → toxic accumulation → bone marrow suppression. Dose of 6-MP must be reduced to 25-33% when co-administered with allopurinol."},
  {id:"mid1100",exam:"mid1",lecture:"Drug-Drug Interactions",q:"Prolonged use of phenylephrine as a nasal decongestant results in:",options:["Epistaxis","Atrophic rhinitis (rhinitis medicamentosa)","Chronic cough","Hypertrophy of nasal mucosa"],answer:1,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. Prolonged use of vasoconstrictive nasal decongestants (phenylephrine, oxymetazoline) causes rebound congestion (rhinitis medicamentosa) and with long-term use → atrophic rhinitis (thinning and atrophy of nasal mucosa). This is a Type C (chronic use) ADR."},
  {id:"mid1101",exam:"mid1",lecture:"Drug-Drug Interactions",q:"Patient has hepatitis, cirrhosis — what change related to sulfonamide use?",options:["Decreased fluid intake","Folinic acid supplement","Alkalization of urine","Increase drug concentration"],answer:2,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. Sulfonamides can crystallize in urine (crystalluria) → renal tubular obstruction. Prevention: - Alkalinize the urine (sodium bicarbonate) — sulfonamides are more soluble at alkaline pH - Adequate fluid intake (hydration)"},
  {id:"mid1102",exam:"mid1",lecture:"Drug-Drug Interactions",q:"A pregnant woman is taking sulfonamide. What is the contraindication?",options:["Kernicterus in the neonate","Gray baby syndrome","Ototoxicity in the fetus","Nephrotoxicity in the mother"],answer:0,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. Sulfonamides displace bilirubin from plasma proteins in the neonate → free unconjugated bilirubin crosses the immature BBB → kernicterus. Contraindicated in the 3rd trimester and neonates < 2 months."},
  {id:"mid1103",exam:"mid1",lecture:"Drug-Drug Interactions",q:"Doctor wants to give chloramphenicol to a neonate but is worried about gray baby syndrome. What would INCREASE the baby's risk?",options:["Decreased hepatic glucuronyl transferase activity","Decreased renal excretion of the drug","Increased renal glomerular filtration rate","Enhanced plasma protein binding of the drug"],answer:0,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. Neonates have immature glucuronyl transferase (UGT) → cannot conjugate chloramphenicol → drug accumulates → bone marrow suppression, cardiovascular collapse, ashen-gray cyanosis."},
  {id:"mid1104",exam:"mid1",lecture:"Introduction to Toxicology",q:"A child swallowed iron tablets. The appropriate treatment is:",options:["Naloxone","Atropine","N-acetylcysteine","Deferoxamine (desferrioxamine) IV"],answer:3,explanation:"Antidotes by toxin: - Iron overdose → Deferoxamine (chelates free iron) - Opioids → Naloxone - Organophosphates → Atropine + Pralidoxime - Acetaminophen (paracetamol) → N-acetylcysteine - Cyanide → Hydroxocobalamin - Digoxin → Digoxin Fab antibodies - Benzodiazepines → Flumazenil"},
  {id:"mid1105",exam:"mid1",lecture:"Introduction to Toxicology",q:"A patient comes to hospital with swelling, low blood pressure, and wheezing after taking an antibiotic. What mediator is responsible?",options:["Norepinephrine","Histamine","Serotonin","Bradykinin"],answer:1,explanation:"Anaphylaxis (Type B IgE-mediated ADR): mast cell degranulation releases histamine → urticaria/angioedema, hypotension, bronchospasm. Treatment: epinephrine IM (not the mediator — the antidote)."},
  {id:"mid1106",exam:"mid1",lecture:"Introduction to Toxicology",q:"A patient commits suicide by drinking eye drops for acute glaucoma and also administers the drug IV — excessive vomiting occurs. What is the adverse effect?",options:["Dry mouth","Excessive salivation","Pupillary dilation","Tachycardia"],answer:1,explanation:"Glaucoma drops contain cholinergic agents (pilocarpine — muscarinic agonist). Systemic overdose → cholinergic toxidrome: SLUDGE (Salivation, Lacrimation, Urination, Defecation, GI cramps, Emesis) + bradycardia, miosis, bronchospasm."},
  {id:"mid1107",exam:"mid1",lecture:"Introduction to Toxicology",q:"Mechanism of action of Sulfamethoxazole + Trimethoprim (Co-trimoxazole):",options:["Inhibiting folate synthesis and reduction (two sequential steps in nucleic acid synthesis)","Inhibiting RNA polymerase"],answer:0,explanation:"⚠️ قد يكون هذا السؤال خارج منهجك الحالي. Co-trimoxazole works by double sequential blockade of folate pathway: - Sulfamethoxazole inhibits dihydropteroate synthase (blocks folate synthesis) - Trimethoprim inhibits dihydrofolate reductase (blocks folate reduction to active THF) Together: synergistic inhibition of bacterial nucleic acid synthesis. Humans can obtain folate from diet, bacteria must synthesize it."},
  {id:"mid1108",exam:"mid1",lecture:"IV Fluid Therapy",q:"For a patient with dehydration AND caloric requirement (NPO patient), the most appropriate IV fluid is:",options:["5% Dextrose in Water (D5W)","Normal saline","Ringer's lactate","3% NaCl"],answer:0,explanation:"D5W (5% Dextrose in Water): - Isotonic in the bag, becomes hypotonic after dextrose is metabolized - Provides 170 cal/L (caloric support for NPO patients) - Used for: dehydration, NPO maintenance, diluting drugs - NOT for: resuscitation, infants (risk of cerebral edema), patients with ↑ICP, mixing with blood"},
  {id:"mid1109",exam:"mid1",lecture:"IV Fluid Therapy",q:"Large volumes of NORMAL SALINE (0.9% NaCl) may cause:",options:["Hyponatremia","Hyperchloremic metabolic acidosis","Hypokalemia","Hypocalcemia"],answer:1,explanation:"Normal saline contains 154 mEq/L of Na⁺ AND 154 mEq/L of Cl⁻ — this is MORE chloride than plasma (104 mEq/L). Large volumes → hyperchloremic metabolic acidosis (dilutional acidosis — excess chloride drives bicarbonate down). Other complications: fluid overload."},
  {id:"mid1110",exam:"mid1",lecture:"IV Fluid Therapy",q:"HYPOTONIC fluids shift water:",options:["Into plasma","Into blood vessels","Into cells (intracellular space)","Into RBCs only"],answer:2,explanation:"Hypotonic solutions (0.45% NaCl, 0.33% NaCl, 0.2% NaCl) have osmolality lower than plasma (<280 mOsm/L). Water shifts by osmosis from the low osmolality ECF into the higher osmolality intracellular space → cells swell. This is why hypotonic fluids are: - Used for: hypernatremia, DKA, hyperosmolar states - ❌ Avoided in: ↑ICP (can worsen cerebral edema), liver disease, burns, trauma"},
  {id:"mid1111",exam:"mid1",lecture:"IV Fluid Therapy",q:"Best fluid for SEVERE SYMPTOMATIC HYPONATREMIA (coma, seizures):",options:["Ringer's lactate","D5W","3% NaCl (hypertonic saline)","5% Albumin"],answer:2,explanation:"Hypertonic saline (3% NaCl, 5% NaCl): - Osmolality ≥ 375 mOsm/L - Draws water OUT of cells into ECF → raises serum sodium rapidly - Indication: severe symptomatic hyponatremia (coma, seizures, Na⁺ <120 mEq/L) - Must be given slowly via central venous line (peripheral infusion causes thrombophlebitis) - Risk: osmotic demyelination syndrome if corrected too rapidly"},
  {id:"mid1112",exam:"mid1",lecture:"IV Fluid Therapy",q:"5% ALBUMIN works by:",options:["Providing calories","Correcting sodium","Diluting drugs","Increasing oncotic pressure"],answer:3,explanation:"5% Albumin is a colloid (not a crystalloid). It works by: - Increasing colloid oncotic pressure in the intravascular space - Draws fluid from the interstitial space into the bloodstream → expands intravascular volume - Used for: volume expansion, protein replacement in severe hypoalbuminemia, hemodynamic instability in shock - Cannot provide calories; does not directly correct sodium."},
  {id:"mid1113",exam:"mid1",lecture:"IV Fluid Therapy",q:"Normal saline is appropriate in all of the following EXCEPT:",options:["Hemorrhagic shock resuscitation","Diluting packed RBCs","Hyponatremia","Patient with hyperchloremia or metabolic acidosis (it worsens it)"],answer:3,explanation:""},
  {id:"mid1114",exam:"mid1",lecture:"IV Fluid Therapy",q:"A patient takes MORPHINE overdose and is administered NALOXONE. Respiratory depression is reversed. What is the pharmacological effect of naloxone?",options:["Competitive antagonist (at opioid receptors)","Non-pharmacological effect","Partial agonist","Agonistic effect"],answer:0,explanation:"Naloxone is a pure competitive antagonist at opioid receptors (μ, κ, δ). It displaces morphine from opioid receptors → reverses all opioid effects (respiratory depression, sedation, miosis, analgesia). It has high affinity for opioid receptors but NO intrinsic activity."},
  {id:"mid1115",exam:"mid1",lecture:"IV Fluid Therapy",q:"Biotransformation of a drug is primarily directed to:",options:["Inactivate a drug","Activate a drug","Convert lipid-soluble drug to non-lipid-soluble metabolite","Convert non-lipid-soluble drug to lipid-soluble metabolite"],answer:2,explanation:"The primary goal of drug biotransformation is to convert lipophilic (lipid-soluble) drugs into more hydrophilic (non-lipid-soluble) metabolites that can be renally excreted. This may inactivate, activate (prodrug), or create toxic metabolites — but the DIRECTION is always toward increased water solubility."},
  {id:"mid1116",exam:"mid1",lecture:"IV Fluid Therapy",q:"Which property facilitates a drug's ability to cross the blood-brain barrier?",options:["Lipophilic","Hydrophilic","High molecular weight","High plasma protein binding"],answer:0,explanation:""},
  {id:"mid1117",exam:"mid1",lecture:"IV Fluid Therapy",q:"The fraction of drug that reaches systemic circulation is:",options:["Bioavailability","First-pass metabolism","Volume of distribution","Drug clearance"],answer:0,explanation:"Bioavailability (F) is the fraction of administered drug reaching systemic circulation unchanged. IV administration gives F = 100%."},
  {id:"mid1118",exam:"mid1",lecture:"IV Fluid Therapy",q:"What does the therapeutic index INDICATE?",options:["Safety margin of a drug","Potency of the drug at its receptor","Maximum achievable effect of the drug","Rate of drug absorption from the GI tract"],answer:0,explanation:"Therapeutic index (TI = TD50/ED50) reflects the safety margin — the wider it is, the safer the drug. It says nothing about potency or efficacy."}
];
const MID2_QUESTIONS: Question[] = [
  {id:"mid21",exam:"mid2",lecture:"Cholinergic Agonists",q:"A 10-year-old boy accidentally ingested a medication. He presents with signs of excessive nicotinic AND muscarinic stimulation WITHOUT central nervous system effects. Which drug is most likely?",options:["Pilocarpine","Rivastigmine","Pyridostigmine","Physostigmine"],answer:2,explanation:"Pyridostigmine is a quaternary amine AChE inhibitor — does not cross BBB (no CNS effects), stimulates both nicotinic and muscarinic receptors peripherally."},
  {id:"mid22",exam:"mid2",lecture:"Cholinergic Agonists",q:"A girl from the countryside is brought to the ER with pale face, cool & wet skin. What is the most appropriate treatment?",options:["Atropine + pralidoxime","Pralidoxime + physostigmine","Atropine + physostigmine","Pralidoxime + physostigmine"],answer:0,explanation:"Classic organophosphate poisoning (cholinergic crisis). Atropine blocks muscarinic effects; pralidoxime (PAM) regenerates AChE if given early."},
  {id:"mid23",exam:"mid2",lecture:"Cholinergic Agonists",q:"If a person is exposed to organophosphorus compounds and is not treated, what is the most likely cause of death?",options:["Respiratory failure","Cardiac arrest","Glaucoma","Hypertension"],answer:0,explanation:"Organophosphates cause irreversible AChE inhibition → excess ACh → bronchoconstriction + bronchospasm + respiratory muscle paralysis → respiratory failure."},
  {id:"mid24",exam:"mid2",lecture:"Cholinergic Agonists",q:"A farmer develops excessive sweating, vomiting, and salivation after work. Which of the following is the antidote?",options:["Pralidoxime and atropine","Physostigmine and diazepam","Neostigmine and propranolol","Naloxone and flumazenil"],answer:0,explanation:"Organophosphate poisoning: atropine blocks muscarinic effects (SLUDGE); pralidoxime reactivates AChE before aging occurs. Physostigmine is a cholinesterase inhibitor — would worsen the toxicity."},
  {id:"mid25",exam:"mid2",lecture:"Cholinergic Agonists",q:"A 40-year-old male with myasthenia gravis is treated with neostigmine. He develops bradycardia and diarrhea. Which drug manages these symptoms?",options:["Atropine","Vitamin K","Protamine sulfate","Physostigmine"],answer:0,explanation:"Neostigmine ↑ ACh → excess muscarinic effects (bradycardia, diarrhea, salivation). Atropine (competitive muscarinic blocker) is co-administered to block these side effects. Physostigmine would worsen them."},
  {id:"mid26",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following increases parasympathomimetic activity?",options:["Isoflurophate","Cyclopentolate","Atropine","Scopolamine"],answer:0,explanation:"Isoflurophate is an irreversible organophosphate AChE inhibitor → increases ACh → increased parasympathetic activity."},
  {id:"mid27",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which receptor increases salivation when activated in parasympathetic conditions?",options:["M3","M2","M1","Nn"],answer:0,explanation:"M3 receptors mediate exocrine gland secretion including salivary glands (also sweat glands)."},
  {id:"mid28",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following is an action of a parasympathomimetic (cholinergic agonist)?",options:["Contraction of the bladder wall","Contraction of skeletal muscle blood vessels","Pupillary dilation","Increase in heart rate"],answer:0,explanation:"M3 stimulation contracts the detrusor muscle (bladder wall) and relaxes the sphincter → promotes urination. Parasympathomimetics cause miosis (not mydriasis), bradycardia, and vasodilation."},
  {id:"mid29",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following actions is brought out by parasympathomimetics?",options:["Vasoconstriction of skeletal muscle blood vessels","Slowing of the heart","Relaxation of the urinary bladder wall","Dilatation of the eye pupil"],answer:1,explanation:"Parasympathetic stimulation slows the heart via M2 receptors on the SA/AV node."},
  {id:"mid210",exam:"mid2",lecture:"Cholinergic Agonists",q:"What is the mode of action of pirenzepine?",options:["Selective M1 cholinergic antagonist","Selective M2 cholinergic antagonist","Non-selective muscarinic agonist","Nicotinic receptor blocker"],answer:0,explanation:"Pirenzepine and dicyclomine selectively block M1 receptors on gastric parietal cells → reduce HCl secretion. Unlike non-selective antimuscarinics, they have fewer anticholinergic side effects."},
  {id:"mid211",exam:"mid2",lecture:"Cholinergic Agonists",q:"A cholinergic agonist drug can be used to treat which condition?",options:["Increased gastric acid secretion","Urge urinary incontinence","Urinary retention and postoperative ileus","Hypertensive urgency"],answer:2,explanation:"Bethanechol (M3 agonist) contracts the detrusor muscle and GI smooth muscle → treats urinary retention and paralytic ileus. It is contraindicated in bladder obstruction or asthma."},
  {id:"mid212",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following will present in a patient taking Atropine?",options:["Constipation","Sweating","Bradycardia","Increased salivation"],answer:0,explanation:"Atropine blocks M3 receptors in GI tract → reduced peristalsis → constipation. Also causes: dry mouth, tachycardia (M2 block), urinary retention, mydriasis, cycloplegia. Sweating and increased salivation are cholinergic effects."},
  {id:"mid213",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following is a characteristic of parasympathetic stimulation?",options:["Mydriasis (pupil dilation)","Bradycardia","Bronchodilation","Increased heart rate"],answer:1,explanation:"Parasympathetic stimulation activates muscarinic receptors → SLUDGE effects: Salivation, Lacrimation, Urination, Defecation, GI motility↑, Emesis. Cardiac effects: bradycardia (M2 on SA node). Ocular: miosis (pupil constriction). Respiratory: bronchoconstriction. Mydriasis, tachycardia, and bronchodilation are sympathetic (adrenergic) effects."},
  {id:"mid214",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following can be used to treat an accidental overdose of Pilocarpine?",options:["Atropine","Physostigmine","Bethanechol","Carbachol"],answer:0,explanation:"Pilocarpine is a muscarinic agonist. Overdose → excess muscarinic effects. Atropine (competitive muscarinic antagonist) reverses these effects."},
  {id:"mid215",exam:"mid2",lecture:"Cholinergic Agonists",q:"A patient took a large dose of pilocarpine. What other complications could appear beyond vomiting?",options:["Bradycardia","Decreased salivation","Tachycardia","Urinary retention"],answer:0,explanation:"Pilocarpine overdose → excessive M2 cardiac stimulation → bradycardia; also excessive secretions, bronchospasm, miosis. Decreased salivation and urinary retention are antimuscarinic effects — the opposite."},
  {id:"mid216",exam:"mid2",lecture:"Cholinergic Agonists",q:"Which of the following drugs would increase the parasympathetic activity?",options:["Tropicamide","Hyoscine","Atropine","Neostigmine"],answer:3,explanation:"Neostigmine is an AChE inhibitor → ↑ ACh → ↑ parasympathetic activity. All others are antimuscarinic drugs."},
  {id:"mid217",exam:"mid2",lecture:"Cholinergic Antagonists",q:"What is the most appropriate treatment for a 3-year-old who accidentally ingested atropine eye drops and presents with hyperthermia, dry mouth, dilated pupils, tachycardia, and hallucinations?",options:["Pralidoxime","Physostigmine","Atropine","Neostigmine"],answer:1,explanation:"Atropine toxicity → physostigmine (tertiary amine AChE inhibitor) crosses BBB and reverses both central and peripheral atropine effects. Neostigmine is quaternary — doesn't cross BBB."},
  {id:"mid218",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A 48-year-old man presents with dilated pupils, dry mucous membranes, tachycardia, urinary retention, absent bowel sounds, hallucinations. What is the diagnosis?",options:["Organophosphate poisoning","Opioid overdose","Atropine toxicity","Beta-blocker overdose"],answer:2,explanation:"Classic \"anticholinergic toxidrome\": Blind as a bat (mydriasis), Dry as a bone, Hot as a hare, Red as a beet, Mad as a hatter, tachycardia."},
  {id:"mid219",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A woman prescribed an anticholinergic for motion sickness later experiences vivid dreams and hallucinations. Which drug was most likely used?",options:["Atropine","Glycopyrrolate","Scopolamine","Dicyclomine"],answer:2,explanation:"Scopolamine (hyoscine) has greater CNS penetration than atropine → used for motion sickness but can cause CNS excitation, vivid dreams, hallucinations, especially in females pre-anesthetically."},
  {id:"mid220",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A patient is planning to travel by sea and has a history of severe nausea and vomiting during travel. Which drug is most likely prescribed?",options:["Scopolamine","Salbutamol","Propranolol","Fluoxetine"],answer:0,explanation:"Scopolamine (hyoscine) is the preferred antiemetic for motion sickness — more effective than atropine for this indication (blocks vestibular M1 receptors)."},
  {id:"mid221",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A child with acute iridocyclitis is prescribed a mydriatic-cycloplegic. Which drug is preferred due to its shorter duration of action?",options:["Atropine","Tropicamide","Scopolamine","Glycopyrrolate"],answer:1,explanation:"Tropicamide produces mydriasis for ~6 hours; cyclopentolate ~24 hours. Atropine lasts up to 7 days. Shorter-acting preferred (easier to reverse) except in children requiring cycloplegia."},
  {id:"mid222",exam:"mid2",lecture:"Cholinergic Antagonists",q:"Which of the following is not an indication for antimuscarinic drugs?",options:["Motion sickness","Parkinson's disease","Bladder spasms","Narrow angle glaucoma"],answer:3,explanation:"Narrow angle glaucoma is a CONTRAINDICATION — antimuscarinics cause mydriasis → ↑ IOP → worsening of narrow-angle glaucoma."},
  {id:"mid223",exam:"mid2",lecture:"Cholinergic Antagonists",q:"Which of the following in unaccepted (NOT a therapeutic indication) of antimuscarinic drugs?",options:["Atrial fibrillation","Postoperative bladder spasm","Motion sickness","Parkinson's disease"],answer:0,explanation:"AF is not an indication for antimuscarinics. Atropine is used for bradycardia. Antimuscarinics are used for: motion sickness, bladder spasms, Parkinson's, preanesthesia, intestinal colic."},
  {id:"mid224",exam:"mid2",lecture:"Cholinergic Antagonists",q:"Parasympatholytics should not be used in which conditions?",options:["Pre-anesthetic","Intestinal colic","Bronchospasm","Prostate enlargement"],answer:3,explanation:"Antimuscarinics relax bladder wall and contract sphincter → urinary retention → contraindicated in enlarged prostate (BPH)."},
  {id:"mid225",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A medical student evaluating atropine doses. At a steady-state dose of 0.5 mg, what effect is expected?",options:["Coma","Skin dryness","Bradykinesia","Hallucinations"],answer:1,explanation:"At 0.5 mg atropine → initial paradoxical bradycardia (vagal M1 block), dry mouth/skin. Higher doses → tachycardia → mydriasis → hallucinations/CNS effects. The dose-dependent table: 0.5mg = mild dryness; 1mg = dry mouth + ↑HR; 2mg = mydriasis; 5mg+ = hallucinations/delirium."},
  {id:"mid226",exam:"mid2",lecture:"Cholinergic Antagonists",q:"Which of the following adverse effects is expected after administration of anticholinergic (atropine)?",options:["Urinary incontinence","Cycloplegia","Diarrhea","Salivation"],answer:1,explanation:"Atropine blocks M3 in ciliary muscle → paralysis of accommodation (cycloplegia) and mydriasis. It causes urinary RETENTION (not incontinence), constipation, and dry mouth."},
  {id:"mid227",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A patient with BPH is about to undergo prostatectomy. Which of the following is absolutely contraindicated?",options:["Scopolamine","Propranolol","Labetalol","Metformin"],answer:0,explanation:"Scopolamine (antimuscarinic) blocks M3 receptors in the bladder → urinary retention → absolutely contraindicated in BPH, especially pre-operatively. Propranolol and labetalol are beta-blockers unrelated to urinary tone."},
  {id:"mid228",exam:"mid2",lecture:"Cholinergic Antagonists",q:"Why is ipratropium bromide preferred over scopolamine in treating chronic pulmonary obstruction?",options:["Better bioavailability by inhalation","Minor effects on the central nervous system","No effects on bronchial secretions","More potent than scopolamine"],answer:1,explanation:"Ipratropium is a quaternary amine → does not cross BBB → fewer CNS side effects. Inhaled route also limits systemic effects. Used in asthma and COPD."},
  {id:"mid229",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A patient with COPD prescribed an inhaled anticholinergic. After prolonged use, he does NOT develop tolerance. Which drug?",options:["Tiotropium","Ipratropium","Succinylcholine","Benztropine"],answer:0,explanation:"Tiotropium is selective M3 blocker → does not block presynaptic M2 → no ↑ ACh → no tolerance. Also longer acting (once daily, for COPD maintenance)."},
  {id:"mid230",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A 60-year-old male with urinary urgency/incontinence is prescribed a selective M3 antagonist. Which is most appropriate?",options:["Ipratropium","Scopolamine","Solifenacin","Pancuronium"],answer:2,explanation:"Solifenacin, darifenacin, oxybutynin are uroselective M3 blockers → relax bladder wall → used for urge incontinence and nocturnal enuresis."},
  {id:"mid231",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A 70-year-old with Parkinson's experiencing excessive salivation and tremors. Which drug is most appropriate?",options:["Glycopyrrolate","Benztropine","Ipratropium","Oxybutynin"],answer:1,explanation:"Benztropine (and biperiden, benzhexol) are antiparkinsonian antimuscarinics that cross BBB → reduce tremors and sialorrhea in Parkinson's / drug-induced parkinsonism."},
  {id:"mid232",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A colonoscopy patient receives an intramuscular anticholinergic to relax the intestine. What other adverse effect could occur?",options:["Urinary incontinence","Cycloplegia","Diarrhea","Salivation"],answer:1,explanation:"Antimuscarinics → block M3 in ciliary muscle → cycloplegia (blurred vision). Also cause dry mouth, urinary retention, tachycardia — not incontinence or diarrhea."},
  {id:"mid233",exam:"mid2",lecture:"Cholinergic Antagonists",q:"Which of the following drugs antagonizes the action of tubocurarine?",options:["Halothane","Neostigmine","Gentamicin","Diltiazem"],answer:1,explanation:"Tubocurarine is a non-depolarizing (competitive) NMB. Neostigmine (AChE inhibitor) ↑ ACh in synaptic cleft → competes with tubocurarine → reverses blockade. Aminoglycosides and halothane POTENTIATE the block."},
  {id:"mid234",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A patient is given a neuromuscular blocker. An initial phase of muscle fasciculations is followed by paralysis. Which drug?",options:["Pancuronium","Succinylcholine","Rocuronium","Vecuronium"],answer:1,explanation:"Succinylcholine is the ONLY depolarizing NMB — acts as ACh agonist → initial fasciculations → sustained depolarization → paralysis. Non-depolarizing agents (pancuronium, rocuronium, vecuronium) cause NO fasciculations."},
  {id:"mid235",exam:"mid2",lecture:"Cholinergic Antagonists",q:"After surgery, anesthesiologist gives neostigmine to reverse neuromuscular blockade. Which drug was used initially?",options:["Succinylcholine","Pancuronium","Atropine","Tiotropium"],answer:1,explanation:"Only non-depolarizing NMBs (pancuronium, rocuronium, vecuronium) are reversible with neostigmine. Succinylcholine is NOT reversed by AChE inhibitors (it is depolarizing)."},
  {id:"mid236",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A patient is given a NMB that causes histamine release, ganglionic blockade, and prolonged apnea in pseudocholinesterase deficiency. Which drug?",options:["Rocuronium","Succinylcholine","Pancuronium","Vecuronium"],answer:1,explanation:"Succinylcholine: hydrolyzed by plasma pseudocholinesterase (genetic deficiency → prolonged apnea), weak histamine release, and ganglionic block at high doses."},
  {id:"mid237",exam:"mid2",lecture:"Cholinergic Antagonists",q:"A patient develops malignant hyperthermia (severe muscle rigidity, hyperthermia) after a NMB. Which drug?",options:["Succinylcholine","Atracurium","Rocuronium","Vecuronium"],answer:0,explanation:"Succinylcholine (depolarizing) can trigger malignant hyperthermia in genetically susceptible patients → treat with dantrolene."},
  {id:"mid238",exam:"mid2",lecture:"Cholinergic Antagonists",q:"An ICU patient with liver cirrhosis needs a competitive NMB for ventilator management. Which is the best choice?",options:["Suxamethonium (succinylcholine)","Atracurium or cisatracurium","Pancuronium","Vecuronium"],answer:1,explanation:"Atracurium and cisatracurium undergo spontaneous Hofmann elimination (temperature + pH-dependent, organ-independent) → safe in liver failure AND renal failure — no accumulation. Pancuronium, vecuronium, and rocuronium are hepatically metabolized and accumulate in cirrhosis. Suxamethonium (metabolized by pseudocholinesterase, partly produced in liver) is used for rapid intubation, not maintenance."},
  {id:"mid239",exam:"mid2",lecture:"Adrenergic Agonists",q:"A 17-year-old girl is brought to the ER 15 minutes after being stung by a bee. She has shortness of breath, face swelling, low blood pressure, and bilateral wheezing. Which drug is most appropriate?",options:["Norepinephrine","Dopamine","Epinephrine","Dobutamine"],answer:2,explanation:"Anaphylactic shock → epinephrine is drug of choice. α1 effect → vasoconstriction (raises BP); β2 effect → bronchodilation; β1 → ↑HR. Also stabilizes mast cells."},
  {id:"mid240",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following is a non-selective beta agonist?",options:["Dobutamine","Salbutamol","Isoproterenol","Terbutaline"],answer:2,explanation:"Isoproterenol stimulates both β1 (cardiac) and β2 (bronchial, vascular) equally → nonselective. Dobutamine is selective β1. Salbutamol and terbutaline are selective β2 agonists."},
  {id:"mid241",exam:"mid2",lecture:"Adrenergic Agonists",q:"A patient with septic shock is treated with a drug that decreases total peripheral resistance at low doses and increases it at high doses. Which drug?",options:["Dopamine","Norepinephrine","Epinephrine","Phenylephrine"],answer:0,explanation:"Dopamine has dose-dependent receptor selectivity: low dose → D1 → vasodilation (↓TPR, ↑renal flow); moderate → β1 → ↑cardiac output; high → α1 → vasoconstriction (↑TPR). NE and phenylephrine cause vasoconstriction at all doses."},
  {id:"mid242",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which adrenergic agonist is primarily used as a vasopressor for septic shock?",options:["Epinephrine","Norepinephrine","Dobutamine","Dopamine"],answer:1,explanation:"Norepinephrine is the vasopressor of choice for septic shock — potent α1+α2 → strong vasoconstriction → ↑BP. Mainly α effects, minimal β2."},
  {id:"mid243",exam:"mid2",lecture:"Adrenergic Agonists",q:"Phenylephrine acts primarily through which mechanism?",options:["Alpha-1 agonist","Alpha-2 antagonist","Beta-1 agonist","Beta-2 agonist"],answer:0,explanation:"Phenylephrine is a pure α1 agonist → vasoconstriction → ↑BP, nasal decongestant (topical), reflex bradycardia when used IV."},
  {id:"mid244",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following is a selective β1 agonist?",options:["Dobutamine","Dopamine","Salbutamol","Salmeterol"],answer:0,explanation:"Dobutamine is a selective β1 agonist → ↑ myocardial contractility (positive inotrope) with minimal chronotropy. Used in acute heart failure. Salbutamol and salmeterol are selective β2 agonists."},
  {id:"mid245",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following is a mixed adrenergic agonist?",options:["Propranolol","Ephedrine","Phenylephrine","Terbutaline"],answer:1,explanation:"Ephedrine has both direct (α and β receptor stimulation) and indirect (triggers NE release from nerve terminals) effects — classically described as a \"mixed\" adrenergic agonist. Propranolol is a β-blocker."},
  {id:"mid246",exam:"mid2",lecture:"Adrenergic Agonists",q:"An asthmatic patient given a non-selective β agonist to relieve bronchoconstriction. What adverse effect is expected?",options:["Tachycardia","Bradycardia","Hypotension","Bronchoconstriction"],answer:0,explanation:"Non-selective β agonist → β1 stimulation → tachycardia and palpitations (while β2 provides bronchodilation). Selective β2 agonists (salbutamol) preferred in asthma to minimize this."},
  {id:"mid247",exam:"mid2",lecture:"Adrenergic Agonists",q:"An 8-year-old girl with bronchial asthma (started therapy 2 weeks ago) presents with tremors, muscle cramps, palpitations. Which drug is responsible?",options:["Propranolol","Albuterol","Prazosin","Dobutamine"],answer:1,explanation:"Albuterol (salbutamol) is a β2 agonist. At higher doses/systemic absorption → β1-mediated tachycardia/palpitations + β2-mediated skeletal muscle tremors and cramps."},
  {id:"mid248",exam:"mid2",lecture:"Adrenergic Agonists",q:"A second-trimester pregnant woman in labor was given a medication to relax the uterus and delay delivery. What adverse effect could occur?",options:["Tachycardia","Hypotension","Bradycardia","Bronchoconstriction"],answer:0,explanation:"Tocolytics (β2 agonists: terbutaline, ritodrine) relax uterine smooth muscle (β2). Spillover onto cardiac β1 receptors → tachycardia is the main cardiovascular adverse effect."},
  {id:"mid249",exam:"mid2",lecture:"Adrenergic Agonists",q:"The following drug can relax the pregnant uterus:",options:["Noradrenaline","Acetylcholine","Terbutaline","Propranolol"],answer:2,explanation:"Terbutaline is a β2 agonist → relaxes uterine smooth muscle → used as tocolytic (delays premature labor)."},
  {id:"mid250",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following drugs is used to treat nasal congestion?",options:["Alpha-1 agonist","Beta-2 agonist","Alpha-2 antagonist","Dopamine agonist"],answer:0,explanation:"α1 agonists (phenylephrine, oxymetazoline, xylometazoline) vasoconstrict nasal mucosal vessels → reduce congestion. Prolonged use causes atrophic rhinitis (rebound congestion)."},
  {id:"mid251",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following is a result of prolonged use of phenylephrine as a nasal decongestant?",options:["Epistaxis","Atrophic rhinitis","Chronic cough","Hypertrophy of nasal mucosa"],answer:1,explanation:"Prolonged α1 agonist nasal decongestant → receptor downregulation → rebound congestion → atrophic rhinitis (rhinitis medicamentosa)."},
  {id:"mid252",exam:"mid2",lecture:"Adrenergic Agonists",q:"A patient taking MAO inhibitors ingests tyramine-rich food (red wine, aged cheese). Which acute response is most likely?",options:["No response","Stimulation of NE release","Inhibition of ACh release","Inhibition of NE release"],answer:1,explanation:"MAOIs block MAO → tyramine not metabolized → enters nerve terminals → massive NE release → hypertensive crisis (\"cheese reaction\")."},
  {id:"mid253",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following is a common adverse effect of amphetamines?",options:["Bradycardia","Somnolence","Constipation","Hypertension"],answer:3,explanation:"Amphetamines → indirect sympathomimetics → massive NE/DA release → hypertension, tachycardia, insomnia, anorexia."},
  {id:"mid254",exam:"mid2",lecture:"Adrenergic Agonists",q:"Which of the following drugs can be used to treat hypertension?",options:["Norepinephrine","Phenylephrine","Alpha methyldopa","Tyramine"],answer:2,explanation:"Alpha-methyldopa is a central α2 agonist → ↓ sympathetic outflow → ↓ BP. Preferred in pregnancy-induced hypertension."},
  {id:"mid255",exam:"mid2",lecture:"Adrenergic Agonists",q:"A doctor administered norepinephrine IV for septic shock; it caused tissue necrosis at the injection site. What is the best antidote?",options:["Phentolamine","Timolol","Terazosin","Prazosin"],answer:0,explanation:"NE extravasation → intense α1 vasoconstriction → ischemic tissue necrosis. Phentolamine (non-selective α blocker) injected locally reverses vasoconstriction and restores blood flow. All options are alpha blockers but phentolamine is the agent used for this specific indication."},
  {id:"mid256",exam:"mid2",lecture:"Adrenergic Agonists",q:"Using epinephrine with local anesthetic will:",options:["Prolong the duration of anesthetic action","Shorten the onset of action","Cause rapid systemic distribution","Increase systemic toxicity of the local anesthetic"],answer:0,explanation:"Epinephrine causes local vasoconstriction (α1) → reduces absorption of local anesthetic from injection site → prolongs duration of action + reduces systemic toxicity."},
  {id:"mid257",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A 58-year-old man with hypertension is started on a drug that selectively blocks α1 receptors. Which effect is most likely?",options:["Increased heart rate","Vasoconstriction","Decreased peripheral resistance","Bronchoconstriction"],answer:2,explanation:"α1 blockade → vasodilation → ↓ peripheral resistance → ↓ BP. Used for hypertension and BPH."},
  {id:"mid258",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient with BPH without hypertension is prescribed a drug to improve urinary symptoms. Which is most appropriate?",options:["Tamsulosin","Dobutamine","Clonidine","Propranolol"],answer:0,explanation:"Tamsulosin is a selective α1A blocker (uroselective) → relaxes smooth muscle of prostate/bladder neck → improves urinary flow in BPH without significant BP drop."},
  {id:"mid259",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A 60-year-old asthmatic man with hypertension and slightly enlarged prostate. Which medication treats both conditions?",options:["Prazosin","Tamsulosin","Labetalol","Propranolol"],answer:0,explanation:"Prazosin (non-selective α1 blocker) lowers BP by vasodilation and relaxes prostate/bladder neck smooth muscle → treats both HTN and BPH. Labetalol and propranolol are beta-blockers (CI in asthma). Tamsulosin (selective α1A) helps BPH but has minimal BP effect."},
  {id:"mid260",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient taking an α-blocker complains of dizziness when standing. What is the most likely mechanism?",options:["Excessive vasodilation reducing venous return on standing (orthostatic hypotension)","Increased renal potassium loss causing muscle weakness","Reflex vagal stimulation from GI absorption","Central suppression of baroreceptor sensitivity"],answer:0,explanation:"Alpha-1 blockers (prazosin, doxazosin, terazosin) block vascular α1 receptors → vasodilation. On standing, normal sympathetic vasoconstriction cannot compensate → venous pooling → reduced venous return → orthostatic (postural) hypotension and dizziness. This 'first-dose effect' is most pronounced with prazosin."},
  {id:"mid261",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following best describes the effect of α1 blockade on blood vessels?",options:["Vasoconstriction","Vasodilation","No change","Increased contractility"],answer:1,explanation:"α1 receptor activation → vasoconstriction. Blocking α1 → removes vasoconstrictor tone → vasodilation."},
  {id:"mid262",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following drugs is most likely to cause reflex tachycardia?",options:["Prazosin (alpha-1 blocker)","Propranolol (non-selective beta-blocker)","Metoprolol (selective beta-1 blocker)","Labetalol (alpha+beta blocker)"],answer:0,explanation:"Prazosin (α1 blocker) → vasodilation → ↓ BP → baroreceptor reflex activation → reflex tachycardia (can be troublesome). Propranolol and metoprolol BLOCK the reflex. Labetalol also blocks the beta receptor, so no reflex tachycardia. Alpha-blockers without concurrent beta blockade are classic causes of reflex tachycardia."},
  {id:"mid263",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which β-blocker is preferred in a patient with asthma or COPD?",options:["Propranolol","Nadolol","Metoprolol (cardioselective β1)","Timolol"],answer:2,explanation:"Metoprolol is a cardioselective β1 blocker — preferentially blocks cardiac β1 receptors with less effect on bronchial β2 → safer in asthma/COPD. Propranolol, nadolol, and timolol are non-selective → block β2 → bronchoconstriction → contraindicated in asthma."},
  {id:"mid264",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following is the primary mechanism of β-blockers in hypertension?",options:["Increased peripheral resistance","Increased cardiac output","Decreased cardiac output and renin release","Increased sodium retention"],answer:2,explanation:"β-blockers: β1 blockade → ↓ HR and contractility → ↓ CO; ↓ renin release from kidney (β1) → ↓ angiotensin II → ↓ BP."},
  {id:"mid265",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following drugs is a non-selective β-blocker?",options:["Metoprolol","Atenolol","Propranolol","Nebivolol"],answer:2,explanation:"Propranolol is non-selective (β1+β2). Metoprolol, atenolol, nebivolol are selective β1 (cardioselective) blockers."},
  {id:"mid266",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A nonselective β-blocker is given to a patient with asthma. What is the most likely adverse effect?",options:["Bronchoconstriction (worsening of asthma)","Tachycardia and palpitations","Hypertension","Hyperglycemia"],answer:0,explanation:"Non-selective β-blockers (propranolol, timolol, nadolol) block both β1 (cardiac) and β2 (bronchial) receptors. In asthmatic patients, β2 blockade → bronchoconstriction → potentially life-threatening worsening of asthma. This is why non-selective β-blockers are contraindicated in asthma. Cardioselective β1 blockers (metoprolol, atenolol) are safer alternatives."},
  {id:"mid267",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which β-blocker is safest in a patient with asthma?",options:["Propranolol","Timolol","Metoprolol","Nadolol"],answer:2,explanation:"Metoprolol is cardioselective (β1 > β2) → less bronchospasm risk. Propranolol, timolol, nadolol are non-selective → contraindicated in asthma."},
  {id:"mid268",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient with hypertension and asthma was given an adrenergic blocker, after which asthma worsened. What is the best alternative?",options:["Propranolol","Metoprolol","Timolol","Carvedilol"],answer:1,explanation:"Switch to a cardioselective β1 blocker (metoprolol, atenolol) → minimal β2 blockade → less bronchoconstriction. Propranolol, timolol, and carvedilol are non-selective → worsen asthma."},
  {id:"mid269",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient taking a β-blocker develops fatigue and bradycardia. Which receptor is primarily responsible?",options:["α1","β1","β2","M3"],answer:1,explanation:"β1 blockade in heart → ↓ HR (bradycardia) and ↓ contractility → fatigue."},
  
  {id:"mid271",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which symptoms of hypoglycemia are masked by beta blockers?",options:["Sweating only","Tremor and tachycardia","Confusion only","Polyuria"],answer:1,explanation:"β-blockers mask β-adrenergic signs: tachycardia + tremor. Sweating (cholinergic) and CNS symptoms (confusion) are NOT masked."},
  {id:"mid272",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient on chronic β-blocker therapy suddenly stops the medication. What is the expected outcome?",options:["Rebound tachycardia and angina due to receptor upregulation","Permanent blockade of cardiac beta receptors","Increased hepatic clearance of the drug","Decreased sympathetic tone in the heart"],answer:0,explanation:"Chronic beta-blocker use → compensatory upregulation of beta receptors (↑ number and sensitivity). Abrupt withdrawal unmasks these hypersensitive receptors → rebound tachycardia, hypertension, angina, and risk of MI — especially in patients with ischemic heart disease. Beta-blockers must always be tapered gradually."},
  {id:"mid273",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which receptor blockade is responsible for decreased aqueous humor production in glaucoma?",options:["α1","α2","β1","β2"],answer:3,explanation:"β2 blockade in ciliary epithelium → ↓ aqueous humor production → ↓ IOP. Example: timolol eye drops for glaucoma."},
  {id:"mid274",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient with glaucoma is treated with a β-blocker eye drop. What is the main mechanism?",options:["Increased aqueous humor outflow","Decreased aqueous humor production","Increased pupil size","Increased ciliary contraction"],answer:1,explanation:"Timolol (β1+β2 blocker) eye drop → ↓ aqueous humor secretion by ciliary body → ↓ IOP. Does not affect pupil size (unlike miotics or mydratics)."},
  {id:"mid275",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which β-blocker is a beta-receptor antagonist primarily used for glaucoma?",options:["Nadolol","Pilocarpine","Timolol","Propranolol"],answer:2,explanation:"Timolol (non-selective β-blocker) topical → ↓ aqueous humor → glaucoma treatment."},
  {id:"mid276",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which receptor blockade reduces renin release from the kidney?",options:["α1","α2","β1","β2"],answer:2,explanation:"β1 receptors in juxtaglomerular cells regulate renin release. β1 blockade → ↓ renin → ↓ angiotensin II → ↓ aldosterone → ↓ BP."},
  {id:"mid277",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient develops cold extremities while taking a β-blocker. What is the cause?",options:["Increased vasodilation","Reduced peripheral blood flow","Increased cardiac output","Bronchodilation"],answer:1,explanation:"β2 blockade in peripheral vasculature → removes vasodilatory tone → reduced peripheral blood flow → cold extremities. More pronounced with non-selective β-blockers."},
  {id:"mid278",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A patient with pheochromocytoma is treated with a β-blocker BEFORE an α-blocker. What complication may occur?",options:["Severe hypotension","Bronchodilation","Hypertensive crisis","Hypoglycemia"],answer:2,explanation:"Pheo → excess NE/Epi. If β-blocker given first → unopposed α1 stimulation → severe hypertensive crisis. MUST give α-blocker (phenoxybenzamine) FIRST, then add β-blocker."},
  {id:"mid279",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following is an irreversible alpha receptor antagonist?",options:["Tolazoline","Prazosin","Phenoxybenzamine","Labetalol"],answer:2,explanation:"Phenoxybenzamine is an irreversible (covalent bond), non-selective α-blocker (α1+α2). Prazosin and tolazoline are reversible. Used for pheochromocytoma preoperatively."},
  {id:"mid280",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following is a non-selective alpha blocker?",options:["Phenoxybenzamine","Prazosin","Tamsulosin","Ephedrine"],answer:0,explanation:"Phenoxybenzamine is non-selective (α1+α2) and irreversible. Prazosin and tamsulosin are selective α1 blockers."},
  {id:"mid281",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following is a reversible β-blocker with α1 blocking actions used to treat hypertension?",options:["Propranolol","Labetalol","Prazosin","Phentolamine"],answer:1,explanation:"Labetalol blocks both β and α1 (reversibly) → combined mechanism → used in hypertension, hypertensive emergencies, pregnancy."},
  {id:"mid282",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which β-blocker is used in heart failure because it also blocks α1 receptors (vasodilation) and has antioxidant properties?",options:["Esmolol","Metoprolol","Carvedilol","Timolol"],answer:2,explanation:"Carvedilol is a non-selective β-blocker that also blocks α1 receptors → vasodilation. It has additional antioxidant properties. Indicated in heart failure (reduces mortality), along with metoprolol and bisoprolol (which are cardioselective only). Esmolol is ultra-short-acting (IV only), used for acute rate control."},
  {id:"mid283",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"A hypertensive patient accidentally given an α2-agonist instead of an α1-blocker. Which is correct?",options:["α2-agonists ↑ NE release from sympathetic terminals","α2-agonists can reduce BP","α2-agonist can increase BP","No effect on BP"],answer:1,explanation:"α2 agonists (clonidine, methyldopa) → act on presynaptic α2 → ↓ NE release → central sympathoinhibition → ↓ BP. So the patient would still get BP reduction, similar goal."},
  {id:"mid284",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following drugs is used in performance anxiety?",options:["Propranolol","Phenylephrine","Pilocarpine","Bethanechol"],answer:0,explanation:"Propranolol (β-blocker) blunts somatic signs of anxiety (tachycardia, tremor, palpitations) → used for situational/performance anxiety."},
  {id:"mid285",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following is correct regarding α-adrenergic blockers?",options:["Used in treatment of hypotension in anaphylactic shock","Used in treatment of BPH","Used in treatment of asthma","Reduce frequency of urination"],answer:1,explanation:"α1 blockers (prazosin, tamsulosin, doxazosin) relax prostatic smooth muscle → improve urine flow in BPH. They do NOT treat anaphylaxis (epinephrine does) and do NOT treat asthma."},
  {id:"mid286",exam:"mid2",lecture:"Adrenergic Receptors & Blockers",q:"Which of the following is correct regarding beta blockers?",options:["Treatment with β-blockers should not be stopped abruptly","Propranolol is a cardioselective β-blocker","β-blockers may cause orthostatic hypotension","Cardioselective β-blockers worsen asthma","β-blockers decrease peripheral resistance by vasorelaxation"],answer:0,explanation:"Abrupt β-blocker withdrawal → rebound tachycardia/angina. Propranolol is NON-selective. Cardioselective blockers are safer (but not safe) in asthma. β-blockers do NOT primarily decrease peripheral resistance."},
  {id:"mid287",exam:"mid2",lecture:"Autocoids (Histamine & Serotonin)",q:"Which of the following is best for seasonal allergic rhinitis?",options:["Loratadine","Cyclizine","Diphenhydramine","Chlorpheniramine"],answer:0,explanation:"Loratadine is a 2nd-generation H1 antihistamine → non-sedating, no anticholinergic effects → preferred for allergic rhinitis. 1st-gen agents (cyclizine, diphenhydramine, chlorphenamine) are sedating."},
  {id:"mid288",exam:"mid2",lecture:"Autocoids (Histamine & Serotonin)",q:"A cancer patient undergoing chemotherapy is given a drug to prevent nausea and vomiting. Which is most likely used?",options:["Metoclopramide","Ondansetron","Domperidone","Prochlorperazine"],answer:1,explanation:"Ondansetron is a 5-HT3 antagonist → highly effective for chemotherapy-induced nausea/vomiting (CINV). Adverse effect: QT prolongation."},
  {id:"mid289",exam:"mid2",lecture:"Autocoids (Histamine & Serotonin)",q:"A patient on warfarin starts cimetidine. Two weeks later, clotting time is prolonged. What is the cause?",options:["Increased renal excretion of warfarin","Decreased hepatic cytochrome P450 activity","Increased hepatic cytochrome P450 activity","Decreased plasma protein binding"],answer:1,explanation:"Cimetidine (H2 blocker) is a potent CYP450 inhibitor → ↓ warfarin metabolism → ↑ warfarin levels → ↑ bleeding risk. Famotidine does NOT inhibit CYP450."},
  {id:"mid290",exam:"mid2",lecture:"Eicosanoids & Kinins",q:"Which of the following causes vasodilation and decreases platelet aggregation?",options:["PGI₂","PGD₂","PGF₂α","PGE₂"],answer:0,explanation:"PGI₂ (prostacyclin, from endothelium): vasodilation + ↓ platelet aggregation. Opposes TXA2 (from platelets: vasoconstriction + ↑ aggregation)."},
  {id:"mid291",exam:"mid2",lecture:"Eicosanoids & Kinins",q:"Which leukotriene is responsible for neutrophil chemotaxis and inflammation?",options:["LTB4","LTD4","LTE4","LTF4"],answer:0,explanation:"LTB4 is a potent neutrophil chemoattractant. LTC4, LTD4, LTE4 (cysteinyl leukotrienes) cause bronchoconstriction and are blocked by montelukast."},
  {id:"mid292",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"NSAIDs exert their therapeutic effect by inhibiting which enzyme?",options:["Phospholipase A2","Cyclooxygenase (COX)","Lipoxygenase","Thromboxane synthase"],answer:1,explanation:"NSAIDs inhibit COX-1 and/or COX-2 → ↓ prostaglandin and thromboxane synthesis → anti-inflammatory, analgesic, antipyretic effects."},
  {id:"mid293",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"A patient with myocardial infarction is given aspirin to prevent thrombus formation. What is the appropriate dose?",options:["81 mg once daily","4 g per day","8 g per day","650 mg every 6 hours"],answer:0,explanation:"Aspirin at low dose (75-150 mg/day): irreversibly inhibits platelet COX-1 → ↓ TXA2 → antiplatelet effect. Higher doses needed for anti-inflammatory (4-8g/day). Low dose preferred for cardiovascular prophylaxis."},
  {id:"mid294",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"Which of the following is a reversible inhibitor of platelet cyclooxygenase?",options:["Leukotrienes","Ibuprofen","Aspirin","Celecoxib"],answer:1,explanation:"Ibuprofen (and most NSAIDs) reversibly inhibit COX-1/COX-2 → platelet function recovers when drug is eliminated. Aspirin irreversibly acetylates COX-1 in platelets → effect lasts platelet lifespan (7–10 days). Celecoxib selectively inhibits COX-2 (not platelet COX-1)."},
  
  {id:"mid296",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"Which of the following patient characteristics is the most compelling reason for avoiding celecoxib?",options:["History of peptic ulcer disease","History of gout","History of myocardial infarction","History of rheumatoid arthritis"],answer:2,explanation:"COX-2 inhibitors (celecoxib) selectively inhibit COX-2 → ↓ PGI2 (vasodilatory) without reducing thromboxane A2 → prothrombotic state → increased risk of MI and stroke. Contraindicated in patients with existing cardiovascular disease."},
  {id:"mid297",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"A 16-year-old girl with aspirin overdose. Which syndrome is most likely?",options:["Bone marrow suppression and aplastic anemia","Fever, hepatic dysfunction, encephalopathy (Reye's)","Hyperthermia, metabolic acidosis, and coma (salicylism)","Rapid, fulminant hepatic failure","Rash, interstitial nephritis, and acute renal failure"],answer:2,explanation:"Salicylate (aspirin) overdose → salicylism: tinnitus, nausea; severe: hyperthermia, metabolic acidosis, respiratory alkalosis (CNS stimulation then depression), coma. Treatment: alkalinize urine (NaHCO3) + renal excretion."},
  {id:"mid298",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"A patient takes an NSAID chronically and develops a gastric ulcer. What type of ADR is this?",options:["Type C","Type B","Type D","Type A"],answer:0,explanation:"Type C (Chronic) ADR = dose- and time-related, occurs with prolonged use. Chronic NSAID use → COX-1 inhibition → ↓ protective prostaglandins → gastric ulcer. This is the classic Type C example per the KAU pharmacology lecture. Type A = acute dose-related extension (e.g., warfarin→bleeding). Type B = unpredictable/immune (e.g., penicillin anaphylaxis)."},
  {id:"mid299",exam:"mid2",lecture:"NSAIDs & Paracetamol",q:"Which of the following is an example of an augmented (Type A) adverse drug reaction?",options:["Cushing syndrome with corticosteroids","Anaphylaxis with penicillin","Bleeding with warfarin","Peptic ulcer with NSAIDs"],answer:2,explanation:"Type A (Augmented) reactions are dose-dependent and predictable extensions of pharmacological action. Bleeding with warfarin = Type A (extension of anticoagulant effect). Note: Cushing's with chronic corticosteroids = Type C (chronic/time-related), NOT Type A. Anaphylaxis with penicillin = Type B (bizarre/immunological). Peptic ulcer with NSAIDs = Type C (chronic use)."},
  {id:"mid2100",exam:"mid2",lecture:"Gout",q:"What is the first-line treatment of acute gout?",options:["Allopurinol","Indomethacin","Probenecid","Colchicine (prophylaxis)"],answer:1,explanation:"NSAIDs (especially indomethacin) are first-line for acute gout attacks. Allopurinol and probenecid are for chronic urate-lowering therapy (NOT given during acute attack). Colchicine is second-line."},
  {id:"mid2101",exam:"mid2",lecture:"Gout",q:"A patient with a history of MI is switched to another xanthine oxidase inhibitor. What adverse effect should be monitored?",options:["Stevens-Johnson syndrome","Nephrolithiasis","Neuropathy","Increased risk of cardiovascular events"],answer:3,explanation:"Febuxostat (xanthine oxidase inhibitor, alternative to allopurinol) → ↑ cardiovascular mortality risk in patients with established CV disease. Allopurinol carries risk of SJS/hypersensitivity rash."},
  {id:"mid2102",exam:"mid2",lecture:"Gout",q:"Which of the following drugs if given with allopurinol must be reduced by 25%?",options:["Mercaptopurine","Mechlorethamine","Methotrexate","Cisplatin"],answer:0,explanation:"Allopurinol inhibits xanthine oxidase → ↓ 6-MP metabolism → accumulation → severe myelosuppression. Dose must be reduced to 25% of normal when used with allopurinol."},
  {id:"mid2103",exam:"mid2",lecture:"DMARDs",q:"What is the first-line treatment of rheumatoid arthritis?",options:["Methotrexate","Ibuprofen","Prednisolone","Hydroxychloroquine"],answer:0,explanation:"Methotrexate is the anchor drug / first-line csDMARD for RA. Given once weekly, requires folic acid supplementation."},
  {id:"mid2104",exam:"mid2",lecture:"DMARDs",q:"Which drug is associated with retinal toxicity and is used in autoimmune diseases?",options:["Methotrexate","Hydroxychloroquine","Sulfasalazine","Leflunomide"],answer:1,explanation:"Hydroxychloroquine deposits in melanin-containing tissues → retinal toxicity (maculopathy). Requires ophthalmologic exam every 6-12 months. Used for SLE, RA."},
  {id:"mid2105",exam:"mid2",lecture:"DMARDs",q:"A patient with severe active RA is started on a targeted synthetic DMARD that inhibits the JAK-STAT signaling pathway. Which adverse effect carries a \"black box\" warning?",options:["Hypothyroidism","Hypoglycemia","Thromboembolic events","Nephrotoxicity"],answer:2,explanation:"JAK inhibitors (tofacitinib, baricitinib) → black box warning for: thromboembolism, serious infections, malignancies, and cardiovascular events. Thrombosis is the key boxed warning."},
  {id:"mid2106",exam:"mid2",lecture:"DMARDs",q:"A woman on methotrexate becomes pregnant. What is the right protocol?",options:["Continue treatment and increase folic acid supplementation","Stop methotrexate immediately due to teratogenicity","Replace with leflunomide which is safer in pregnancy","Switch to hydroxychloroquine and reduce dose gradually"],answer:1,explanation:"Methotrexate is Category X — teratogenic (folic acid antagonist → neural tube defects). Must be stopped immediately; effective contraception required. Leflunomide is ALSO teratogenic and has a very long half-life requiring cholestyramine washout."},
  {id:"mid2107",exam:"mid2",lecture:"DMARDs",q:"Which of the following drugs contains both an anti-inflammatory and antimicrobial component?",options:["Sulfasalazine","Methotrexate","Hydroxychloroquine","Leflunomide"],answer:0,explanation:"Sulfasalazine = sulfapyridine (sulfonamide antimicrobial) + 5-aminosalicylate (anti-inflammatory). Cleaved by colonic bacteria. Used in RA and inflammatory bowel disease."},
  {id:"mid2108",exam:"mid2",lecture:"DMARDs",q:"Sulfasalazine is a combination of which two components?",options:["5-aminosalicylate (5-ASA) + sulfapyridine","Methotrexate + folic acid","Hydroxychloroquine + chloroquine","Leflunomide + sulfapyridine"],answer:0,explanation:"Sulfasalazine is a prodrug consisting of 5-aminosalicylic acid (5-ASA/mesalazine — active anti-inflammatory) linked to sulfapyridine (the carrier). Colonic bacteria cleave the azo bond → releasing 5-ASA locally in the colon → reduces inflammation in ulcerative colitis and Crohn's disease."},
  {id:"mid2109",exam:"mid2",lecture:"Mixed / Other Questions",q:"Which drug is used for testicular carcinoma and can cause nephrotoxicity?",options:["Cisplatin","Bleomycin","Vinblastine","Methotrexate"],answer:0,explanation:"Cisplatin causes proximal tubular nephrotoxicity → prevented by intensive IV hydration. BEP regimen (bleomycin + etoposide + cisplatin). Bleomycin → pulmonary toxicity; vinblastine → neurotoxicity."},
  {id:"mid2110",exam:"mid2",lecture:"Mixed / Other Questions",q:"Which drug would most likely cause cardiac problems?",options:["Doxorubicin"],answer:0,explanation:"Doxorubicin (anthracycline) → cardiotoxicity (dilated cardiomyopathy) via free radical damage. Cumulative dose-dependent."},
  {id:"mid2111",exam:"mid2",lecture:"Mixed / Other Questions",q:"What is the mechanism of action of methotrexate (antineoplastic context)?",options:["Inhibition of dihydrofolate reductase","Inhibition of topoisomerase II","Alkylation of DNA at the N7 position of guanine","Inhibition of thymidylate synthase by forming the FdUMP complex"],answer:0,explanation:"MTX inhibits DHFR → blocks FH2→FH4 conversion → depletes tetrahydrofolate → inhibits both thymidylate synthase (indirect) and purine synthesis. Leucovorin bypasses the block."},
  {id:"mid2112",exam:"mid2",lecture:"Mixed / Other Questions",q:"Which of the following treatments needs leucovorin to increase its efficiency?",options:["5-Fluorouracil","Methotrexate","6-Mercaptopurine","Cyclophosphamide"],answer:0,explanation:"5-FU + leucovorin: leucovorin (reduced folate) stabilizes the ternary complex of FdUMP-thymidylate synthase → prolongs enzyme inhibition → enhanced cytotoxicity. Used in colorectal cancer."},
  {id:"mid2113",exam:"mid2",lecture:"Mixed / Other Questions",q:"What is the mechanism of action of 5-fluorouracil?",options:["Irreversible inhibition of thymidylate synthase","Inhibition of dihydrofolate reductase","Alkylation of DNA at the N7 position of guanine","Inhibition of topoisomerase I"],answer:0,explanation:"5-FU → FdUMP → irreversibly inhibits thymidylate synthase → ↓ dTMP synthesis → ↓ DNA synthesis. It is a pyrimidine antimetabolite, CCS (S-phase)."},
  {id:"mid2114",exam:"mid2",lecture:"Mixed / Other Questions",q:"The first-line treatment for breast cancer with positive receptor:",options:["Interferons","Tamoxifen","Trastuzumab","Cyclophosphamide"],answer:1,explanation:"Tamoxifen (SERM) competitively blocks estrogen receptors in breast tissue → first-line for ER+ breast cancer. Trastuzumab is for HER2+ cancer. Interferons and cyclophosphamide are non-targeted."},
  {id:"mid2115",exam:"mid2",lecture:"Mixed / Other Questions",q:"Administration of filgrastim (G-CSF) is mainly to do what?",options:["Minimize systemic infection in neutropenic patients","Reduce tumor mass in solid tumors","Prevent cardiotoxicity from anthracyclines","Enhance drug delivery to tumor cells"],answer:0,explanation:"Filgrastim (G-CSF) stimulates bone marrow neutrophil production → prevents febrile neutropenia from chemotherapy. Also used after paclitaxel to prevent severe neutropenia."},
  {id:"mid2116",exam:"mid2",lecture:"Mixed / Other Questions",q:"The half-life of a drug is 3 hours. How much time will it take for this drug to be completely eliminated?",options:["9 hours","12 hours","21 hours","4 hours"],answer:1,explanation:"Drug elimination takes ~4-5 half-lives to reach >97% elimination. 5 × 3h = 15h (some say 4 × 3h = 12h for practical purposes). Answer key says 12h."},
  {id:"mid2117",exam:"mid2",lecture:"Mixed / Other Questions",q:"Which enzyme is the main target of zidovudine?",options:["HIV Reverse transcriptase (RNA-dependent DNA polymerase)","HIV Integrase","HIV Protease","Human DNA polymerase"],answer:0,explanation:"Zidovudine (AZT) is a thymidine analog that competitively inhibits HIV reverse transcriptase (RNA-dependent DNA polymerase). Once incorporated into viral DNA, it acts as a chain terminator (lacks 3'-OH). It is classified as an NRTI. Integrase inhibitors (raltegravir) and protease inhibitors (ritonavir) are different HIV drug classes."},
  {id:"mid2118",exam:"mid2",lecture:"Mixed / Other Questions",q:"A female patient with cryptococcal meningitis refused IV medication. What is the best drug?",options:["Fluconazole","Amphotericin B","Ketoconazole","Flucytosine"],answer:0,explanation:"Fluconazole has excellent oral bioavailability (~90%) and good CNS penetration → appropriate oral alternative for cryptococcal meningitis maintenance therapy. Amphotericin B is IV only; ketoconazole does not penetrate CSF."},
  {id:"mid2119",exam:"mid2",lecture:"Mixed / Other Questions",q:"A patient has recurrent UTIs and ciprofloxacin resistance. What is the most likely cause?",options:["Mutation of topoisomerase I","Mutation of DNA gyrase","Production of an active efflux pump"],answer:1,explanation:"Fluoroquinolone resistance: primarily via mutations in DNA gyrase (topoisomerase II) or topoisomerase IV. Efflux pumps are also a mechanism."},
  {id:"mid2120",exam:"mid2",lecture:"Mixed / Other Questions",q:"A patient with S. pneumoniae infection and penicillin allergy (bronchospasm). Which is the best treatment?",options:["Ciprofloxacin","Cefaclor","Ampicillin","Erythromycin"],answer:3,explanation:"Penicillin allergy (anaphylaxis/bronchospasm) → avoid penicillins AND cephalosporins (cross-reactivity). Erythromycin (macrolide) or azithromycin are alternatives for S. pneumoniae in penicillin-allergic patients."},
  {id:"mid2121",exam:"mid2",lecture:"Mixed / Other Questions",q:"What is the main role of clavulanic acid in Augmentin?",options:["Enables amoxicillin to cross the blood-brain barrier","Protects amoxicillin from beta-lactamase destruction","Increases amoxicillin absorption from the GI tract","Prolongs the half-life of amoxicillin in plasma"],answer:1,explanation:"Clavulanic acid is a beta-lactamase inhibitor — it irreversibly binds and inhibits bacterial beta-lactamase → protects amoxicillin from enzymatic hydrolysis → extends its spectrum to beta-lactamase-producing organisms."},
  {id:"mid2122",exam:"mid2",lecture:"Mixed / Other Questions",q:"A boy has pneumonia and was treated with an antibiotic, but it didn't affect him. What is the next antibiotic?",options:["Amoxicillin","Ampicillin","Fluoxetine","Vancomycin"],answer:3,explanation:"If standard antibiotics fail for pneumonia (resistant Streptococcus or MRSA) → vancomycin is the drug of last resort for resistant gram-positive organisms."},
  {id:"mid2123",exam:"mid2",lecture:"Mixed / Other Questions",q:"What is the mechanism of action of terbinafine?",options:["Inhibition of squalene epoxidase causing squalene accumulation","Inhibition of ergosterol synthesis by blocking CYP14α-demethylase","Binding to ergosterol forming pores in the fungal cell membrane","Inhibition of beta-glucan synthase reducing cell wall synthesis"],answer:0,explanation:"Terbinafine selectively inhibits fungal squalene epoxidase → squalene accumulates (toxic) + ergosterol depleted → membrane disruption → fungicidal. B = azole mechanism; C = amphotericin B/nystatin; D = echinocandin."},
  {id:"mid2124",exam:"mid2",lecture:"Mixed / Other Questions",q:"A doctor wanted to give a neonate chloramphenicol but was worried about gray baby syndrome. What would increase the baby's risk?",options:["Decreased hepatic glucuronyl transferase activity in the neonate","Decreased renal excretion of the drug","Increased renal clearance rate","Decreased blood-brain barrier permeability"],answer:0,explanation:"Neonates have immature UDP-glucuronosyltransferase → cannot conjugate chloramphenicol → accumulation → cardiovascular collapse, abdominal distension, ashen-gray color."},
  {id:"mid2125",exam:"mid2",lecture:"Mixed / Other Questions",q:"Which of the following binds reversibly to the 50S ribosomal subunit and inhibits the peptidyl transferase reaction?",options:["Chloramphenicol","Linezolid","Erythromycin","Clindamycin"],answer:0,explanation:"Chloramphenicol specifically inhibits the peptidyl transferase reaction on the 50S subunit (bacteriostatic). Linezolid also binds 50S but inhibits the 70S initiation complex. Erythromycin inhibits translocation; clindamycin acts similarly to erythromycin."},
  {id:"mid2126",exam:"mid2",lecture:"Mixed / Other Questions",q:"A 21-year-old with cutaneous anthrax is prescribed ciprofloxacin. Which should he avoid taking with ciprofloxacin?",options:["Alcohol","Grapefruit juice","Antacids","High-fat meal"],answer:2,explanation:"Antacids (Al³⁺, Mg²⁺, Ca²⁺) chelate ciprofloxacin → reduce absorption by up to 90%. Must be taken at least 2 hours apart. Grapefruit and alcohol have no significant interaction with ciprofloxacin."},
  {id:"mid2127",exam:"mid2",lecture:"Mixed / Other Questions",q:"A patient is given a drug targeting dihydropteroate synthase. What is the most common adverse effect?",options:["Skin rash and hypersensitivity reactions","Kernicterus in neonates","Nephrotoxicity from crystalluria","Hepatotoxicity with elevated liver enzymes"],answer:0,explanation:"Sulfonamides (dihydropteroate synthase inhibitors): most common adverse effect = skin rash (urticaria, erythema multiforme, Stevens-Johnson syndrome). Kernicterus occurs specifically in neonates. Crystalluria occurs but is prevented by hydration."},
  {id:"mid2128",exam:"mid2",lecture:"Mixed / Other Questions",q:"A drug made of sulfamethoxazole and trimethoprim. Mechanism of action?",options:["Inhibiting two sequential steps in the bacterial folate synthesis pathway","Inhibiting bacterial cell wall crosslinking","Binding to the 30S ribosomal subunit","Inhibiting bacterial RNA polymerase"],answer:0,explanation:"Sequential blockade: SMX inhibits dihydropteroate synthase; TMP inhibits DHFR → both block folate pathway at consecutive steps → synergistic bactericidal effect. Human cells use dietary folate → selective toxicity."},
  {id:"mid2129",exam:"mid2",lecture:"Mixed / Other Questions",q:"Drug A at 5 mg produces the same BP decrease as Drug B at 500 mg. What does this indicate?",options:["Drug A is 100 times more potent than Drug B","Drug A produces a greater maximum effect than Drug B","Drug A is less toxic than Drug B","Drug A has a higher therapeutic index than Drug B"],answer:0,explanation:"Potency = dose required for a specified effect. Drug A requires 100× less → 100× more potent. Both produce the same effect (equal efficacy). No information about toxicity or therapeutic index."},
  {id:"mid2130",exam:"mid2",lecture:"Mixed / Other Questions",q:"What drug is used to prepare a patient for colon surgery?",options:["Neomycin","Gentamicin","Metronidazole","Vancomycin"],answer:0,explanation:"Neomycin (non-absorbable aminoglycoside) is given orally before GI surgery → reduces intestinal flora → decreases postoperative infection risk. Its severe nephrotoxicity prevents parenteral use."},
  {id:"mid2131",exam:"mid2",lecture:"Mixed / Other Questions",q:"Drug that increases intraocular pressure and causes cycloplegia?",options:["Cyclopentolate","Pilocarpine","Physostigmine","Timolol"],answer:0,explanation:"Cyclopentolate is a synthetic antimuscarinic (mydriatic-cycloplegic): blocks M3 → pupil dilation + ciliary muscle relaxation (cycloplegia) + ↑ IOP (reduces aqueous outflow). Contraindicated in narrow-angle glaucoma. Pilocarpine and physostigmine are cholinergic → reduce IOP."},
  {id:"mid2132",exam:"mid2",lecture:"Mixed / Other Questions",q:"If a male patient takes a drug that causes breast enlargement (gynecomastia), what is the drug?",options:["Ketoconazole"],answer:0,explanation:"Ketoconazole inhibits CYP enzymes → ↓ testosterone synthesis → gynecomastia. Cimetidine (H2 blocker) is also a classic cause via antiandrogen effect."},
  {id:"mid2133",exam:"mid2",lecture:"Mixed / Other Questions",q:"What is the best scenario for treating a patient with rimantadine over amantadine?",options:["Pregnant woman requiring influenza A prophylaxis","Patient with Parkinson's disease","Patient with epilepsy","Patient with renal failure"],answer:3,explanation:"Rimantadine is hepatically metabolized → does NOT accumulate in renal failure (unlike amantadine which is renally excreted → accumulates and causes neurotoxicity in renal failure). Both amantadine and rimantadine are teratogenic in animals → caution in pregnancy. Amantadine is used for Parkinson's; neither is indicated for epilepsy."}
];
const FINAL_QUESTIONS: Question[] = [
  {id:"final1",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which of the following antibiotics would be best given to a patient with penicillinase-producing Staphylococcus aureus pneumonia?",options:["Carbenicillin","Ampicillin","Piperacillin","Oxacillin"],answer:3,explanation:"Oxacillin is an antistaphylococcal (beta-lactamase-resistant) penicillin — unaffected by penicillinase. Ampicillin and carbenicillin are destroyed by beta-lactamase."},
  {id:"final2",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient with Pseudomonas aeruginosa is receiving IV gentamicin with poor response. Penicillin is added in a separate IV line. What will occur?",options:["Colitis due to C. difficile may develop","Penicillin will enhance the bacterial response to aminoglycoside","Penicillin will increase the risk of aminoglycoside nephrotoxicity","Chemical neutralization and termination of penicillin effects"],answer:1,explanation:"Penicillins (by disrupting cell wall) enhance bacterial uptake of aminoglycosides → synergistic bactericidal effect. They must be given in separate IV lines to avoid chemical inactivation."},
  {id:"final3",exam:"final",lecture:"Cell Wall Inhibitors",q:"Beta-lactamase production is a resistance mechanism in H. influenzae, Moraxella catarrhalis, and N. gonorrhoeae. Which drug is most likely effective against ALL three?",options:["Ceftriaxone","Amoxicillin","Clindamycin","TMP-SMX"],answer:0,explanation:"Ceftriaxone (3rd gen cephalosporin) is resistant to beta-lactamase and has broad G- coverage including all three organisms. Amoxicillin is destroyed by beta-lactamase."},
  {id:"final4",exam:"final",lecture:"Cell Wall Inhibitors",q:"A woman on epilepsy medication has a UTI. Which antibiotic should be avoided?",options:["Vancomycin","Ceftriaxone","Imipenem","Aztreonam"],answer:2,explanation:"Imipenem (carbapenem) causes CNS toxicity/seizures at high plasma levels — especially dangerous in patients with pre-existing epilepsy or CNS disorders. Meropenem is preferred over imipenem in such patients as it is less epileptogenic."},
  {id:"final5",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient with penicillin allergy (bronchospasm) presents with S. pneumoniae infection. Best choice?",options:["Ciprofloxacin","Cefaclor","Ampicillin","Erythromycin"],answer:3,explanation:"Erythromycin (macrolide) is the drug of choice for patients allergic to penicillin with G+ infections. Cefaclor is a cephalosporin with possible cross-sensitivity. Ciprofloxacin has limited activity against S. pneumoniae."},
  {id:"final6",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient received IV vancomycin too rapidly and developed marked flushing and itching over the chest, neck, and face. What antibiotic caused this?",options:["Amoxicillin","Daptomycin","Linezolid","Vancomycin"],answer:3,explanation:"\"Red man syndrome\" — rapid IV infusion of vancomycin causes histamine release → flushing, pruritus over chest/neck/face. Prevented by infusing over at least 60 minutes."},
  {id:"final7",exam:"final",lecture:"Cell Wall Inhibitors",q:"A 10-year-old swimmer develops otitis externa due to a gram-negative organism. Best treatment?",options:["Ampicillin + Tazobactam","Vancomycin + Tazobactam","Piperacillin + Tazobactam"],answer:2,explanation:"Swimmer's ear is commonly caused by Pseudomonas aeruginosa (G-). Piperacillin is an antipseudomonal penicillin; adding tazobactam (beta-lactamase inhibitor) extends coverage."},
  {id:"final8",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient with pseudomembranous colitis is allergic to metronidazole. Which drug is most appropriate?",options:["Vancomycin","Clindamycin","Doxycycline","Ampicillin"],answer:0,explanation:"Vancomycin given orally (not absorbed from GIT) is effective against C. difficile. First-line is metronidazole; vancomycin oral is used when metronidazole is contraindicated or fails."},
  {id:"final9",exam:"final",lecture:"Cell Wall Inhibitors",q:"Augmentin consists of clavulanic acid + amoxicillin. What is the main role of clavulanic acid?",options:["Enables crossing the BBB","Protects amoxicillin from beta-lactamase"],answer:1,explanation:"Clavulanic acid is a beta-lactamase inhibitor — it irreversibly binds and inhibits beta-lactamase enzymes, protecting amoxicillin from enzymatic destruction and extending its spectrum."},
  {id:"final10",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient had recurrent UTIs and acquired resistance to ciprofloxacin. What is the most likely mechanism?",options:["Mutation of topoisomerase I","Mutation of DNA gyrase","Production of active efflux pump"],answer:1,explanation:"Quinolone resistance is most commonly due to mutations in DNA gyrase (topoisomerase II) — the primary target — reducing drug binding affinity. Efflux pumps also contribute."},
  {id:"final11",exam:"final",lecture:"Cell Wall Inhibitors",q:"A gram-negative cocci infection + penicillin allergy history (anaphylaxis). Which drug is contraindicated?",options:["Ceftriaxone","Erythromycin","Ciprofloxacin","Doxycycline"],answer:0,explanation:"Patients with history of anaphylaxis to penicillin should NOT receive cephalosporins (including ceftriaxone) due to cross-sensitivity (~5–10%). Aztreonam is the safe alternative for G- coverage in penicillin-allergic patients."},
  {id:"final12",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which of the following tetracyclines does NOT require renal excretion and does not accumulate in renal failure?",options:["Minocycline","Doxycycline","Oxytetracycline","Tetracycline"],answer:1,explanation:"Doxycycline is eliminated primarily via bile into feces (not the kidney) — making it the only tetracycline safe to use in renal dysfunction. All others accumulate in renal failure."},
  {id:"final13",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which drug is most effective for treating Rickettsia, Mycoplasma, and Chlamydia infections?",options:["Tetracycline","Penicillin G","Vancomycin","Gentamicin"],answer:0,explanation:"Tetracyclines are broad-spectrum and are the drug of choice for intracellular organisms: Rickettsia (Rocky Mountain spotted fever), Mycoplasma pneumoniae, and Chlamydia infections."},
  {id:"final14",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which drug is most suitable to treat Chlamydia, Rickettsia, and Acne?",options:["Tetracycline"],answer:0,explanation:"Tetracyclines (especially doxycycline) cover all three: intracellular organisms (Rickettsia, Chlamydia) and acne vulgaris (via anti-inflammatory and antibacterial effects against P. acnes)."},
  {id:"final15",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which of the following is a primarily bacteriostatic antibiotic that is bactericidal at high concentrations?",options:["Ethambutol","Ampicillin","Erythromycin","Tetracycline"],answer:2,explanation:"Macrolides (erythromycin) are bacteriostatic at normal doses and bactericidal at high concentrations. Beta-lactams (ampicillin) are always bactericidal; tetracyclines are bacteriostatic."},
  {id:"final16",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which drug binds reversibly to the 50S ribosomal subunit and inhibits the peptidyl transferase reaction?",options:["Chloramphenicol","Linezolid"],answer:0,explanation:"Chloramphenicol binds reversibly to the 50S subunit and specifically inhibits the peptidyl transferase reaction. Linezolid binds to 23S rRNA of the 50S subunit but inhibits the 70S initiation complex formation."},
  {id:"final17",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A neonate is given chloramphenicol and develops gray baby syndrome. What increased the risk?",options:["Decreasing conjugation in the liver","Decreasing excretion"],answer:0,explanation:"Neonates have decreased glucuronyl transferase activity → cannot adequately conjugate (inactivate) chloramphenicol → drug accumulates → bone marrow suppression and cyanosis (\"gray baby syndrome\")."},
  {id:"final18",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A patient treated with clindamycin. Which organism was most likely the causative agent?",options:["E. coli","Bacteroides fragilis","Klebsiella","C. difficile"],answer:1,explanation:"Clindamycin is used for anaerobic infections, especially Bacteroides fragilis (penetrating wounds, intra-abdominal infections), and bone infections. It should NOT be used against C. difficile — it causes CDI."},
  {id:"final19",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Superinfection results from?",options:["Long-term use of broad-spectrum antimicrobials","Long-term use of narrow-spectrum antimicrobials","Short-term use of broad-spectrum antimicrobials","Short-term use of narrow-spectrum antimicrobials"],answer:0,explanation:"Long-term broad-spectrum antibiotic use kills normal flora, allowing resistant organisms (especially C. difficile) to overgrow → superinfection. Highest risk: broad-spectrum penicillins, cephalosporins, quinolones, and clindamycin."},
  {id:"final20",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which drug is used for bacteremia from Pseudomonas (gram-negative aerobic)? Addition of gentamicin provides coverage against:",options:["Klebsiella pneumoniae","MRSA","Legionella","Bacteroides fragilis"],answer:0,explanation:"Aminoglycosides (gentamicin) are uniquely bactericidal against aerobic G- organisms: Pseudomonas, E. coli, Klebsiella pneumoniae. They are ineffective against anaerobes and cannot cross BBB."},
  {id:"final21",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Patient taking this antibiotic must be given supplementary folinic acid to prevent folate deficiency anemia. What is the drug?",options:["Linezolid","Ciprofloxacin","Trimethoprim","Levofloxacin"],answer:2,explanation:"Trimethoprim inhibits dihydrofolate reductase → folate deficiency → megaloblastic anemia. Folinic acid (leucovorin) supplementation bypasses the block and prevents this adverse effect."},
  {id:"final22",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"The most appropriate drug to manage pseudomembranous colitis (C. difficile)?",options:["Metronidazole","Ampicillin"],answer:0,explanation:"Metronidazole (oral) is first-line for C. difficile pseudomembranous colitis. Vancomycin oral is an alternative. Ampicillin is a broad-spectrum penicillin that can itself cause CDI."},
  {id:"final23",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 35-year-old hepatitis C patient, a few hours after starting therapy, develops fever, chills, and muscle aches. Which drug most likely caused this?",options:["Entecavir","Lamivudine","Interferon alpha","Adefovir"],answer:2,explanation:"Interferon-alpha causes flu-like symptoms (fever, chills, myalgia, fatigue) at the start of treatment — very common, dose-dependent side effect. Patients are warned about this."},
  {id:"final24",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"A 24-year-old woman is treated with sulfisoxazole for UTI. A contraindication to its use is history of which condition?",options:["Glucose-6-phosphate deficiency","Gout","Deep venous thrombosis","Tendinitis"],answer:0,explanation:"Sulfonamides cause hemolytic anemia in G6PD-deficient patients due to oxidative stress. Also contraindicated in pregnancy at term (kernicterus) and infants < 2 months."},
  {id:"final25",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"A 15-year-old girl with E. coli pyelonephritis — why was ciprofloxacin not preferred?",options:["Ciprofloxacin can induce cartilage erosion","Ciprofloxacin is nephrotoxic","Ciprofloxacin is bacteriostatic","Ciprofloxacin is effective in GIT, not urine"],answer:0,explanation:"Fluoroquinolones cause arthropathy (cartilage damage and tendinitis) in patients < 18 years — contraindicated in children and adolescents. Also contraindicated in pregnancy."},
  {id:"final26",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"A 50-year-old man started an antibiotic for acute prostatitis 1 week ago and now presents with sharp left calf pain. Which drug likely caused this?",options:["Trimethoprim","Erythromycin","Co-trimoxazole","Levofloxacin"],answer:3,explanation:"Fluoroquinolones (especially levofloxacin) cause tendinitis and tendon rupture — risk is higher in patients > 60 years, on corticosteroids, or with organ transplants. Prostatitis is a key indication for levofloxacin."},
  {id:"final27",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Which drugs may prolong QT interval and should not be used in patients predisposed to dysrhythmias?",options:["Ciprofloxacin","Moxifloxacin"],answer:1,explanation:"3rd and 4th generation fluoroquinolones (moxifloxacin, levofloxacin, gatifloxacin, sparfloxacin) prolong the QT interval. Ciprofloxacin (2nd gen) has minimal QT effect. Moxifloxacin should be avoided in cardiac patients."},
  {id:"final28",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"A 21-year-old man with cutaneous anthrax is given ciprofloxacin. What should he avoid taking with it?",options:["Alcohol","Grapefruit juice","Antacids"],answer:2,explanation:"Antacids (containing aluminum, magnesium), calcium supplements, iron, and zinc chelate ciprofloxacin → reduce absorption. Sucralfate has the same effect. Ciprofloxacin is the DOC for anthrax prophylaxis/treatment."},
  {id:"final29",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Beta-lactamase production is a common resistance mechanism in H. influenzae, Moraxella catarrhalis, and N. gonorrhoeae. Which is most likely effective against ALL strains?",options:["Ceftriaxone","Amoxicillin","Clindamycin","TMP-SMX"],answer:0,explanation:"(See Q3 — same question.) Ceftriaxone (3rd gen cephalosporin) has intrinsic resistance to most beta-lactamases and broad G- coverage."},
  {id:"final30",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"A community-acquired pneumonia patient has a history of severe ampicillin allergy (anaphylaxis). Which is acceptable treatment?",options:["Levofloxacin","Ciprofloxacin","Penicillin","Sulfamethoxazole"],answer:0,explanation:"Levofloxacin is a respiratory fluoroquinolone with excellent S. pneumoniae activity — the preferred alternative in penicillin-allergic patients. Ciprofloxacin (2nd gen) has poor anti-pneumococcal activity."},
  {id:"final31",exam:"final",lecture:"Antifungal Drugs",q:"Which antifungal drug inhibits squalene epoxidase?",options:["Terbinafine"],answer:0,explanation:"Terbinafine selectively inhibits fungal squalene epoxidase → accumulation of toxic squalene → cell death. Drug of choice for dermatophytes, especially onychomycosis (nail infections). Better tolerated and shorter duration than griseofulvin."},
  {id:"final32",exam:"final",lecture:"Antifungal Drugs",q:"What is the mechanism of action of flucytosine?",options:["Inhibits thymidylate synthase"],answer:0,explanation:"Flucytosine is converted inside the fungal cell to 5-FU → then to 5F-dUMP → inhibits thymidylate synthase → inhibits DNA/RNA synthesis. Synergistic with amphotericin B (which increases cell permeability allowing more 5-FC entry)."},
  {id:"final33",exam:"final",lecture:"Antifungal Drugs",q:"What is the mechanism of action of miconazole (and other azoles)?",options:["Inhibits ergosterol synthesis","Inhibits lanosterol conversion to ergosterol"],answer:1,explanation:"Azoles inhibit cytochrome P450-dependent C14-α-demethylase enzyme → blocks lanosterol→ergosterol conversion → depletes ergosterol → disrupts fungal cell membrane. This is the mechanism of all azoles (imidazoles and triazoles)."},
  {id:"final34",exam:"final",lecture:"Antifungal Drugs",q:"An HIV patient developed systemic candidiasis. An antifungal was given IV but later caused elevated liver enzymes. Which drug was most likely given?",options:["Ketoconazole","Flucytosine"],answer:0,explanation:"Ketoconazole frequently causes liver toxicity (hepatotoxicity). It also inhibits adrenal/gonadal steroid synthesis and has many drug interactions. It is rarely used systemically due to toxicity — fluconazole is preferred."},
  {id:"final35",exam:"final",lecture:"Antifungal Drugs",q:"Which of the following antifungal drugs is a polyene?",options:["Amphotericin B"],answer:0,explanation:"Polyenes (amphotericin B, nystatin) bind directly to ergosterol in the fungal cell membrane, forming pores → leakage of intracellular contents → cell death. This mechanism is different from azoles."},
  {id:"final36",exam:"final",lecture:"Antifungal Drugs",q:"A 37-year-old AIDS patient with systemic candidiasis received IV antifungal treatment. Lab results: elevated creatinine/BUN, hypokalemia. Which drug caused this?",options:["Griseofulvin","Fluconazole","Flucytosine","Amphotericin B"],answer:3,explanation:"Amphotericin B causes dose-dependent nephrotoxicity (↑creatinine, ↑BUN) and hypokalemia (requiring K+ supplementation). IV normal saline before/after infusion helps reduce nephrotoxicity. Liposomal formulations are less nephrotoxic."},
  {id:"final37",exam:"final",lecture:"Antifungal Drugs",q:"Which drug is least likely to be effective in esophageal candidiasis if used orally?",options:["Griseofulvin","Clotrimazole","Nystatin","Ketoconazole"],answer:0,explanation:"Griseofulvin is active only against dermatophytes — it has NO activity against Candida. Clotrimazole, nystatin (local action), and ketoconazole all have anti-Candida activity."},
  {id:"final38",exam:"final",lecture:"Antifungal Drugs",q:"A patient with Aspergillus lung infection. Which drug is appropriate?",options:["Nystatin","Flucytosine","Terbinafine","Fluconazole"],answer:3,explanation:"For Aspergillus: voriconazole is now first-line (replaced amphotericin B). Fluconazole (D) — while not the best — may be chosen if voriconazole unavailable. Itraconazole also has activity. Nystatin and fluconazole differ in Aspergillus coverage; the correct answer from this question bank is D."},
  {id:"final39",exam:"final",lecture:"Antifungal Drugs",q:"A patient is given both fluconazole and warfarin simultaneously. What will most likely result?",options:["Bleeding due to increased warfarin levels"],answer:0,explanation:"Fluconazole inhibits hepatic CYP2C9 → decreases warfarin metabolism → elevated warfarin levels → increased bleeding risk. Azoles are potent enzyme inhibitors causing many drug interactions."},
  {id:"final40",exam:"final",lecture:"Antifungal Drugs",q:"Anti-fungal drug used only topically due to systemic toxicity, active against most Candida species:",options:["Terbinafine","Nystatin","Fluconazole","Miconazole"],answer:1,explanation:"Nystatin has similar mechanism to amphotericin B (binds ergosterol) but is too toxic for systemic use. Used topically for oral thrush, vaginal candidiasis, and GI candidiasis. Not absorbed systemically after oral administration."},
  {id:"final41",exam:"final",lecture:"Antiparasitic Drugs",q:"Metronidazole mechanism in parasitic infections:",options:["Binds to ergosterol forming pores","Inhibits microtubule formation","Activated as a prodrug in anaerobes → free radicals → DNA damage","Inhibits neuraminidase"],answer:2,explanation:"Metronidazole is a prodrug reduced only in anaerobic organisms → free radicals → DNA strand breaks → cell death. Used for Giardia, Entamoeba, and anaerobic bacteria. Causes metallic taste and disulfiram-like reaction with alcohol."},
  {id:"final42",exam:"final",lecture:"Antiparasitic Drugs",q:"First-line drug for dermatophyte nail infections (onychomycosis):",options:["Nystatin","Amphotericin B","Terbinafine","Fluconazole"],answer:2,explanation:"Terbinafine is drug of choice for dermatophytes especially nail infections — shorter duration (3 months), better tolerated, and more effective than griseofulvin or itraconazole."},
  {id:"final43",exam:"final",lecture:"Antiviral Drugs",q:"Which statement about the mechanisms of action of antiviral drugs is accurate?",options:["Interferon-α increases activity of host cell ribonucleases that degrade viral mRNA","Cidofovir has no requirement for phosphorylation","Ganciclovir inhibits viral DNA polymerase but does not cause chain termination","The initial step in foscarnet activation in HSV-infected cells is phosphorylation by thymidine kinase"],answer:0,explanation:"Interferons induce synthesis of host cell enzymes (including ribonucleases) that degrade viral mRNA and inhibit viral protein translation. Foscarnet does NOT require phosphorylation (unlike acyclovir)."},
  {id:"final44",exam:"final",lecture:"Antiviral Drugs",q:"An HIV patient presents with acute pancreatitis. Which drug in his regimen (zidovudine, didanosine, ritonavir, acyclovir, ketoconazole) is most likely responsible?",options:["Acyclovir","Didanosine","Ketoconazole","Verapamil"],answer:1,explanation:"Didanosine (NRTI) is known for dose-dependent pancreatitis and peripheral neuropathy as its major adverse effects. It should be avoided in patients with risk factors for pancreatitis."},
  {id:"final45",exam:"final",lecture:"Antiviral Drugs",q:"The drug causing pancreatitis in Q44 should be withdrawn and replaced by:",options:["Atazanavir","Cidofovir","Foscarnet","Lamivudine"],answer:3,explanation:"Lamivudine is another NRTI that can replace didanosine — it does not cause pancreatitis. Lamivudine also has activity against HBV."},
  {id:"final46",exam:"final",lecture:"Antiviral Drugs",q:"Which statement about antiviral agents is accurate?",options:["Dosage modification of nevirapine is required in renal insufficiency","Interferons prevent dissemination of herpes zoster in cancer patients","Oral valacyclovir requires multiple daily doses due to short half-life","Peripheral neuropathy is the major dose-limiting toxic effect of ganciclovir"],answer:1,explanation:"Interferons are used in immunocompromised cancer patients to prevent herpes zoster dissemination. Ganciclovir's dose-limiting toxicity is myelosuppression (neutropenia), not neuropathy. Valacyclovir has improved bioavailability vs acyclovir."},
  {id:"final47",exam:"final",lecture:"Antiviral Drugs",q:"Needlestick injury from an AIDS patient (CD4=20, viral load >10⁷ copies/mL). Most appropriate treatment for the nurse?",options:["Single doses of ritonavir and zidovudine","Zidovudine full doses for 2 weeks","Monitor blood to determine if transmission occurred","Zidovudine + lamivudine + a protease inhibitor for 4 weeks"],answer:3,explanation:"Post-exposure prophylaxis (PEP) for high-risk HIV exposure: triple HAART regimen for 4 weeks. A 3-drug regimen (2 NRTIs + 1 PI) is recommended due to high viral load in source patient."},
  {id:"final48",exam:"final",lecture:"Antiviral Drugs",q:"In an AIDS patient on HAART + prophylactics, which drug suppresses herpetic infections and provides CMV retinitis prophylaxis?",options:["Fluconazole","Indinavir","Rifampin","Valganciclovir"],answer:3,explanation:"Valganciclovir (prodrug of ganciclovir) is used for CMV prophylaxis and treatment in immunocompromised patients. Ganciclovir/valganciclovir is DOC for CMV retinitis."},
  {id:"final49",exam:"final",lecture:"Antiviral Drugs",q:"Why may the dose of indinavir need to be increased in a patient also taking rifampin?",options:["Fluconazole slows gastric emptying","Indinavir must be taken with meals","Rifampin increases liver drug-metabolizing enzymes","Sulfamethoxazole displaces indinavir from plasma proteins"],answer:2,explanation:"Rifampin is a potent CYP enzyme inducer → accelerates metabolism of protease inhibitors (like indinavir) → lower plasma levels. Dose adjustment or alternative regimen is needed."},
  {id:"final50",exam:"final",lecture:"Antiviral Drugs",q:"Which drug causes additive anemia and neutropenia when combined with zidovudine in an AIDS patient?",options:["Acyclovir","Amantadine","Ganciclovir","Pentamidine"],answer:2,explanation:"Both ganciclovir and zidovudine cause myelosuppression — using them together greatly increases risk of severe neutropenia and anemia. This combination requires careful monitoring or avoidance."},
  {id:"final51",exam:"final",lecture:"Antiviral Drugs",q:"A nursing mother with genital herpes who previously responded to topical treatment needs oral therapy. Which drug?",options:["Amantadine","Foscarnet","Ritonavir","Valacyclovir"],answer:3,explanation:"Valacyclovir is the preferred oral agent for genital herpes — better bioavailability than acyclovir (converted to acyclovir after absorption), fewer daily doses. Foscarnet is reserved for resistant HSV."},
  {id:"final52",exam:"final",lecture:"Antiviral Drugs",q:"Which drug blocks HIV entry by binding to the CCR5 receptor of CD4 cells?",options:["Abacavir","Adefovir","Enfuvirtide","Maraviroc"],answer:3,explanation:"Maraviroc is a CCR5 antagonist (entry inhibitor) — blocks the CCR5 co-receptor on CD4+ cells, preventing HIV attachment. Enfuvirtide is a fusion inhibitor (different mechanism — blocks gp41 fusion)."},
  {id:"final53",exam:"final",lecture:"Antiviral Drugs",q:"Regarding interferon-α, which statement is FALSE?",options:["At start of treatment, most patients experience flu-like symptoms","Indications include treatment of genital warts","It is used in hepatitis B and C management","Lamivudine interferes with its activity against hepatitis B"],answer:3,explanation:"Lamivudine does NOT interfere with interferon activity — in fact, combination of interferon + lamivudine was studied for HBV but offered no extra benefit over lamivudine alone. All other statements are true."},
  {id:"final54",exam:"final",lecture:"Antiviral Drugs",q:"More than 90% of this drug is excreted in urine intact. Low urinary solubility requires adequate hydration to prevent nephrotoxicity. Which drug?",options:["Acyclovir","Amantadine","Indinavir","Trifluridine"],answer:0,explanation:"Acyclovir is >90% renally excreted. Crystalluria occurs with IV use, especially in dehydrated patients or with rapid infusion. Adequate hydration and slow infusion rate prevent this."},
  {id:"final55",exam:"final",lecture:"Antiviral Drugs",q:"Used in prophylaxis and treatment of influenza A & B including H1N1, this drug facilitates clumping of mature virions:",options:["Amantadine","Efavirenz","Oseltamivir","Rimantadine"],answer:2,explanation:"Oseltamivir (neuraminidase inhibitor) prevents release and spread of newly synthesized virions by inhibiting neuraminidase enzyme. Unlike amantadine, it is effective against both influenza A and B. Must be given within 24–48 hours of symptom onset."},
  {id:"final56",exam:"final",lecture:"Antiviral Drugs",q:"Which antiretroviral drugs are safe to use in pregnancy?",options:["Lamivudine","Lopinavir/ritonavir","Nevirapine","Zidovudine","All of the drugs listed above"],answer:4,explanation:"All listed antiretrovirals are categorized as acceptable in pregnancy. Zidovudine is classically used to prevent mother-to-child HIV transmission. Nevirapine (single dose) is given at onset of labor to prevent perinatal transmission."},
  {id:"final57",exam:"final",lecture:"Antiviral Drugs",q:"Which enzyme is the main target of zidovudine?",options:["RNA synthesis","Protease inhibitor","Nucleoside reverse transcriptase inhibitor","Non-nucleoside reverse transcriptase inhibitor"],answer:2,explanation:"Zidovudine (AZT) is an NRTI — it is phosphorylated by host kinases to the active triphosphate, which competitively inhibits HIV reverse transcriptase and causes chain termination of viral DNA."},
  {id:"final58",exam:"final",lecture:"Antiviral Drugs",q:"A patient with HSV encephalitis — physician advises drinking large amounts of water to avoid adverse effects. Which drug was given?",options:["Acyclovir"],answer:0,explanation:"IV acyclovir for HSV encephalitis — adequate hydration prevents crystalluria/nephrotoxicity. Acyclovir is the drug of choice for HSV encephalitis, including in immunocompromised patients."},
  {id:"final59",exam:"final",lecture:"Antiviral Drugs",q:"What is the drug of choice for CMV retinitis?",options:["Ganciclovir"],answer:0,explanation:"Ganciclovir (IV) or valganciclovir (oral prodrug) is DOC for CMV retinitis in immunocompromised patients (HIV/transplant). Major adverse effect: myelosuppression (neutropenia)."},
  {id:"final60",exam:"final",lecture:"Antiviral Drugs",q:"What is a component of HAART?",options:["Nucleoside reverse transcriptase inhibitor"],answer:0,explanation:"HAART (highly active antiretroviral therapy) typically = 2 NRTIs + 1 NNRTI or protease inhibitor. This combination suppresses viral replication from multiple steps and delays resistance development."},
  {id:"final61",exam:"final",lecture:"Antiviral Drugs",q:"A patient's physician added ritonavir to the drug regimen. Why?",options:["Synergistic effect","Additive effect","Ritonavir is an enzyme inhibitor (pharmacokinetic booster)"],answer:2,explanation:"Ritonavir is a potent CYP3A4 inhibitor. At low doses, it inhibits metabolism of co-administered protease inhibitors (\"boosting\") → higher and more sustained plasma levels of the second PI. No longer used as a standalone PI."},
  {id:"final62",exam:"final",lecture:"Antiviral Drugs",q:"Which antiviral drug is contraindicated in pregnant women?",options:["Ribavirin","Lamivudine"],answer:0,explanation:"Ribavirin is teratogenic and mutagenic — absolutely contraindicated in pregnancy (Category X). It also causes dose-dependent hemolytic anemia by accumulating in RBCs. Lamivudine is safe in pregnancy."},
  {id:"final63",exam:"final",lecture:"Antiviral Drugs",q:"A 60-year-old man with Parkinson's disease needs prophylaxis against influenza A. Which mechanism of action is most efficient for this purpose?",options:["Prevents viral replication","Prevents viral uncoating","Prevents release of newly synthesized viruses"],answer:1,explanation:"Amantadine inhibits viral uncoating and release of RNA into host cells. As a bonus, amantadine is also used for Parkinson's disease (dopamine-releasing effect). It is effective only against influenza A, unlike oseltamivir."},
  {id:"final64",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Anticancer drugs kill:",options:["Certain numbers of the cells","All cells","Certain percentage of the cells","Resting cells","A + D"],answer:2,explanation:"First-order kinetics: anticancer drugs kill a constant FRACTION (percentage) of tumor cells per dose, not a fixed number. A given dose kills the same proportion regardless of tumor size (Gompertzian kinetics)."},
  {id:"final65",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"The Gompertzian equation describes the relation between:",options:["Number of cells and time","Tumor mass and sensitivity to anticancer drugs","Slowly and rapidly proliferating cells","CCS and CCNS drugs","All of the above"],answer:0,explanation:"The Gompertz equation describes tumor growth kinetics — the relationship between number of cells and time. Tumors grow rapidly when small, then slow as they get larger (due to nutrient/oxygen limitations)."},
  {id:"final66",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"All of the following organs show rapid proliferation making them susceptible to anticancer toxicity EXCEPT:",options:["Ovary","Bone marrow","Testis","Hair follicle","Nerve"],answer:4,explanation:"Nerves are post-mitotic cells (slow/non-dividing). Rapidly proliferating normal tissues most susceptible to cytotoxic damage: bone marrow, GI mucosa, hair follicles, gonads (ovary, testis)."},
  {id:"final67",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Methotrexate is considered:",options:["Cell-cycle specific anticancer drug","Cell-cycle nonspecific anticancer drug","An alkylating agent","Topoisomerase inhibitor","Antibiotic anticancer drug"],answer:0,explanation:"Methotrexate is a folate antagonist antimetabolite — CCS (S-phase specific). It inhibits DHFR → blocks DNA/RNA synthesis. Alkylating agents and cisplatin are CCNS."},
  {id:"final68",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Antidote for high methotrexate levels is:",options:["Folic acid","MESNA","Desferrioxamine","Leucovorin"],answer:3,explanation:"Leucovorin (folinic acid) is the antidote for MTX toxicity — it bypasses the blocked DHFR enzyme and replenishes the folate pool (\"leucovorin rescue\"). Standard folic acid is NOT effective."},
  {id:"final69",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Methotrexate acts by inhibition of:",options:["Dihydrofolate reductase","Topoisomerase I","Topoisomerase II","Thymidylate synthetase"],answer:0,explanation:"MTX inhibits DHFR → prevents conversion of FH2→FH4 → depletes reduced folate coenzyme → inhibits thymidylate synthase and purine synthesis → blocks DNA synthesis."},
  {id:"final70",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"6-Mercaptopurine (6-MP) acts by inhibition of:",options:["Topoisomerase I","Adenyl cyclase and IMP dehydrogenase","Topoisomerase II","Thymidylate synthetase","Dihydrofolate reductase"],answer:1,explanation:"6-MP is a purine analogue — its active metabolite inhibits enzymes in purine synthesis pathway (including IMP dehydrogenase), producing nonfunctional DNA/RNA. Metabolized by xanthine oxidase — allopurinol interaction is critical."},
  {id:"final71",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"The mechanism of action of 5-fluorouracil (5-FU) is:",options:["Cross-linking of double-stranded DNA","Inhibition of DNA-dependent RNA synthesis","Interference with topoisomerase I","Irreversible inhibition of thymidylate synthase"],answer:3,explanation:"5-FU is converted to FdUMP which irreversibly inhibits thymidylate synthase → ↓thymidine synthesis → ↓DNA synthesis. Leucovorin enhances this effect by stabilizing the enzyme-FdUMP complex."},
  {id:"final72",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Iron chelators can be used as a protective agent against:",options:["Vincristine-induced nephrotoxicity","Methotrexate-induced hemorrhage","Trastuzumab-induced hypersensitivity","6-MP-induced bone marrow depression","Doxorubicin-induced cardiotoxicity"],answer:4,explanation:"Dexrazoxane (an iron chelator) protects the heart from doxorubicin cardiotoxicity by chelating iron that would otherwise participate in free-radical generation. Liposomal doxorubicin formulations also reduce cardiotoxicity."},
  {id:"final73",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"The anticancer drug most likely responsible for cardiac toxicity is:",options:["Cyclophosphamide","Doxorubicin","Fluorouracil","Tamoxifen","Vincristine"],answer:1,explanation:"Doxorubicin causes irreversible dose-related cardiomyopathy/congestive heart failure (anthracycline cardiotoxicity). Mechanism: intercalation + topoisomerase II inhibition → free radicals → myocardial damage."},
  {id:"final74",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"During ABVD treatment, a patient developed dyspnea, nonproductive cough, fever, and pulmonary infiltration on X-ray. Which drug is the causative agent?",options:["Doxorubicin","Vinblastine","Dacarbazine","Doxorubicin and dacarbazine","Bleomycin"],answer:4,explanation:"Bleomycin's dose-limiting toxicity is pulmonary toxicity — ranging from interstitial pneumonitis to irreversible pulmonary fibrosis. Routine pulmonary function tests are required during treatment."},
  {id:"final75",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"A patient with colonic cancer receives 5-FU + leucovorin. The rationale for leucovorin depends on it being essential for:",options:["Conversion of 5-FU to FdUMP","Protection against 5-FU-induced anemia","Inhibition of thymidylate synthase by FdUMP","Prolongation of the antitumor effect of 5-FU"],answer:2,explanation:"Leucovorin (reduced folate coenzyme) is required for FdUMP to form a stable ternary complex with thymidylate synthase → enhances and prolongs enzyme inhibition → greater antitumor effect."},
  {id:"final76",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Neutropenia develops in a cancer patient on chemotherapy. Which agent accelerates neutrophil recovery?",options:["Leucovorin","Filgrastim","Prednisone","Vitamin B12"],answer:1,explanation:"Filgrastim (G-CSF = granulocyte colony-stimulating factor) stimulates bone marrow to produce neutrophils. Used to treat/prevent severe chemotherapy-induced neutropenia. Also prevents febrile neutropenia with paclitaxel."},
  {id:"final77",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Which of the following anticancer drugs is a tyrosine kinase inhibitor?",options:["Imatinib","Methotrexate","Doxorubicin","Cyclophosphamide"],answer:0,explanation:"Imatinib (Gleevec) is a targeted tyrosine kinase inhibitor — specifically inhibits BCR-ABL kinase in CML (chronic myeloid leukemia) and c-KIT in GISTs. Represents targeted cancer therapy."},
  {id:"final78",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Which anticancer drug activates the immune system and is used for treatment of melanoma?",options:["Paclitaxel","Lambrolizumab (pembrolizumab)","Doxorubicin","6-MP"],answer:1,explanation:"Pembrolizumab (Keytruda) is an anti-PD-1 monoclonal antibody — a checkpoint inhibitor that \"releases\" T-cell immune response against tumor cells. Used in melanoma, lung cancer, and others."},
  {id:"final79",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Prednisone is used in which of the following?",options:["Lymphomas","Tuberculosis","Cushing syndrome"],answer:0,explanation:"Corticosteroids (prednisone) are used as part of chemotherapy regimens for lymphomas and leukemias (anti-inflammatory, immunosuppressive, and direct cytotoxic effects on lymphoid cells). Part of MOPP regimen."},
  {id:"final80",exam:"final",lecture:"Anticancer Drugs (1) — Antimetabolites & Antibiotic Agents",q:"Which of the following statements about 5-FU + leucovorin is most accurate?",options:["Irreversible inhibition of thymidylate synthase by cellular metabolites of 5-FU","Cross-linking of double-stranded DNA","Inhibition of DNA-dependent RNA synthesis","Interference with topoisomerase activity"],answer:0,explanation:"Same as Q71/Q75. The cellular metabolite FdUMP + leucovorin (N5,N10-methylene THF) + thymidylate synthase form a covalent ternary complex → irreversible inhibition."},
  {id:"final81",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Which of the following bases is most susceptible to alkylating agents?",options:["Adenosine","Cytosine","Thymidine","Guanine","Uridine"],answer:3,explanation:"Alkylating agents primarily transfer alkyl groups to the N7 position of guanine → DNA cross-linking, strand breaks, intrastrand linkage → prevents normal DNA synthesis/replication."},
  {id:"final82",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"The main toxic effect of cyclophosphamide:",options:["Alopecia","Fever","Liver toxicity","Hypersensitivity","Hemorrhagic cystitis"],answer:4,explanation:"Cyclophosphamide's metabolite acrolein accumulates in the bladder → hemorrhagic cystitis. Prevented by increased fluid intake and MESNA (sodium-2-mercaptoethanesulfonate, which binds acrolein)."},
  {id:"final83",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"MESNA is an antidote for:",options:["Cyclophosphamide-induced hemorrhagic cystitis","Methotrexate toxicity","5-FU toxicity","6-MP toxicity","Cisplatin toxicity"],answer:0,explanation:"MESNA reacts with acrolein (the toxic cyclophosphamide metabolite) in the bladder → forms a non-toxic compound, preventing urothelial damage. Does not affect antitumor activity."},
  {id:"final84",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Cyclophosphamide interacts with which drug to induce complete apnea?",options:["Succinylcholine","Aspirin","Methotrexate","5-Fluorouracil"],answer:0,explanation:"Cyclophosphamide inhibits plasma pseudocholinesterase → prolongs the action of succinylcholine (which is normally hydrolyzed by pseudocholinesterase) → prolonged apnea/neuromuscular blockade. Clinically important in surgical patients."},
  {id:"final85",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Which anticancer drug can be used for treatment of brain tumors?",options:["Lomustine","Busulfan","5-FU","Cyclophosphamide","Adriamycin"],answer:0,explanation:"Nitrosoureas (lomustine, carmustine) are highly lipid-soluble → cross BBB. Used for brain tumors and CNS lymphomas. Other alkylating agents and antimetabolites cannot cross the BBB adequately."},
  {id:"final86",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"A drug used in combination therapy for testicular carcinoma and associated with nephrotoxicity:",options:["Bleomycin","Cisplatin","Etoposide","Leuprolide","Vinblastine"],answer:1,explanation:"Cisplatin causes severe nephrotoxicity (proximal tubular damage) requiring intensive IV hydration and diuresis for prevention. Used in testicular carcinoma (BEP regimen: bleomycin + etoposide + cisplatin)."},
  {id:"final87",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"A cell cycle-specific anticancer drug acting mainly in M phase:",options:["Bleomycin","Cisplatin","Etoposide","Methotrexate","Vincristine"],answer:4,explanation:"Vinca alkaloids (vincristine, vinblastine) and taxanes (paclitaxel) are M-phase specific — they target tubulin/microtubules essential for mitotic spindle formation. MTX is S-phase specific; cisplatin/alkylating agents are CCNS."},
  {id:"final88",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"The main mechanism by which vincristine exerts its effects:",options:["Alkylating DNA causing cross-linking","Blocking microtubular assembly and mitosis during M-phase","Intercalating DNA strands","Stabilizing assembled microtubular array","Inhibiting topoisomerase"],answer:1,explanation:"Vincristine (and vinblastine) bind tubulin → prevent microtubule polymerization → arrest mitosis in M-phase. In contrast, paclitaxel stabilizes assembled microtubules (D) — both prevent mitosis but by opposite mechanisms."},
  {id:"final89",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"The anticancer agent most likely causing neurotoxicity (areflexia and peripheral neuritis):",options:["Cyclophosphamide","Mercaptopurine","Methotrexate","Prednisone","Vincristine"],answer:4,explanation:"Vincristine's major adverse effect is peripheral neuropathy — areflexia, muscle weakness, constipation (autonomic neuropathy). Vinblastine causes more myelosuppression than neurotoxicity."},
  {id:"final90",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"In MOPP + ABVD treatment of Hodgkin's lymphoma, which class is CCS and used in BOTH regimens?",options:["Alkylating agents","Antibiotics","Antimetabolites","Plant alkaloids (vincristine/vinblastine)","Purine antagonists"],answer:3,explanation:"Vinca alkaloids are CCS (M-phase). Vincristine is in MOPP; vinblastine is in ABVD. Alkylating agents (mechlorethamine, dacarbazine) are CCNS. Doxorubicin (antibiotic) is CCS but only in ABVD."},
  {id:"final91",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Paclitaxel is active at which cell cycle phase?",options:["G1","S","G0","G2/M"],answer:3,explanation:"Paclitaxel (taxane) stabilizes polymerized microtubules → prevents depolymerization → arrests cells in G2/M phase. Adverse effects: neutropenia (prevented by G-CSF/filgrastim), hypersensitivity (pretreat with dexamethasone + diphenhydramine + H2 blocker), neuropathy."},
  {id:"final92",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"All of the following are aromatase inhibitors EXCEPT:",options:["Aminoglutethimide","Anastrozole","Goserelin","Letrozole","Exemestane"],answer:2,explanation:"Goserelin is a GnRH agonist (not an aromatase inhibitor) — used to suppress gonadal steroid production in hormone-sensitive cancers. Aromatase inhibitors (anastrozole, letrozole, exemestane, aminoglutethimide) block peripheral conversion of androgens to estrogens."},
  {id:"final93",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"All of the following are true concerning tamoxifen EXCEPT:",options:["More effective in post-menopausal than pre-menopausal women","Available in oral form only","Hot flashes, nausea, and vomiting are most common side effects","Used in treatment of breast cancer","Proven effective in treating both ER-positive AND negative tumors"],answer:4,explanation:"Tamoxifen (SERM — selective estrogen receptor modulator) is effective ONLY in ER-positive breast cancer. It has NO benefit in ER-negative tumors. It is 1st line for ER+ breast cancer and is administered orally."},
  {id:"final94",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Trastuzumab is a monoclonal antibody used for breast cancer that shows:",options:["High expression of HER2 protein","Low expression of HER2 protein","No expression of HER2 protein","Intermediate expression of HER2 protein"],answer:0,explanation:"Trastuzumab (Herceptin) targets HER2 (human epidermal growth factor receptor 2) — only effective in HER2-overexpressing breast cancers (~20-25% of cases). HER2 testing is mandatory before prescribing."},
  {id:"final95",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Which agent in breast cancer chemotherapy has specific activity only in a SUBSET of patients?",options:["Cyclophosphamide","Doxorubicin","Trastuzumab","Methotrexate","Tamoxifen"],answer:2,explanation:"Trastuzumab is effective only in HER2+ subset. Tamoxifen is also subset-specific (ER+) but choice C (trastuzumab) is the most specific targeted therapy. CMF/FAC regimens use non-targeted cytotoxic agents."},
  {id:"final96",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Hydration and/or diuresis can prevent the renal toxicity associated with:",options:["Cisplatin","Chlorambucil","Tamoxifen","Gemcitabine","MTX"],answer:0,explanation:"Cisplatin causes proximal tubular nephrotoxicity — intensive IV hydration (normal saline) and forced diuresis before/during/after administration are mandatory. High-dose MTX also requires hydration + urinary alkalinization."},
  {id:"final97",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"A patient is being treated with allopurinol for chemotherapy-induced hyperuricemia. Which drug's dose must be reduced?",options:["5-FU","6-MP","6-TG","Fludarabine","Cytarabine"],answer:1,explanation:"Allopurinol inhibits xanthine oxidase → the enzyme that metabolizes 6-MP → 6-MP accumulates → increased toxicity (myelosuppression, hepatotoxicity). 6-MP dose must be reduced by 25–75% when given with allopurinol."},
  {id:"final98",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Which drug must have its dose reduced by 25% when given with allopurinol?",options:["Mercaptopurine","Mechlorethamine","Methotrexate"],answer:0,explanation:"Same principle as Q97. 6-mercaptopurine (and 6-thioguanine) are metabolized by xanthine oxidase. Allopurinol blocks this → drug accumulates. Dose reduction 25–75% is required."},
  {id:"final99",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Doxorubicin cardiotoxicity can be reduced by:",options:["MESNA","Dexrazoxane"],answer:1,explanation:"Dexrazoxane (an iron chelator) reduces doxorubicin cardiotoxicity. MESNA is used for cyclophosphamide-induced hemorrhagic cystitis — not cardiotoxicity. Liposomal doxorubicin also has reduced cardiac effects."},
  {id:"final100",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Chemotherapy caused acute hemorrhagic cystitis. Which drug was most likely responsible?",options:["Cyclophosphamide","Doxorubicin","Fluorouracil","Methotrexate","Tamoxifen"],answer:0,explanation:"Cyclophosphamide is metabolized to acrolein → accumulates in bladder mucosa → hemorrhagic cystitis. MESNA and adequate hydration prevent this toxicity. None of the other drugs causes this specific toxicity."},
  {id:"final101",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"Which anticancer drug is cell cycle specific (CCS)?",options:["Mechlorethamine","Fluorouracil","Tamoxifen","Cisplatin"],answer:1,explanation:"5-FU is a CCS antimetabolite (S-phase). Mechlorethamine and cisplatin are alkylating/CCNS agents. Tamoxifen is a hormone antagonist (CCNS). CCS drugs include antimetabolites, bleomycin, vinca alkaloids, taxanes, and etoposide."},
  {id:"final102",exam:"final",lecture:"Anticancer Drugs (2) — Alkylating Agents, Microtubule Inhibitors, Hormones",q:"First-line treatment for breast cancer caused by a positive estrogen receptor:",options:["Interferons","Tamoxifen","Trastuzumab"],answer:1,explanation:"Tamoxifen is 1st-line hormonal therapy for ER+ breast cancer (both pre- and post-menopausal). It competitively blocks estrogen receptors in breast tissue while having partial agonist effects in bone and uterus."},
  {id:"final103",exam:"final",lecture:"Mixed/Other",q:"Biotransformation of a drug is primarily directed to:",options:["Inactivate a drug","Activate a drug","Convert lipid-soluble drug to non-lipid-soluble metabolite","Convert non-lipid-soluble drug to lipid-soluble metabolite"],answer:2,explanation:"Biotransformation primarily converts lipid-soluble (membrane-permeable) drugs to water-soluble metabolites → easier renal/biliary excretion. Not all metabolites are inactive (prodrugs are activated by metabolism)."},
  {id:"final104",exam:"final",lecture:"Mixed/Other",q:"Drugs acting on the same organ but on different receptors causing opposite effects:",options:["Physiological antagonism","Chemical antagonism","Competitive antagonism","Pharmacological antagonism"],answer:0,explanation:"Physiological (functional) antagonism: two drugs have opposite effects via different receptors on the same system (e.g., adrenaline and histamine on bronchial smooth muscle). Competitive antagonism involves the same receptor."},
  {id:"final105",exam:"final",lecture:"Mixed/Other",q:"High protein binding of a drug:",options:["Facilitates glomerular filtration","Minimizes drug interaction","Makes the drug long-acting","Increases Vd"],answer:2,explanation:"Highly protein-bound drugs have slow release from albumin → prolonged duration of action. They have reduced Vd (stay in plasma), are not freely filtered, and may displace other drugs (increasing interaction risk)."},
  {id:"final106",exam:"final",lecture:"Mixed/Other",q:"A 16-year-old girl with aspirin overdose. Which syndrome is most likely?",options:["Bone marrow suppression and aplastic anemia","Fever, hepatic dysfunction, and encephalopathy","Hyperthermia, metabolic acidosis, and coma","Rapid fulminant hepatic failure","Rash, interstitial nephritis, acute renal failure"],answer:2,explanation:"Salicylate (aspirin) overdose causes: initially respiratory alkalosis (hyperventilation), then metabolic acidosis, hyperthermia (uncouples oxidative phosphorylation), tinnitus, and potentially coma. B = Reye syndrome."},
  {id:"final107",exam:"final",lecture:"Mixed/Other",q:"Celecoxib contraindication — most compelling reason to avoid it:",options:["History of alcohol abuse","History of gout","History of myocardial infarction","History of osteoporosis","History of peptic ulcer disease"],answer:2,explanation:"COX-2 inhibitors (celecoxib) increase cardiovascular risk (↑thromboxane A2 without ↓PGI2 inhibition) → contraindicated in patients with history of MI, stroke, or cardiovascular disease."},
  {id:"final108",exam:"final",lecture:"Mixed/Other",q:"TT is trying to quit smoking. Failed on nicotine patch and gum. Which drug may be useful?",options:["Varenicline","Dextroamphetamine","Lorazepam","Methylphenidate"],answer:0,explanation:"Varenicline (Champix) is a partial nicotinic receptor agonist — reduces craving and blocks nicotine reward. Second-line when nicotine replacement fails. Bupropion is another non-nicotine option."},
  {id:"final109",exam:"final",lecture:"Mixed/Other",q:"Common adverse effect of amphetamines:",options:["Bradycardia","Somnolence","Constipation","Hypertension","Fatigue"],answer:3,explanation:"Amphetamines are CNS stimulants and sympathomimetics → hypertension, tachycardia, anorexia, insomnia, euphoria. Used in ADHD (methylphenidate, amphetamine salts) and narcolepsy."},
  {id:"final110",exam:"final",lecture:"Mixed/Other",q:"Which is correct regarding beta-blockers?",options:["Treatment with beta-blockers should not be stopped abruptly","Propranolol is a cardioselective beta-blocker","Beta-blockers may cause orthostatic hypotension","Cardioselective beta-blockers worsen asthma","Beta-blockers decrease peripheral resistance by vasorelaxation"],answer:0,explanation:"Abrupt beta-blocker withdrawal causes rebound tachycardia and angina (upregulation of beta receptors). Propranolol is non-selective. Cardioselective beta-blockers (atenolol, metoprolol) are safer in asthma but not completely safe."},
  {id:"final111",exam:"final",lecture:"Mixed/Other",q:"Which is correct regarding alpha-adrenergic blockers?",options:["Alpha blockers treat hypotension in anaphylactic shock","Alpha blockers treat benign prostatic hyperplasia (BPH)","Alpha blockers treat asthma","Alpha blockers reduce frequency of urination"],answer:1,explanation:"Alpha-1 blockers (tamsulosin, prazosin) relax smooth muscle of the bladder neck and prostate → reduce urinary obstruction in BPH. In anaphylaxis, epinephrine (alpha-1 agonist) is used, not a blocker."},
  {id:"final112",exam:"final",lecture:"Mixed/Other",q:"A hypertensive patient accidentally received an alpha-2 agonist instead of an alpha-1 blocker. What happens?",options:["Alpha-2 agonists increase norepinephrine release","Alpha-2 agonists can reduce blood pressure in this patient","Alpha-2 agonists increase blood pressure","Alpha-2 agonists will not affect blood pressure"],answer:1,explanation:"Alpha-2 agonists (clonidine, methyldopa) stimulate presynaptic alpha-2 receptors in the CNS → decrease sympathetic outflow → reduce norepinephrine release → decrease blood pressure. Used as antihypertensives."},
  {id:"final113",exam:"final",lecture:"Mixed/Other",q:"A reversible inhibitor of platelet cyclooxygenase:",options:["Leukotrienes","Ibuprofen","Aspirin"],answer:1,explanation:"Ibuprofen (and most NSAIDs) reversibly inhibit COX-1/COX-2. Aspirin irreversibly acetylates COX-1 in platelets → permanent (8–10 days, platelet lifespan) inhibition. This is why aspirin antiplatelet effect persists even after drug elimination."},
  {id:"final114",exam:"final",lecture:"Mixed/Other",q:"An 8-year-old boy with ADHD on methylphenidate — his brother takes the bottle and develops toxicity. Expected presentation?",options:["Hypertension, tachycardia, seizures","Miosis, sweating, diarrhea","Hypotension, coma"],answer:0,explanation:"Methylphenidate (CNS stimulant) overdose: excessive sympathetic stimulation → hypertension, tachycardia, hyperthermia, seizures, psychosis. Treatment: supportive, benzodiazepines for seizures."},
  {id:"final115",exam:"final",lecture:"Mixed/Other",q:"To prolong the duration of a drug:",options:["Increase vascularity of absorbing area","Reduction of solubility of the drug","Administration in watery solution"],answer:1,explanation:"Reducing drug solubility (e.g., depot/sustained-release formulations, procaine penicillin G, benzathine penicillin G) → slows absorption → prolongs duration of action."},
  {id:"final116",exam:"final",lecture:"Mixed/Other",q:"MAO-B inhibitors are used in Parkinson's because:",options:["They accelerate conversion of levodopa to dopamine","Inhibit dopamine metabolism","Stimulate dopamine receptors","Inhibit their effect on peripheral D2 receptors"],answer:1,explanation:"MAO-B (monoamine oxidase B) normally degrades dopamine in the brain. Inhibiting it (selegiline, rasagiline) → preserves dopamine levels in the striatum → improves Parkinson's symptoms."},
  {id:"final117",exam:"final",lecture:"Mixed/Other",q:"Levodopa is used with carbidopa in Parkinson's because carbidopa:",options:["Prevents peripheral conversion of levodopa to metabolites","Enhances absorption of levodopa","Increases affinity for levodopa","Facilitates levodopa crossing the blood-brain barrier"],answer:0,explanation:"Carbidopa inhibits peripheral aromatic amino acid decarboxylase (DOPA decarboxylase) → prevents conversion of levodopa to dopamine in the periphery → more levodopa reaches the brain + reduced peripheral dopaminergic side effects."},
  {id:"final118",exam:"final",lecture:"Mixed/Other",q:"Pramipexole is a drug used for Parkinson's. It is considered:",options:["Dopamine agonist","COMT inhibitor","MAO inhibitor","Anticholinergic"],answer:0,explanation:"Pramipexole (Mirapex) is a non-ergot dopamine D2/D3 receptor agonist. Used in early Parkinson's (monotherapy) or as adjunct to levodopa. May cause hallucinations, somnolence, impulse control disorders."},
  {id:"final119",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which of the following statements is correct regarding imipenem, aztreonam, vancomycin, and bacitracin?",options:["Imipenem is combined with cilastatin to resist hydrolysis by β-lactamase enzyme","Amoxycillin is more appropriate than ampicillin for treatment of shigella or salmonella-derived enteritis","Aztreonam is effective against gram +ve organisms and anaerobes","Vancomycin is the drug of choice in cases of methicillin-resistant Staphylococcus aureus (MRSA)","Bacitracin is the drug of choice in treatment of antibiotic-induced colitis due to Clostridium difficile"],answer:3,explanation:"Vancomycin (glycopeptide) inhibits cell wall synthesis by binding D-Ala-D-Ala terminus of peptidoglycan precursors, blocking transglycosylation. It is the drug of choice for MRSA infections. Imipenem is combined with cilastatin to prevent renal hydrolysis by dehydropeptidase-I (not beta-lactamase). Aztreonam (monobactam) is only effective against aerobic gram-negative organisms. Bacitracin is not used for C. difficile colitis."},
  {id:"final120",exam:"final",lecture:"Cell Wall Inhibitors",q:"Penicillin G is effective against all of the following organisms EXCEPT:",options:["Listeria monocytogenes","Mycoplasma pneumoniae","Streptococcus pyogenes","Treponema pallidum","Bacillus anthracis"],answer:1,explanation:"Penicillin G is a narrow-spectrum antibiotic effective against gram-positive cocci, gram-negative cocci, spirochetes, and some anaerobes. Mycoplasma pneumoniae lacks a cell wall entirely, making it intrinsically resistant to all cell-wall-active antibiotics including penicillin. Macrolides (azithromycin, clarithromycin) or doxycycline are used for Mycoplasma infections."},
  {id:"final121",exam:"final",lecture:"Cell Wall Inhibitors",q:"In a patient with pneumonia due to β-lactamase-producing H. influenzae not responding to ampicillin, you will give:",options:["Oral vancomycin","Add gentamicin to ampicillin therapy","Give oral amoxicillin","Switch to I.V. cefotaxime","Oral trimethoprim"],answer:3,explanation:"Beta-lactamase-producing H. influenzae is resistant to ampicillin. Cefotaxime (third-generation cephalosporin) is stable to beta-lactamases and has excellent gram-negative activity including H. influenzae. Adding gentamicin to ampicillin is ineffective against beta-lactamase-producing organisms."},
  {id:"final122",exam:"final",lecture:"Cell Wall Inhibitors",q:"Typical therapeutic applications of penicillin G include all of the following EXCEPT:",options:["UTI due to E. coli","Streptococcal infections","Bacillus anthracis","Treponema pallidum","Clostridium perfringens"],answer:0,explanation:"Penicillin G is a narrow-spectrum beta-lactam NOT effective against gram-negative rods like E. coli. E. coli UTIs require fluoroquinolones, co-trimoxazole, or aminoglycosides. The other options are valid penicillin G indications."},
  {id:"final123",exam:"final",lecture:"Cell Wall Inhibitors",q:"In patient with pseudomembranous colitis due to C. difficile, the treatment of choice is:",options:["Oral tetracycline","Oral vancomycin","Oral tobramycin","I.V. imipenem","I.V. cephoperazone"],answer:1,explanation:"Pseudomembranous colitis caused by C. difficile is treated with oral metronidazole (first-line for mild disease) or oral vancomycin (for severe or recurrent cases). Oral vancomycin is not absorbed systemically and acts locally in the gut. IV vancomycin is NOT effective for C. difficile colitis."},
  {id:"final124",exam:"final",lecture:"Cell Wall Inhibitors",q:"Piperacillin differs from ampicillin in all of the following properties EXCEPT:",options:["Stability in gastric acid","Effectiveness as an antipseudomonal agent","Resistance to penicillinase","Spectrum of antibacterial action","The broadness of the spectrum of susceptible bacteria"],answer:2,explanation:"Both piperacillin and ampicillin are susceptible to penicillinase (beta-lactamase). Piperacillin differs from ampicillin in having antipseudomonal activity, broader gram-negative spectrum, and only being available parenterally. Penicillinase-resistant penicillins include cloxacillin, dicloxacillin, nafcillin, and oxacillin."},
  {id:"final125",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which antimicrobial agent is a polypeptide active against gram-positive organisms and is only used topically because of nephrotoxicity?",options:["Ampicillin","Gentamicin","Bacitracin","Carbenicillin","Aztreonam"],answer:2,explanation:"Bacitracin is a polypeptide antibiotic that inhibits cell wall synthesis (bactoprenol phosphate cycle). Systemic use causes severe nephrotoxicity, so it is restricted to topical application (skin wounds, eye/ear drops). It has activity against gram-positive organisms."},
  {id:"final126",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which penicillin is active against penicillinase-producing Staphylococcus aureus?",options:["Cloxacillin","Amoxicillin","Piperacillin","Ticarcillin","Penicillin V"],answer:0,explanation:"Cloxacillin, dicloxacillin, oxacillin, nafcillin, and methicillin are antistaphylococcal penicillins that resist staphylococcal penicillinase through steric hindrance. They are used for methicillin-sensitive S. aureus (MSSA) infections. They are NOT effective against MRSA."},
  {id:"final127",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about cephalosporins are correct EXCEPT:",options:["They are B-lactam antibiotics closely related structurally and functionally to the penicillins","They are more resistant to B-lactamases than the penicillins","Based on bacterial susceptibility and resistance to B-lactamase they are classified into first, second and third generation","They should be avoided or used with caution in individuals allergic to penicillin","They are effective against methicillin-resistant Staphylococcus aureus (MRSA)"],answer:4,explanation:"Cephalosporins are NOT effective against MRSA. MRSA possesses mecA gene encoding PBP2a with very low affinity for all beta-lactam antibiotics including cephalosporins."},
  {id:"final128",exam:"final",lecture:"Cell Wall Inhibitors",q:"For a 14-year-old with S. aureus osteomyelitis - effective therapy includes all EXCEPT:",options:["Oxacillin","Norfloxacin","Cloxacillin","Nafcillin","Cefazolin"],answer:1,explanation:"Norfloxacin is an early fluoroquinolone with limited distribution primarily to urine (urinary antiseptic); it has poor tissue/bone penetration and inadequate serum levels for osteomyelitis. Oxacillin, cloxacillin, nafcillin (antistaphylococcal penicillins), and cefazolin (first-gen cephalosporin) are effective for staphylococcal osteomyelitis."},
  {id:"final129",exam:"final",lecture:"Cell Wall Inhibitors",q:"Beta-lactamase-producing H. influenzae, M. catarrhalis, and N. gonorrhoeae are resistant to penicillin G. Which antibiotic is effective against all?",options:["Ampicillin","Ceftriaxone","Clindamycin","Gentamycin","Piperacillin"],answer:1,explanation:"Ceftriaxone is a third-generation cephalosporin that is stable to common beta-lactamases and has excellent activity against H. influenzae, M. catarrhalis, and N. gonorrhoeae. It is the drug of choice for gonorrhea (single IM dose)."},
  {id:"final130",exam:"final",lecture:"Cell Wall Inhibitors",q:"Sulbactam is important because it:",options:["Easily penetrates gram-negative microorganisms","Inactivates bacterial beta-lactamase","Is specific for gram-positive microorganisms","Is a potent inhibitor of cell wall transpeptidase","Has a spectrum of activity similar to that of penicillin"],answer:1,explanation:"Sulbactam is a beta-lactamase inhibitor that irreversibly inactivates a wide range of beta-lactamases, protecting the accompanying penicillin from hydrolysis. It is combined with ampicillin (Unasyn). Sulbactam has minimal antibacterial activity on its own."},
  {id:"final131",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which cephalosporin shows good activity against anaerobes, particularly B. fragilis?",options:["Cefaclor","Cephalexin","Cephradine","Cefoxitin"],answer:3,explanation:"Cefoxitin is a second-generation cephalosporin (cephamycin) with a 7-alpha-methoxy group that confers resistance to beta-lactamases from anaerobes, providing good activity against B. fragilis. It is used for intra-abdominal infections and pelvic inflammatory disease."},
  {id:"final132",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about penicillins and cephalosporins are correct EXCEPT:",options:["Penicillin G has limited antibacterial activity and is susceptible to beta-lactamases","Ampicillin is the drug of choice for the treatment of Pseudomonas aeruginosa infections","First-generation cephalosporins are more effective against staphylococcal infections than are third-generation cephalosporins","Methicillin is an antistaphylococcal penicillin","Ceftriaxone is a third-generation cephalosporin with a long half-life and has good penetration into bone"],answer:1,explanation:"Ampicillin is an aminopenicillin with NO antipseudomonal activity. Antipseudomonal penicillins include piperacillin, ticarcillin, and carbenicillin."},
  {id:"final133",exam:"final",lecture:"Cell Wall Inhibitors",q:"Cilastatin is combined with which antibiotic to prevent degradation by renal dehydropeptidase?",options:["Amoxycillin","Imipenem","Cephalexin","Ticarcillin","Cloxacillin"],answer:1,explanation:"Imipenem is combined with cilastatin because renal dehydropeptidase-I hydrolyzes imipenem. Cilastatin inhibits this enzyme, preventing imipenem inactivation in the kidney. Meropenem and ertapenem are stable to dehydropeptidase and do NOT require cilastatin."},
  {id:"final134",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about penicillin G are correct EXCEPT:",options:["It is excreted from the body mainly via the hepatobiliary route","It is poorly absorbed after oral use due to destruction by stomach acid","It is a narrow-spectrum antibiotic","It is more effective in killing growing bacteria than microorganisms in the stationary phase","It is destroyed by β-lactamase"],answer:0,explanation:"Penicillin G is excreted mainly by RENAL tubular secretion (not hepatobiliary route). Probenecid blocks tubular secretion, prolonging penicillin levels."},
  {id:"final135",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about imipenem are correct EXCEPT:",options:["It is inactivated by B-lactamases","It has the broadest spectrum of activity","It contains a B-lactam ring in its structure","It needs adjustment of the dose in renal insufficiency","It is combined with cilastatin, an inhibitor of the enzyme dehydropeptidase"],answer:0,explanation:"Imipenem is actually RESISTANT to most beta-lactamases (that is one of its key advantages). However, it can be hydrolyzed by metallo-beta-lactamases/carbapenemases. Imipenem requires dose adjustment in renal failure to prevent seizures."},
  {id:"final136",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about vancomycin are correct EXCEPT:",options:["It inhibits bacterial cell wall synthesis","Is ineffective against methicillin-resistant staphylococci","Is given orally to treat antibiotic-induced pseudomembranous colitis","It is used prophylactically in dental patients with prosthetic heart valves","It acts synergistically with aminoglycosides in treatment of enterococcal endocarditis"],answer:1,explanation:"Vancomycin IS effective against MRSA (methicillin-resistant staphylococci) - it is the drug of choice. Vancomycin inhibits cell wall synthesis (D-Ala-D-Ala binding), and is not affected by the mecA/PBP2a resistance mechanism."},
  {id:"final137",exam:"final",lecture:"Cell Wall Inhibitors",q:"Such agents as clavulanic acid, sulbactam, or tazobactam are often added to penicillin combination products. What is the main reason?",options:["Add antibiotic activity against Pseudomonas and many Enterobacter species","Facilitate antibiotic penetration into CNS and CSF","Inhibit cell wall transpeptidases","Inhibit inactivation of penicillin by β-lactamase-producing bacteria","Reduce the risk and/or severity of allergic reactions in susceptible patients"],answer:3,explanation:"Beta-lactamase inhibitors (clavulanic acid, sulbactam, tazobactam) irreversibly bind and inactivate bacterial beta-lactamases, protecting the companion penicillin from hydrolysis. They have minimal intrinsic antibacterial activity."},
  {id:"final138",exam:"final",lecture:"Cell Wall Inhibitors",q:"Amoxicillin differs from ampicillin in which way?",options:["Has better oral bioavailability","Is a broad-spectrum penicillin","Has greater antipseudomonal activity","Does not cause hypersensitivity reactions","Is effective against penicillinase-producing organisms"],answer:0,explanation:"Amoxicillin has superior oral bioavailability (~90%) compared to ampicillin (~30-40%) and is less affected by food. Both are aminopenicillins with the same antibacterial spectrum. Neither has antipseudomonal activity."},
  {id:"final139",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which penicillin is used in prophylaxis of rheumatic fever?",options:["Azlocillin","Ampicillin","Methicillin","Piperacillin","Benzathine penicillin G"],answer:4,explanation:"Benzathine penicillin G is a long-acting IM penicillin preparation (depot formulation) that releases penicillin slowly over 2-4 weeks. Monthly injections maintain adequate serum levels for prevention of recurrent streptococcal infections and rheumatic fever."},
  {id:"final140",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about cephalosporins are correct EXCEPT:",options:["As a group are all stable to stomach acid","They have the same mechanism of action as the penicillins","Are more resistant to B-lactamases than are the penicillins","Include agents that are active against Pseudomonas aeruginosa","Third-generation cephalosporins show greater activity than first-generation against gram-negative bacilli"],answer:0,explanation:"Not all cephalosporins are stable to stomach acid; several (cefazolin, cefuroxime IV, cefotaxime, ceftriaxone, ceftazidime) are acid-labile and can only be given parenterally. Oral cephalosporins (cephalexin, cefadroxil, cefuroxime axetil) are acid-stable."},
  {id:"final141",exam:"final",lecture:"Cell Wall Inhibitors",q:"Antibiotic-associated pseudomembranous colitis (AAPMC) - which drug is most likely to cause it?",options:["Amoxycillin","Azithromycin","Clindamycin","Metronidazole","Trimethoprim plus sulphamethoxazole"],answer:2,explanation:"Clindamycin is the antibiotic most classically associated with causing pseudomembranous colitis by disrupting normal gut flora and allowing C. difficile overgrowth. Metronidazole is used to TREAT C. difficile colitis."},
  {id:"final142",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient takes antimicrobial medication with milk - most likely to cause therapeutic failure of which drug?",options:["Aminoglycosides","Cephalosporin, first generation","Cephalosporin, second generation","Penicillin","Tetracycline"],answer:4,explanation:"Tetracyclines form insoluble chelate complexes with divalent cations (Ca²⁺ in milk, dairy products), dramatically reducing absorption. Tetracyclines should be taken on an empty stomach."},
  {id:"final143",exam:"final",lecture:"Cell Wall Inhibitors",q:"For beta-lactamase-positive staphylococci pneumonia - which drug is effective therapy?",options:["Ampicillin","Cloxacillin","Mezlocillin","Piperacillin","Penicillin G"],answer:1,explanation:"Cloxacillin (antistaphylococcal/penicillinase-resistant penicillin) is effective against beta-lactamase-producing S. aureus (MSSA). Ampicillin, piperacillin, mezlocillin, and penicillin G are all hydrolyzed by staphylococcal beta-lactamase."},
  {id:"final144",exam:"final",lecture:"Cell Wall Inhibitors",q:"The following drug is a beta-lactamase inhibitor used in combination with amoxicillin:",options:["Bacitracin","Vancomycin","Monobactam","Clavulanic acid","Imipenem/cilastatin"],answer:3,explanation:"Clavulanic acid is a beta-lactamase inhibitor with minimal antibacterial activity that protects amoxicillin from beta-lactamase hydrolysis. The combination (Augmentin) extends amoxicillin's spectrum to beta-lactamase-producing organisms."},
  {id:"final145",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which drug is effective for methicillin-resistant staphylococcal infection?",options:["Piperacillin","Vancomycin","Clavulanic acid","Streptomycin","Bacitracin"],answer:1,explanation:"Vancomycin is the treatment of choice for MRSA. MRSA has an altered PBP2a (encoded by mecA) with low affinity for all beta-lactams. Vancomycin acts by binding to the D-Ala-D-Ala terminus of peptidoglycan precursors."},
  {id:"final146",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which is a 4th generation cephalosporin?",options:["Cephalexin","Cefaclor","Cefepime","Cefotaxime","Ceftriaxone"],answer:2,explanation:"Cefepime is the main fourth-generation cephalosporin with excellent gram-positive and broad gram-negative activity including Pseudomonas aeruginosa. Ceftriaxone and cefotaxime are third-generation; cephalexin and cefaclor are first/second-generation."},
  {id:"final147",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which drug reaches therapeutic concentrations in CNS?",options:["Doxycycline","Erythromycin","Aminoglycosides","Chloramphenicol"],answer:3,explanation:"Chloramphenicol is highly lipid-soluble and achieves excellent CSF penetration (45-99% of serum concentration), even without meningeal inflammation. Aminoglycosides, erythromycin, and most tetracyclines do NOT achieve therapeutic CNS levels."},
  {id:"final148",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which meropenem/imipenem statement is INCORRECT?",options:["They are the broadest-spectrum β-lactam antibiotic preparation currently available","They play a role in empiric therapy","Meropenem but not imipenem requires cilastatin to protect it from degradation","They are effective against P. aeruginosa","They are not effective by the oral route"],answer:2,explanation:"Imipenem (NOT meropenem) requires cilastatin to protect it from degradation by renal dehydropeptidase-I. Meropenem is stable to this enzyme and does not need cilastatin."},
  {id:"final149",exam:"final",lecture:"Cell Wall Inhibitors",q:"For VRE (E. faecium) bacteremia with multiple drug interactions concern - which antibiotic to choose?",options:["Linezolid","Clindamycin","Doxycycline","Clarithromycin","Chloramphenicol"],answer:0,explanation:"Linezolid is preferred for VRE bacteremia when minimizing drug interactions is a priority. While quinupristin/dalfopristin also treats VRE faecium, it is a potent CYP3A4 inhibitor with significant drug interactions. Linezolid has fewer CYP-mediated interactions."},
  {id:"final150",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient with severe penicillin allergy (gram-negative bacteremia) - most appropriate empiric treatment?",options:["Ampicillin plus sulbactam","Aztreonam","Cefazolin","Imipenem plus cilastatin","Ticarcillin plus clavulanic acid"],answer:1,explanation:"Aztreonam (monobactam) is the safest option for gram-negative bacteremia in a penicillin-allergic patient with history of anaphylaxis. Aztreonam has minimal cross-reactivity with penicillins and covers gram-negative rods including Pseudomonas."},
  {id:"final151",exam:"final",lecture:"Cell Wall Inhibitors",q:"Gonorrhea in a 25-year-old male - which is appropriate treatment?",options:["Ceftriaxone IM","Penicillin G IM","Gentamicin IM","Piperacillin/tazobactam IV","Vancomycin IV"],answer:0,explanation:"Ceftriaxone (third-generation cephalosporin) given as a single IM injection is the drug of choice for uncomplicated gonorrhea (Neisseria gonorrhoeae). Penicillin G is no longer recommended due to widespread beta-lactamase-producing N. gonorrhoeae strains."},
  {id:"final152",exam:"final",lecture:"Cell Wall Inhibitors",q:"Syphilis treatment (T. pallidum infection) - the best course of action?",options:["Give a single oral dose of fosfomycin","Give no other antibiotics since drug treatment of gonorrhea provides coverage for incubating syphilis","Inject intramuscular benzathine penicillin G","Treat with oral tetracycline for 7 days","Treat with vancomycin"],answer:2,explanation:"Benzathine penicillin G (long-acting IM penicillin) is the drug of choice for all stages of syphilis caused by Treponema pallidum. Treatment of gonorrhea does NOT provide coverage for incubating syphilis."},
  {id:"final153",exam:"final",lecture:"Cell Wall Inhibitors",q:"Statement about imipenem that is most accurate:",options:["Has a narrow spectrum of antibacterial action","It is used in fixed combination with sulbactam","Is highly susceptible to β-lactamases produced by Enterobacter species","In renal dysfunction, dosage reductions are necessary to avoid seizures","Imipenem is active against methicillin-resistant staphylococci"],answer:3,explanation:"Imipenem accumulates in renal dysfunction and can cause CNS toxicity including seizures at high concentrations. Dose reduction is required in renal failure. Imipenem has the BROADEST (not narrowest) spectrum, is combined with cilastatin (not sulbactam), and is NOT active against MRSA."},
  {id:"final154",exam:"final",lecture:"Cell Wall Inhibitors",q:"For empiric treatment of purulent meningitis (gram-positive diplococci) with potential penicillin-resistant pneumococci:",options:["Ampicillin-sulbactam","Cefoperazone","Cefotaxime plus vancomycin","Cefoxitin","Nafcillin"],answer:2,explanation:"For S. pneumoniae meningitis where penicillin resistance is possible, the combination of a third-generation cephalosporin (cefotaxime or ceftriaxone) PLUS vancomycin is recommended to cover both susceptible and resistant strains."},
  {id:"final155",exam:"final",lecture:"Cell Wall Inhibitors",q:"Molecular basis for pneumococcal resistance to penicillin G:",options:["The production of beta-lactamases","Structural changes in penicillin-binding proteins","Decreased intracellular accumulation of penicillin G","Changes in the D-Ala-D-Ala building block of peptidoglycan precursor","Changes in porin structure"],answer:1,explanation:"Streptococcus pneumoniae develops penicillin resistance through mutations in penicillin-binding proteins (PBPs), particularly PBP2x and PBP2b, reducing beta-lactam binding affinity. Unlike most gram-negatives, pneumococcal resistance is NOT due to beta-lactamase production."},
  {id:"final156",exam:"final",lecture:"Cell Wall Inhibitors",q:"Gram-positive rods in CSF (Listeria) in elderly patient - empiric treatment should include:",options:["Ampicillin","Cefazolin","Fosfomycin","Ticarcillin","Vancomycin"],answer:0,explanation:"Listeria monocytogenes is the organism most commonly causing meningitis in elderly/immunocompromised patients and presents as gram-positive rods in CSF. Ampicillin (or penicillin G) is the drug of choice for Listeria; cephalosporins are NOT effective. Ampicillin is often combined with gentamicin for synergy."},
  {id:"final157",exam:"final",lecture:"Cell Wall Inhibitors",q:"Cefotetan statement that is accurate:",options:["It is active against MRSA strains","It is the drug of choice in community-acquired pneumonia","It decreases prothrombin time","It is a third-generation cephalosporin","Its antibacterial spectrum includes Bacteroides fragilis"],answer:4,explanation:"Cefotetan (like cefoxitin, a cephamycin/second-generation cephalosporin) has activity against Bacteroides fragilis due to its 7-alpha-methoxy group. It is NOT active against MRSA, is NOT the drug of choice for community-acquired pneumonia, can INCREASE prothrombin time (causing bleeding), and is a SECOND-generation (not third)."},
  {id:"final158",exam:"final",lecture:"Cell Wall Inhibitors",q:"Patient with enterococcal endocarditis and severe penicillin allergy - best treatment:",options:["Amoxicillin clavulanate","Aztreonam","Cefazolin plus gentamicin","Meropenem","Vancomycin"],answer:4,explanation:"For enterococcal endocarditis in a penicillin-allergic patient, vancomycin (plus gentamicin for synergy) is the appropriate alternative to ampicillin. Aztreonam is ineffective against gram-positive organisms."},
  {id:"final159",exam:"final",lecture:"Cell Wall Inhibitors",q:"Drug described: active against Pseudomonas, resistance emerges alone, not for penicillin-allergic patients, enhanced by tazobactam:",options:["Amoxicillin","Aztreonam","Imipenem","Piperacillin","Vancomycin"],answer:3,explanation:"Piperacillin is an antipseudomonal penicillin with Pseudomonas activity, but resistance develops rapidly when used alone. It is contraindicated in penicillin-allergic patients. Piperacillin/tazobactam (Zosyn) combines piperacillin with the beta-lactamase inhibitor tazobactam."},
  {id:"final160",exam:"final",lecture:"Cell Wall Inhibitors",q:"Vancomycin statement that is accurate:",options:["It is bacteriostatic","It binds to PBPs","It is not susceptible to penicillinase","It has the advantage of oral bioavailability","Staphylococcal enterocolitis occurs commonly with its use"],answer:2,explanation:"Vancomycin is a glycopeptide, completely different in structure from beta-lactams, and is NOT a substrate for beta-lactamase (penicillinase). It is bactericidal (not static) against most gram-positive organisms. It does NOT bind PBPs (it binds D-Ala-D-Ala). It is poorly absorbed orally."},
  {id:"final161",exam:"final",lecture:"Cell Wall Inhibitors",q:"Ampicillin statement that is FALSE:",options:["Its activity is enhanced by sulbactam","It causes maculopapular rashes","It is the drug of choice for Listeria monocytogenes infection","It eradicates most strains of MRSA","Pseudomembranous colitis may occur with its use"],answer:3,explanation:"Ampicillin does NOT eradicate MRSA. MRSA has an altered PBP2a with low affinity for all beta-lactam antibiotics including ampicillin. All other options (A, B, C, E) are true statements about ampicillin."},
  {id:"final162",exam:"final",lecture:"Cell Wall Inhibitors",q:"Co-trimoxazole - all statements correct EXCEPT: Is a combination of sulfamethoxazole and clavulanic acid:",options:["Is the treatment of choice for pneumonia due to Pneumocystis carinii","Has a broader spectrum of action than sulfonamides","May cause hemolytic anemia in patients with glucose-6-phosphate dehydrogenase deficiency","May increase levels of methotrexate due to displacement from albumin binding sites","Is a combination of sulfamethoxazole and clavulanic acid"],answer:4,explanation:"Co-trimoxazole is a combination of TRIMETHOPRIM (not clavulanic acid) + sulfamethoxazole. Clavulanic acid is a beta-lactamase inhibitor combined with amoxicillin (Augmentin)."},
  {id:"final163",exam:"final",lecture:"Cell Wall Inhibitors",q:"Drug useful for MRSA infection from the list:",options:["Piperacillin","Vancomycin","Clavulanic acid","Streptomycin","Bacitracin"],answer:1,explanation:"Vancomycin is the drug of choice for MRSA. Piperacillin (antipseudomonal penicillin) and clavulanic acid (beta-lactamase inhibitor) are ineffective against MRSA. Streptomycin (aminoglycoside) and bacitracin (topical polypeptide) are not used for MRSA treatment."},
  {id:"final164",exam:"final",lecture:"Cell Wall Inhibitors",q:"Antituberculous drug statements are correct EXCEPT: Cycloserine may cause hearing loss:",options:["Isoniazide (INH) can cause severe hepatitis","INH may cause peripheral neuropathy which is preventable with pyridoxine","Rifampicin causes a reddish discoloration of soft contact lenses","Ethambutol may cause optic neuritis","Cycloserine may cause hearing loss"],answer:4,explanation:"Cycloserine causes CNS toxicity (psychosis, seizures, peripheral neuropathy) but NOT hearing loss/ototoxicity. Aminoglycosides (streptomycin, amikacin) cause ototoxicity."},
  {id:"final165",exam:"final",lecture:"Cell Wall Inhibitors",q:"Regarding prophylactic antibiotics - NOT warranted in which situation?",options:["Prevention of meningitis among individuals in close contact with infected patients","Patient with a hip prosthesis who is having a tooth removed","Presurgical treatment for implantation of a hip prosthesis","Patient who complains of frequent respiratory illness","Presurgical treatment in gastrointestinal procedures"],answer:3,explanation:"Frequent respiratory illness (usually viral) is NOT an indication for prophylactic antibiotics; such use promotes antibiotic resistance."},
  {id:"final166",exam:"final",lecture:"Cell Wall Inhibitors",q:"Second-generation cephalosporin used orally with activity against Bacteroides fragilis for pelvic inflammatory disease:",options:["Cefazolin","Cefaclor","Cefotaxime","Ceftriaxone","Cefepime"],answer:1,explanation:""},
  {id:"final167",exam:"final",lecture:"Cell Wall Inhibitors",q:"A pregnant woman (8 months) with UTI - which drug can be used orally without risk to fetus?",options:["Cefadroxil (first-generation cephalosporin)","Cotrimoxazole","Penicillin V","Ceftriaxone (third-generation cephalosporin)","Tetracycline"],answer:0,explanation:"Cefadroxil (first-generation oral cephalosporin) is safe in pregnancy (FDA category B) and can treat UTIs. Co-trimoxazole is contraindicated near term (risk of kernicterus). Tetracycline is contraindicated in pregnancy."},
  {id:"final168",exam:"final",lecture:"Cell Wall Inhibitors",q:"Antibiotic NOT correctly matched with clinical indication:",options:["Penicillin G: pneumonia caused by Klebsiella pneumoniae","Carbenicillin: urinary tract infection caused by Pseudomonas aeruginosa (B-lactamase negative)","Ampicillin: bacterial meningitis caused by Haemophilus influenzae (B-lactamase negative)","Chloramphenicol: typhoid fever caused by Salmonella typhi","Cefazolin: staphylococcal osteomyelitis"],answer:0,explanation:"Klebsiella pneumoniae is a gram-negative rod intrinsically resistant to penicillin G. Klebsiella pneumonia requires third-generation cephalosporins or carbapenems."},
  {id:"final169",exam:"final",lecture:"Cell Wall Inhibitors",q:"Vancomycin is NOT effective in eradicating infections with H. pylori:",options:["Vancomycin","Amoxicillin","Tetracycline","Metronidazole","Clarithromycin"],answer:0,explanation:"Vancomycin is NOT used for H. pylori eradication. Standard triple therapy for H. pylori includes amoxicillin (or metronidazole) + clarithromycin + a proton pump inhibitor. Tetracycline is used in quadruple therapy."},
  {id:"final170",exam:"final",lecture:"Cell Wall Inhibitors",q:"All statements about imipenem/meropenem accurate EXCEPT - Meropenem (not imipenem) requires cilastatin:",options:["They are the broadest-spectrum β-lactam antibiotic preparation currently available","They play a role in empiric therapy","Meropenem but not imipenem requires cilastatin to protect it from degradation","They are effective against P. aeruginosa","They are not effective by the oral route"],answer:2,explanation:"This is INCORRECT - it is IMIPENEM (not meropenem) that requires cilastatin. Imipenem is hydrolyzed by renal dehydropeptidase-I. Meropenem, doripenem, and ertapenem are stable to this enzyme and do not require cilastatin."},
  {id:"final171",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient with Pseudomonas aeruginosa infection receiving IV gentamicin with poor response - adding penicillin in separate IV line will:",options:["The penicillin will increase the risk of aminoglycoside nephrotoxicity","The penicillin will enhance the bacterial response to the aminoglycoside","Chemical neutralization and abolishment of effects of penicillin","Colitis due to superinfection with Clostridium difficile may develop"],answer:1,explanation:"Penicillin (beta-lactam) and aminoglycosides (gentamicin) act synergistically against Pseudomonas: the beta-lactam disrupts the cell wall, facilitating aminoglycoside penetration into the bacterial cell. They MUST be administered in separate IV lines to avoid physical inactivation."},
  {id:"final172",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which of the following drugs is NOT nephrotoxic?",options:["Aztreonam","Gentamicin","Vancomycin","Amphotericin B"],answer:0,explanation:"Aztreonam (monobactam) is NOT nephrotoxic and is generally safe in patients with renal disease. Gentamicin, vancomycin, and amphotericin B all cause nephrotoxicity."},
  {id:"final173",exam:"final",lecture:"Cell Wall Inhibitors",q:"A patient develops severe watery diarrhea, fever, abdominal pain with confirmed C. difficile - antimicrobial therapy is:",options:["Amoxicillin","Ciprofloxacin","Metronidazole","Erythromycin"],answer:2,explanation:"Metronidazole is the first-line treatment for mild-to-moderate C. difficile colitis. Oral vancomycin is used for severe, recurrent, or refractory C. difficile. Ciprofloxacin and amoxicillin can actually cause C. difficile colitis."},
  {id:"final174",exam:"final",lecture:"Cell Wall Inhibitors",q:"One of the following drug is concentration-dependent and can be given as a single dose:",options:["Penicillin","Erythromycin","Amoxicillin","Gentamicin"],answer:3,explanation:"Gentamicin (aminoglycoside) is a concentration-dependent antibiotic where bactericidal activity increases with peak concentration. Once-daily high-dose gentamicin maximizes the peak:MIC ratio and exploits the post-antibiotic effect (PAE). Penicillin and erythromycin are time-dependent antibiotics."},
  {id:"final175",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Tetracyclines would be least effective in treating which disease?",options:["Staphylococcal infections","Rickettsia","Acne","Cholera","Rocky Mountain spotted fever"],answer:0,explanation:"Tetracyclines are bacteriostatic drugs with widespread resistance among staphylococci, making them poor choices for staphylococcal infections. They are highly effective for Rickettsia, Mycoplasma, Chlamydia, cholera, Lyme disease, and acne."},
  {id:"final176",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which statement about clinical uses of aminoglycosides is FALSE?",options:["Owing to their polar nature, aminoglycosides are not absorbed following oral administration","The spectrum of antimicrobial activity of aminoglycosides includes Bacteroides fragilis","Aminoglycosides are often used in combination with cephalosporins in the empiric treatment of life-threatening bacterial infections","Netilmycin is more likely to be effective than streptomycin in the treatment of a hospital-acquired infection caused by Serratia marcescens","Gentamicin is used with ampicillin for synergistic effects in the treatment of enterococcal endocarditis"],answer:1,explanation:"Aminoglycosides are INACTIVE against Bacteroides fragilis and other anaerobes because aminoglycoside transport requires energy from the electron transport chain, which is absent in anaerobes. They are effective against aerobic gram-negative organisms."},
  {id:"final177",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"All properties of aminoglycosides EXCEPT:",options:["They are highly polar polycationic compounds that are not absorbed orally","They may cause ototoxicity, nephrotoxicity, and neuromuscular blockade","They are all bactericidal, and are mainly effective against anaerobic organisms","Amikacin and gentamicin are mainly used in Pseudomonas infections","Streptomycin is used in tularemia and in T.B"],answer:2,explanation:"Aminoglycosides are effective against AEROBIC gram-negative organisms (E. coli, Pseudomonas, Klebsiella, Serratia), NOT anaerobes. They require oxygen-dependent electron transport for uptake into bacterial cells."},
  {id:"final178",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"All statements about clindamycin are accurate EXCEPT:",options:["Its mode of action is similar to that of erythromycin","It is very effective against anaerobic infections","It may cause pseudomembranous colitis","It distributes well in all body fluids including CSF","It is effective in dental infections"],answer:3,explanation:"Clindamycin does NOT penetrate the blood-brain barrier well and achieves poor CSF levels; it should NOT be used for CNS infections. It binds to the 50S ribosomal subunit (same site as erythromycin), has excellent anaerobic activity."},
  {id:"final179",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Typical therapeutic applications of erythromycin include all EXCEPT:",options:["Pseudomonas aeruginosa","Legionella pneumophila","Ureaplasma urealyticum","Chlamydia trachomatis","Corynebacterium diphteriae"],answer:0,explanation:"Erythromycin has no clinically useful activity against Pseudomonas aeruginosa (gram-negative rod). Erythromycin (macrolide) is effective against Legionella, Ureaplasma, Chlamydia, Corynebacterium, and atypical pneumonia organisms."},
  {id:"final180",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"The use of chloramphenicol may result in:",options:["Bone marrow stimulation","Phototoxicity","Aplastic anemia","Staining of teeth","Alopecia"],answer:2,explanation:"Chloramphenicol causes two types of bone marrow toxicity: reversible dose-dependent anemia and irreversible idiosyncratic aplastic anemia (1 in 25,000-40,000 patients). Gray baby syndrome occurs in neonates due to immature hepatic glucuronyl transferase."},
  {id:"final181",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Main reason to avoid chloramphenicol in most infectious diseases:",options:["Hepatotoxicity","Pulmonary fibrosis","Interstitial nephritis","Aplastic anemia","Cardiac arrhythmia"],answer:3,explanation:"Chloramphenicol use is restricted primarily because of its rare but potentially fatal idiosyncratic aplastic anemia (irreversible bone marrow failure). This unpredictable toxicity outweighs its benefits for most indications where safer alternatives exist."},
  {id:"final182",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Antacids with tetracycline reduce effectiveness because:",options:["Antacids inhibit the absorption of tetracycline","Antacids stimulate the drug microsomal metabolizing system, so that the tetracycline is metabolized more rapidly","Ions in antacids solubilize the tetracycline","Antacids enhance the renal excretion of tetracycline","High blood level of tetracycline result in increased protein binding"],answer:0,explanation:"Antacids containing aluminum, magnesium, or calcium ions chelate tetracycline, forming poorly absorbed complexes. This is a pharmacokinetic interaction at the absorption level, reducing tetracycline bioavailability by up to 50-90%."},
  {id:"final183",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 77-year-old woman with pneumonia - serum creatinine doubled after 3 days of antibiotics. Which is most likely responsible?",options:["Doxycycline","Clarithromycin","Gentamicin","Linezolid"],answer:2,explanation:"Gentamicin (aminoglycoside) accumulates in proximal tubular cells and causes acute tubular necrosis (nephrotoxicity). Rising serum creatinine is a hallmark sign. Risk factors include advanced age, pre-existing renal disease, and concurrent nephrotoxins."},
  {id:"final184",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Patient with hepatitis, cirrhosis, ascites - which drug must be carefully monitored?",options:["Erythromycin","Tobramycin","Penicillin G","Clindamycin"],answer:0,explanation:"Erythromycin is extensively metabolized by hepatic CYP3A4 and should be used with caution in liver failure. Cirrhosis reduces hepatic drug metabolism, increasing erythromycin plasma levels and risk of cardiac toxicity (QT prolongation) and hepatotoxicity."},
  {id:"final185",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"5-year-old boy with Lyme disease - doctor would not prescribe tetracycline because of:",options:["Teeth discolouration","Ototoxicity","Nephrotoxicity","Hepatotoxicity"],answer:0,explanation:"Tetracyclines chelate calcium and deposit in developing teeth (causing permanent yellowish-brown discoloration and enamel hypoplasia) and growing bones. They are contraindicated in children under 8 years. For Lyme disease in children under 8, amoxicillin or cefuroxime axetil is recommended."},
  {id:"final186",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"With respect to treatment with aminoglycoside gentamicin - which statement is correct?",options:["Doses must be individualized due to gentamicin's high first-pass metabolism","In order to be effective, it must be given frequently to maintain high plasma levels","Doses may need to be adjusted as nephrotoxicity is a common adverse effect","It is generally well tolerated and has a wide therapeutic index"],answer:2,explanation:"Gentamicin nephrotoxicity (acute tubular necrosis) occurs in 10-25% of patients, necessitating regular monitoring of serum creatinine and drug trough levels. Gentamicin has a NARROW therapeutic index."},
  {id:"final187",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Tetracycline statement that is INCORRECT:",options:["Tetracyclines bind to 30S subunits of the bacterial ribosome and block protein synthesis","Tetracyclines are effective in treating pharyngitis due to streptococcal infections","Phototoxicity is encountered most frequently with demeclocycline and doxycycline","Unlike other tetracyclines, doxycycline can be used in treating patients with renal failure","Though useful in eradicating the meningococcal carrier state, minocycline is not effective for CNS infections"],answer:1,explanation:"Tetracyclines are NOT effective for streptococcal pharyngitis due to widespread resistance of Streptococcus pyogenes. Penicillin or amoxicillin remains the drug of choice."},
  {id:"final188",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Drug/adverse effect pairing that is INCORRECT: Ethambutol - Red-orange color secretions:",options:["Isoniazid: Hepatotoxicity","Zidovudine: Leukopenia","Didanosine: Pancreatitis","Pyrazinamide: Gouty attacks","Ethambutol: Red-orange color secretions"],answer:4,explanation:"Ethambutol causes OPTIC NEURITIS (decreased visual acuity, loss of red-green color discrimination), not red-orange secretions. Red-orange discoloration of urine, tears, and bodily secretions is caused by RIFAMPIN."},
  {id:"final189",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Elimination half-life of which tetracycline remains unchanged in an anuric patient?",options:["Tetracycline","Oxytetracycline","Methacycline","Doxycycline","Chlorotetracycline"],answer:3,explanation:"Doxycycline is excreted primarily via the biliary/GI route (bile and feces) rather than the kidneys. Therefore, renal failure does NOT affect its half-life significantly. Other tetracyclines are renally excreted and accumulate in renal failure."},
  {id:"final190",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"All first-line antituberculous drugs EXCEPT:",options:["Ethionamide","INH","Rifampin","Ethambutol","Streptomycin"],answer:0,explanation:"Ethionamide is a SECOND-LINE antituberculous drug used for MDR-TB. First-line drugs are: Isoniazid (INH), Rifampin, Pyrazinamide, Ethambutol, and Streptomycin."},
  {id:"final191",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Relative to ciprofloxacin, levofloxacin has improved activity against:",options:["Bacteroides fragilis","Escherichia coli","Haemophilus influenzae","Mycoplasma pneumoniae","Streptococcus pneumoniae"],answer:4,explanation:"Levofloxacin is a respiratory fluoroquinolone with enhanced gram-positive activity, particularly against Streptococcus pneumoniae. Ciprofloxacin has limited activity against S. pneumoniae, which is why levofloxacin and moxifloxacin are preferred for community-acquired pneumonia."},
  {id:"final192",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Drug or drug combination effective against VRE S. aureus and most strains of E. faecalis:",options:["Ceftriaxone","Gentamicin","Imipenem/cilastatin","Piperacillin/tazobactam","Streptogramins"],answer:4,explanation:"Quinupristin/dalfopristin (streptogramins) have activity against vancomycin-resistant staphylococci. Note: they are active against Enterococcus faecium but NOT E. faecalis. Linezolid is preferred for VRE faecalis. Streptogramins bind two different sites on the 50S subunit."},
  {id:"final193",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Gray-baby syndrome is caused by:",options:["Trimethoprim-sulfamethoxazole","Gentamicin","Tetracycline","Chloramphenicol","Ciprofloxacin"],answer:3,explanation:"Gray baby syndrome is caused by chloramphenicol accumulation in neonates who lack adequate hepatic glucuronyl transferase to conjugate and excrete the drug. It presents with abdominal distension, vomiting, progressive pallid cyanosis (gray color), cardiovascular collapse."},
  {id:"final194",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Ototoxicity and nephrotoxicity are caused by:",options:["Trimethoprim-sulfamethoxazole","Gentamicin","Tetracycline","Chloramphenicol","Ciprofloxacin"],answer:1,explanation:"Aminoglycosides (gentamicin, tobramycin, amikacin, streptomycin) cause both ototoxicity (irreversible damage to cochlear and vestibular hair cells) and nephrotoxicity (acute tubular necrosis). Risk is increased by concurrent use of loop diuretics."},
  {id:"final195",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Stevens-Johnson syndrome is associated with:",options:["Trimethoprim-sulfamethoxazole","Gentamicin","Tetracycline","Chloramphenicol","Ciprofloxacin"],answer:0,explanation:"Stevens-Johnson syndrome (SJS) is most commonly associated with sulfonamides (including TMP-SMX), anticonvulsants, allopurinol, and NSAIDs."},
  {id:"final196",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Tooth discoloration is caused by:",options:["Trimethoprim-sulfamethoxazole","Gentamicin","Tetracycline","Chloramphenicol","Ciprofloxacin"],answer:2,explanation:"Tetracyclines chelate calcium and form stable complexes that deposit in calcifying tissues (teeth, bone) during development, causing permanent yellowish-brown discoloration and enamel hypoplasia. Effect is most pronounced when given during tooth development (up to age 8 years)."},
  {id:"final197",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which anticancer drug is incorrectly matched: Vincristine - Disrupts DNA structure:",options:["Cyclophosphamide: Alkylating agent that binds to DNA bases","Methotrexate: Inhibition of dihydrofolate reductase enzyme","Tamoxifen: Estrogen antagonist","Asparaginase: Depletes the cell from asparagines","Vincristine: Disrupt DNA structure"],answer:4,explanation:"Vincristine does NOT disrupt DNA structure. Vincristine (vinca alkaloid) binds to tubulin and INHIBITS MICROTUBULE POLYMERIZATION, arresting cells in M phase of mitosis. Drugs that disrupt DNA include alkylating agents (cyclophosphamide)."},
  {id:"final198",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"A patient had recurrent UTIs with ciprofloxacin resistance - most likely cause:",options:["Mutation of topoisomerase I","Mutation of DNA gyrase","Production of active efflux pump","Plasmid-mediated resistance"],answer:1,explanation:"The primary mechanism of fluoroquinolone resistance is chromosomal mutation in the gyrA gene encoding DNA gyrase subunit A, reducing the drug's binding to the enzyme-DNA complex. Efflux pumps are a secondary mechanism."},
  {id:"final199",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Sulfonamides mechanism - INCORRECT statement: Sulphonamides interfere with the build-up of peptide chains on ribosomes:",options:["Penicillins interfere with bacterial cell wall synthesis","Amphotericin B interferes with the function of the cytoplasmic membrane of fungi","Sulphonamides interfere with the build-up of peptide chains on ribosomes","Tetracyclines inhibit bacterial protein synthesis","Rifampicin interferes with bacterial nucleic acid synthesis"],answer:2,explanation:"Sulfonamides do NOT inhibit ribosomes. They are structural analogs of PABA that competitively inhibit dihydropteroate synthase, blocking folic acid synthesis in bacteria."},
  {id:"final200",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"In antimicrobial drug treatment, all are correct EXCEPT - the combination of bactericidal and bacteriostatic drug is particularly efficacious:",options:["Bactericidal drugs lead directly to the destruction of bacterial cells","The ultimate efficacy of bacteriostatic drugs depends on the host's own defense mechanisms","Antimicrobials produce their effect by interfering with metabolic pathways vital for the organism","The production of an enzyme which destroys the antibacterial drug gives rise to one type of antibiotic resistance","The combination of a bactericidal and bacteriostatic drug is particularly efficacious"],answer:4,explanation:"Combining bactericidal and bacteriostatic drugs is generally ANTAGONISTIC. The bacteriostatic drug prevents bacterial growth, reducing the effectiveness of bactericidal drugs that require actively dividing cells (especially beta-lactams)."},
  {id:"final201",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"All statements about Co-trimoxazole are correct EXCEPT:",options:["Is the treatment of choice for pneumonia due to Pneumocystis carinii","Has a broader spectrum of action than sulfonamides","May cause hemolytic anemia in patients with glucose-6-phosphate dehydrogenase deficiency","May increase levels of methotrexate due to displacement from albumin binding sites by sulfamethoxazole","Is a combination of sulfamethoxazole and clavulanic acid"],answer:4,explanation:"Co-trimoxazole is a combination of TRIMETHOPRIM + sulfamethoxazole (NOT clavulanic acid)."},
  {id:"final202",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"1-day-old infant with jaundice - mother was taking antibiotic for UTI 1 week before delivery. What antibiotic did she take?",options:["Azithromycin","Trimethoprim-sulfamethoxazole","Amoxicillin","Fourth-generation cephalosporins"],answer:1,explanation:"Co-trimoxazole (TMP-SMX) is contraindicated near term because sulfonamides displace bilirubin from albumin binding sites. The displaced bilirubin accumulates in neonatal brain tissue (kernicterus) because neonates have immature blood-brain barriers."},
  {id:"final203",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Drug interactions - Pharmacokinetic interactions can result from all EXCEPT:",options:["Impaired absorption","Induction of the drug microsomal enzyme metabolizing system","Inhibition of the drug microsomal enzyme metabolizing system","Inhibition of renal excretion","The combination of a bacteriostatic and a bactericidal antibiotic"],answer:4,explanation:"Combining bacteriostatic and bactericidal antibiotics is a PHARMACODYNAMIC interaction (drug-drug interaction at the level of effect), NOT a pharmacokinetic interaction. Pharmacokinetic interactions involve changes in absorption, distribution, metabolism, or excretion."},
  {id:"final204",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Which drug is least likely to affect hepatic metabolism of other drugs?",options:["Ampicillin","Clarithromycin","Ketoconazole","Griseofulvin","Rifampin"],answer:0,explanation:"Ampicillin does not significantly inhibit or induce hepatic CYP enzymes. Clarithromycin and ketoconazole inhibit CYP3A4. Rifampin is a potent CYP inducer. Griseofulvin also induces CYP enzymes."},
  {id:"final205",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Ciprofloxacin - contraindicated below age 18 years because of:",options:["Arthropathy (articular cartilage erosion in weight-bearing joints)","Ototoxicity","Nephrotoxicity","Aplastic anemia","Kernicterus"],answer:0,explanation:"Fluoroquinolones (ciprofloxacin, levofloxacin) are generally contraindicated in children and adolescents under 18 years because animal studies showed cartilage erosion and arthropathy in weight-bearing joints."},
  {id:"final206",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"Matching - Drug inhibiting DNA gyrase, contraindicated below age 18:",options:["Neomycin","Ciprofloxacin","Ribavirin","Griseofulvin","Azithromycin"],answer:1,explanation:"Ciprofloxacin inhibits DNA gyrase (topoisomerase II) and topoisomerase IV, preventing DNA replication, repair, and transcription. It is contraindicated in children under 18 due to risk of cartilage erosion."},
  {id:"final207",exam:"final",lecture:"Nucleic Acid Synthesis Inhibitors",q:"All drugs are cell-cycle specific EXCEPT:",options:["5-fluorouracil","Methotrexate","Vincristine","Cyclophosphamide","6-mercaptopurine"],answer:3,explanation:"Cyclophosphamide is a cell cycle NON-SPECIFIC alkylating agent that can kill cancer cells regardless of their phase in the cell cycle. Cell cycle-specific drugs include: 5-fluorouracil (S phase), methotrexate (S phase), vincristine (M phase), and 6-mercaptopurine (S phase)."},
  {id:"final208",exam:"final",lecture:"Antifungal Drugs",q:"Dose-limiting toxicity of amphotericin B is:",options:["Myelosuppression","Infusion-related adverse effects","Renal toxicity","Hypotension","Hepatitis"],answer:2,explanation:"Amphotericin B causes dose-limiting nephrotoxicity in up to 80% of patients, manifesting as azotemia, renal tubular acidosis, and hypokalemia. It binds ergosterol in fungal membranes but also binds cholesterol in renal tubular cells. Liposomal formulations reduce nephrotoxicity."},
  {id:"final209",exam:"final",lecture:"Antifungal Drugs",q:"Regarding clinical uses of liposomal amphotericin B formulation - which is more accurate?",options:["Amphotericin B is expensive","To reduce amphotericin B nephrotoxicity","To enhance antifungal spectrum of activity","To improve oral bioavailability"],answer:1,explanation:"Liposomal amphotericin B (AmBisome) was developed primarily to reduce the severe nephrotoxicity of conventional amphotericin B. Liposomes preferentially interact with fungal cell membranes (high ergosterol content) rather than renal tubular cell membranes."},
  {id:"final210",exam:"final",lecture:"Antifungal Drugs",q:"Which antifungal drug is limited to Aspergillus and Candida?",options:["Amphotericin B","Fluconazole","Caspofungin","Voriconazole"],answer:2,explanation:"Caspofungin (echinocandin) inhibits beta-1,3-glucan synthase, disrupting fungal cell wall synthesis. Its spectrum is primarily limited to Candida species and Aspergillus species. It lacks activity against Cryptococcus neoformans."},
  {id:"final211",exam:"final",lecture:"Antifungal Drugs",q:"Topical antifungal used for treating tinea cruris and tinea corporis:",options:["Terbinafine","Itraconazole","Nystatin","Fluconazole"],answer:0,explanation:"Terbinafine (allylamine) inhibits squalene epoxidase in the ergosterol biosynthesis pathway. It is highly effective topically for dermatophyte infections (tinea pedis, corporis, cruris). It is fungicidal against dermatophytes."},
  {id:"final212",exam:"final",lecture:"Antifungal Drugs",q:"Which correctly describes the mechanism of terbinafine?",options:["Formation of pores in the cell membrane","Inhibition of thymidylate synthase","Accumulation of toxic squalene","Inhibition of ergosterol synthesis"],answer:2,explanation:"Terbinafine inhibits squalene epoxidase, blocking the conversion of squalene to squalene 2,3-epoxide in the ergosterol biosynthesis pathway. This causes intracellular accumulation of toxic squalene and depletion of ergosterol. This mechanism distinguishes terbinafine from azoles (which inhibit C14-alpha demethylase)."},
  {id:"final213",exam:"final",lecture:"Antifungal Drugs",q:"Matching - Antifungal drug used for dermatophytes of the nail (Griseofulvin):",options:["Neomycin","Ciprofloxacin","Ribavirin","Griseofulvin","Azithromycin"],answer:3,explanation:"Griseofulvin inhibits fungal mitosis by binding to tubulin, disrupting microtubule assembly. It concentrates in keratin-containing tissues (skin, hair, nails) and is used orally for dermatophyte infections of nails and hair. It requires months of treatment for nail infections."},
  {id:"final214",exam:"final",lecture:"Antifungal Drugs",q:"Matching - Antifungal drug used orally for fungal meningitis in AIDS patient (Fluconazole):",options:["Ketoconazole","Nystatin","Amphotericin B","Fluconazole"],answer:3,explanation:"Fluconazole is the drug used for maintenance therapy of cryptococcal meningitis in AIDS patients (after induction with amphotericin B + flucytosine). It has excellent oral bioavailability (~90%) and good CNS penetration. It inhibits ergosterol synthesis by blocking CYP51 (C14-alpha demethylase)."},
  {id:"final215",exam:"final",lecture:"Antifungal Drugs",q:"An azole most commonly used for topical treatment of Candidiasis:",options:["Terbinafine","Amphotericin B","Flucytosine","Clotrimazole"],answer:3,explanation:"Clotrimazole is the most commonly used topical azole for oral and vaginal candidiasis. All azoles inhibit fungal cytochrome P450 enzyme 14-alpha-demethylase, blocking ergosterol synthesis from lanosterol."},
  {id:"final216",exam:"final",lecture:"Antifungal Drugs",q:"AIDS patient with cryptococcal meningitis who refuses IV medication - which antifungal orally?",options:["Ketoconazole","Amphotericin B","Itraconazole","Nystatin","Fluconazole"],answer:4,explanation:"Fluconazole has excellent oral bioavailability and good CNS penetration, making it suitable for treating cryptococcal meningitis orally. Amphotericin B is only available parenterally. Ketoconazole does not penetrate the CSF well. Nystatin is only topical."},
  {id:"final217",exam:"final",lecture:"Antifungal Drugs",q:"Matching - Indinavir (HIV protease inhibitor that characteristically causes renal stone formation):",options:["Saquinavir","Ritonavir","Indinavir","Lopinavir"],answer:2,explanation:"Indinavir is an HIV protease inhibitor that causes nephrolithiasis (kidney stones) in up to 4-8% of patients due to crystallization of indinavir metabolites in urine. Prevention includes adequate hydration (>1.5 L/day)."},
  {id:"final218",exam:"final",lecture:"Antifungal Drugs",q:"Matching - Amantadine - antiviral drug used prophylactically against influenza A, preventing uncoating of viral DNA:",options:["Acyclovir","Ribavirin","Oseltamivir","Amantadine"],answer:3,explanation:"Amantadine and rimantadine inhibit the M2 ion channel of influenza A virus, blocking the acidification required for viral uncoating (release of viral RNA into the cell). They are active only against influenza A (not influenza B). Due to widespread resistance, they are no longer recommended."},
  {id:"final219",exam:"final",lecture:"Antiparasitic Drugs",q:"A farmer develops excessive sweating, vomiting, and salivation after work - what is the antidote?",options:["PAM and atropine","Naloxone and flumazenil","N-acetylcysteine","Activated charcoal only"],answer:0,explanation:"Excessive secretions, sweating, and GI symptoms indicate cholinergic toxicity from organophosphate pesticide poisoning. Treatment: Atropine (muscarinic antagonist) + Pralidoxime/PAM (reactivates acetylcholinesterase if given before 'aging' occurs)."},
  {id:"final220",exam:"final",lecture:"Antiparasitic Drugs",q:"Patient with C. difficile pseudomembranous colitis - antimicrobial therapy:",options:["Amoxicillin","Ciprofloxacin","Metronidazole","Erythromycin"],answer:2,explanation:"Metronidazole is first-line for C. difficile colitis. It enters anaerobic organisms and is reduced by ferredoxin to form reactive nitro radicals that cause DNA strand breakage. It is also the drug of choice for Entamoeba histolytica (amebiasis), Giardia lamblia, and Trichomonas vaginalis."},
  {id:"final221",exam:"final",lecture:"Antiparasitic Drugs",q:"Matching - Drug that is drug of choice in severe amebic disease and hepatic abscess; activated by pyruvate-ferredoxin oxidoreductase:",options:["Diloxanide furoate","Emetine","Iodoquinol","Metronidazole","Paromomycin"],answer:3,explanation:"Metronidazole is the drug of choice for severe intestinal amebiasis and amebic liver abscess. It is activated to toxic intermediates by the pyruvate-ferredoxin oxidoreductase enzyme system present in the parasite, causing DNA strand breakage."},
  {id:"final222",exam:"final",lecture:"Antiviral Drugs",q:"Which enzyme or replicative process is the main target of zidovudine?",options:["RNA synthesis","Protease inhibitor","Nucleoside reverse transcriptase inhibitors","Non-nucleoside reverse transcriptase inhibitors"],answer:2,explanation:"Zidovudine (AZT/ZDV) is a nucleoside reverse transcriptase inhibitor (NRTI) that inhibits HIV reverse transcriptase. It is phosphorylated by cellular kinases to AZT-triphosphate, which competes with thymidine triphosphate for incorporation into viral DNA, causing chain termination. Adverse effects include anemia, neutropenia (myelosuppression), and myopathy."},
  {id:"final223",exam:"final",lecture:"Antiviral Drugs",q:"HIV patient on several drugs developed hyperlipidemia and insulin resistance - which drug caused these symptoms?",options:["Ketoconazole","Trimethoprim","Indinavir","Zidovudine"],answer:2,explanation:"Indinavir is an HIV protease inhibitor. Metabolic syndrome (hyperlipidemia, insulin resistance/hyperglycemia, lipodystrophy) are class effects of HIV protease inhibitors. Specific to indinavir: nephrolithiasis due to drug crystallization in urine."},
  {id:"final224",exam:"final",lecture:"Antiviral Drugs",q:"Matching - Ribavirin - effective against severe RSV and chronic hepatitis C:",options:["Acyclovir","Ganciclovir","Ribavirin","Amantadine"],answer:2,explanation:"Ribavirin is a broad-spectrum antiviral guanosine analog that inhibits viral RNA-dependent RNA polymerase and mRNA capping. It is used as aerosol for RSV bronchiolitis in infants, and in combination with interferon-alpha for chronic hepatitis C."},
  {id:"final225",exam:"final",lecture:"Antiviral Drugs",q:"Matching - Lamivudine - inhibits reverse transcriptase, used for both HIV and hepatitis B:",options:["Zidovudine","Lamivudine","Didanosine","Stavudine"],answer:1,explanation:"Lamivudine (3TC) is an NRTI that inhibits both HIV reverse transcriptase and HBV DNA polymerase. For HIV it is part of combination ART; for HBV it reduces viral replication."},
  {id:"final226",exam:"final",lecture:"Antiviral Drugs",q:"Matching - Ganciclovir - used to treat cytomegalovirus retinitis:",options:["Acyclovir","Foscarnet","Ribavirin","Ganciclovir"],answer:3,explanation:"Ganciclovir is used for CMV retinitis and other CMV infections in immunocompromised patients. It is phosphorylated by CMV UL97 protein kinase, then by cellular kinases to the active triphosphate form that inhibits CMV DNA polymerase. Main adverse effect is myelosuppression."},
  {id:"final227",exam:"final",lecture:"Antiviral Drugs",q:"Matching - Zanamivir - effective against both type A and B influenza, not effective orally, inhaled or intranasal:",options:["Oseltamivir","Amantadine","Zanamivir","Rimantadine"],answer:2,explanation:"Zanamivir is a neuraminidase inhibitor that must be inhaled (not orally active) and prevents release of new influenza virions. It is effective against both influenza A and B. It can cause bronchospasm in asthmatic patients."},
  {id:"final228",exam:"final",lecture:"Antiviral Drugs",q:"Matching - Saquinavir - HIV protease inhibitor:",options:["Nucleoside reverse transcriptase inhibitor","Non-nucleoside reverse transcriptase inhibitor","HIV protease inhibitor","Integrase inhibitor"],answer:2,explanation:"Saquinavir was the first HIV protease inhibitor approved. HIV protease inhibitors prevent cleavage of viral polyprotein precursors into functional proteins, resulting in immature, non-infectious viral particles. Adverse effects include metabolic syndrome."},
  {id:"final229",exam:"final",lecture:"Antiviral Drugs",q:"All drugs correctly paired with adverse effect EXCEPT - Ethambutol: Red-orange color secretions:",options:["Isoniazid: Hepatotoxicity","Zidovudine: Leukopenia","Didanosine: Pancreatitis","Pyrazinamide: Gouty attacks","Ethambutol: Red-orange color secretions"],answer:4,explanation:"Ethambutol causes OPTIC NEURITIS (not red-orange secretions). Red-orange discoloration of urine, sweat, and tears is caused by RIFAMPIN."},
  {id:"final230",exam:"final",lecture:"Antiviral Drugs",q:"Matching - Voriconazole - broad-spectrum antifungal, orally active, penetrates CNS:",options:["Fluconazole","Voriconazole","Ketoconazole","Itraconazole"],answer:1,explanation:"Voriconazole is an extended-spectrum triazole antifungal used as first-line treatment for invasive aspergillosis. It has excellent oral bioavailability (~96%), good tissue and CSF penetration, and is effective against Aspergillus, Candida, Fusarium, and Scedosporium."},
  {id:"final231",exam:"final",lecture:"Anticancer Drugs",q:"What drug is used for testicular carcinoma and can cause nephrotoxicity?",options:["Cisplatin","Bleomycin","Vinblastine","Methotrexate"],answer:0,explanation:"Cisplatin is the cornerstone drug for testicular cancer chemotherapy (along with bleomycin and etoposide in BEP regimen). Its dose-limiting toxicity is nephrotoxicity (acute tubular necrosis), which is prevented by vigorous IV hydration with saline and mannitol diuresis. Cisplatin also causes ototoxicity, severe nausea/vomiting, and peripheral neuropathy."},
  {id:"final232",exam:"final",lecture:"Anticancer Drugs",q:"Adverse effect of bleomycin:",options:["Cardiac toxicity","Renal toxicity","Pulmonary toxicity","Hepatic toxicity"],answer:2,explanation:"Bleomycin's major dose-limiting toxicity is pulmonary toxicity (interstitial pneumonitis progressing to pulmonary fibrosis), which is related to cumulative dose (risk increases markedly above 400 units total). Unlike most cytotoxics, bleomycin causes MINIMAL myelosuppression."},
  {id:"final233",exam:"final",lecture:"Anticancer Drugs",q:"Rationale for combination of anticancer drugs is:",options:["Reduce the incidence of drug-induced nausea and vomiting","Reduce the risk of drug resistance","Remove the need for a 'drug holiday'","Administer them together in the same formulation"],answer:1,explanation:"The primary rationale for combination chemotherapy is to reduce drug resistance by simultaneously attacking cancer cells through multiple different mechanisms, preventing selection of resistant clones."},
  {id:"final234",exam:"final",lecture:"Anticancer Drugs",q:"Nanoparticles promote tumor selectivity - passively entering tumor cells depends on:",options:["Blood vessels in the tumor are rigid","Blood vessels in the tumor are leaky","Low enzyme content in tumor cells","High enzyme content in tumor cells"],answer:1,explanation:"Tumor blood vessels are structurally abnormal (leaky with wide intercellular gaps) and have defective lymphatic drainage. This allows nanoparticles and macromolecules to extravasate and accumulate in tumor tissue - the Enhanced Permeability and Retention (EPR) effect."},
  {id:"final235",exam:"final",lecture:"Anticancer Drugs",q:"A 45-year-old male in ABVD regimen developed heart failure after 4 cycles - which drug is responsible?",options:["Dacarbazine","Vinblastine","Bleomycin","Doxorubicin"],answer:3,explanation:"Doxorubicin (Adriamycin) causes irreversible cumulative dose-dependent cardiomyopathy and congestive heart failure through free radical damage to cardiac mitochondria. The risk increases substantially above a cumulative dose of 550 mg/m². Dexrazoxane is used as a cardioprotectant. Bleomycin causes pulmonary toxicity."},
  {id:"final236",exam:"final",lecture:"Anticancer Drugs",q:"In MOPP and ABVD regimens - which class used in BOTH is cell cycle specific?",options:["Plant alkaloids","Glucocorticoids","Antibiotics","Alkylating agents"],answer:0,explanation:"Plant alkaloids (vincristine in MOPP, vinblastine in ABVD) are cell cycle specific (M phase) agents that bind tubulin and inhibit mitotic spindle formation. Mechlorethamine (alkylating agent in MOPP) and dacarbazine (in ABVD) are cell cycle NON-specific."},
  {id:"final237",exam:"final",lecture:"Anticancer Drugs",q:"Breast cancer patient on cyclophosphamide developed acute hemorrhagic cystitis - what is the best primary prevention?",options:["Mesna","Folinic acid","Vitamin K","Folic acid"],answer:0,explanation:"Mesna (sodium 2-mercaptoethane sulfonate) is co-administered with cyclophosphamide or ifosfamide to prevent hemorrhagic cystitis. It is excreted in urine where it reacts with and inactivates acrolein (the toxic metabolite responsible for urothelial toxicity). Leucovorin (folinic acid) prevents methotrexate toxicity."},
  {id:"final238",exam:"final",lecture:"Anticancer Drugs",q:"All statements true EXCEPT - Tamoxifen complexes with DNA to inhibit RNA synthesis:",options:["Patients with Hodgkin's disease being treated with procarbazine should be cautioned against ingesting food from fermentative sources","Vincristine is effective in inducing remission in childhood acute lymphocytic leukemia","X-irradiation of the cranio-spinal axis is an effective adjuvant therapy in the treatment of acute lymphocytic leukemia","Treatment with alkylating agent can induce secondary tumors","Tamoxifen complexes with DNA to inhibit RNA synthesis"],answer:4,explanation:"Tamoxifen is a selective estrogen receptor modulator (SERM) that COMPETITIVELY BLOCKS ESTROGEN RECEPTORS in breast tissue - it does NOT complex with DNA or inhibit RNA synthesis directly. Tamoxifen is used for ER-positive breast cancer treatment and prevention."},
  {id:"final239",exam:"final",lecture:"Anticancer Drugs",q:"Which anticancer drug is incorrectly matched: Vincristine: Disrupts DNA structure:",options:["Cyclophosphamide: Alkylating agent that binds to DNA bases","Methotrexate: Inhibition of dihydrofolate reductase enzyme","Tamoxifen: Estrogen antagonist","Asparaginase: Depletes the cell from asparagines","Vincristine: Disrupt DNA structure"],answer:4,explanation:"Vincristine (vinca alkaloid) binds to tubulin dimers and INHIBITS MICROTUBULE POLYMERIZATION (not DNA disruption), arresting mitosis at metaphase. Drugs that disrupt DNA structure are alkylating agents and platinum compounds."},
  {id:"final240",exam:"final",lecture:"Anticancer Drugs",q:"All drugs are cell-cycle specific EXCEPT:",options:["5-fluorouracil","Methotrexate","Vincristine","Cyclophosphamide","6-mercaptopurine"],answer:3,explanation:"Cyclophosphamide is a cell cycle NON-SPECIFIC (CCNS) alkylating agent that damages DNA at any phase of the cell cycle. Cell cycle-specific (CCS) agents: 5-fluorouracil (S phase), methotrexate (S phase), vincristine (M phase), bleomycin (G2/M), and 6-mercaptopurine (S phase)."},
  {id:"final241",exam:"final",lecture:"Anticancer Drugs",q:"All statements about Co-trimoxazole correct EXCEPT - Is a combination of sulfamethoxazole and clavulanic acid:",options:["Is the treatment of choice for pneumonia due to Pneumocystis carinii","Has a broader spectrum of action than sulfonamides","May cause hemolytic anemia in patients with G6PD deficiency","May increase levels of methotrexate due to displacement from albumin binding sites","Is a combination of sulfamethoxazole and clavulanic acid"],answer:4,explanation:"Co-trimoxazole = TMP + sulfamethoxazole (NOT clavulanic acid). Trimethoprim inhibits dihydrofolate reductase (step 2) and sulfamethoxazole inhibits dihydropteroate synthase (step 1), achieving sequential blockade of folate synthesis."},
  {id:"final242",exam:"final",lecture:"Anticancer Drugs",q:"Which drug is responsible for cardiomyopathy in the ABVD regimen?",options:["Cyclophosphamide","Doxorubicin","Fluorouracil","Methotrexate","Tamoxifen"],answer:1,explanation:"Doxorubicin generates reactive oxygen species through iron-mediated reactions, causing oxidative damage to cardiac mitochondria and cardiomyocytes. This leads to dilated cardiomyopathy and congestive heart failure. The cardiac toxicity is irreversible and cumulative dose-dependent. Dexrazoxane chelates iron and prevents doxorubicin-iron complex formation. ## Summary: Questions per Category | Category | Number of Questions | |---|---| | Cell Wall Inhibitors | 56 | | Protein Synthesis Inhibitors | 23 | | Inhibitors of Nucleic Acid Synthesis | 10 | | Antifungal Drugs | 11 | | Antiparasitic Drugs | 3 | | Antiviral Drugs | 9 | | Anticancer Drugs | 12 | | TOTAL | 124 |"},
  {id:"final243",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which of the following is an ACQUIRED mechanism of penicillin resistance?",options:["Alteration of penicillin-binding proteins (PBPs)","Beta-lactamase production","Alteration of cell mitochondria","Decreased expression of porins"],answer:0,explanation:"Alteration of PBPs is an acquired resistance mechanism (e.g., MRSA acquires mecA gene → PBP2a with low penicillin affinity; penicillin-resistant S. pneumoniae via PBP mutations). Beta-lactamase production is also acquired. Mitochondria are absent from bacteria. Decreased porin expression is more of a natural/intrinsic mechanism in gram-negatives limiting drug entry."},
  {id:"final244",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"A patient on a sulfonamide develops crystalluria. What is the best way to prevent this?",options:["Decrease fluid intake","Folinic acid supplementation","Alkalization of urine","Increase the drug concentration"],answer:2,explanation:"Sulfonamides are more soluble in alkaline urine. Alkalinizing the urine (e.g., with sodium bicarbonate) combined with adequate fluid intake prevents sulfonamide crystal formation in the renal tubules. Acidic urine promotes precipitation and crystalluria."},
  {id:"final245",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which of the following third-generation cephalosporins cannot cross the blood-brain barrier?",options:["Cefotaxime","Ceftriaxone","Ceftazidime","Cefixime"],answer:3,explanation:"Cefixime is an oral third-generation cephalosporin that does NOT achieve adequate CSF levels and cannot be used for bacterial meningitis. Cefotaxime, ceftriaxone, and ceftazidime all penetrate the BBB sufficiently and are used for treatment of bacterial meningitis."},
  {id:"final246",exam:"final",lecture:"Cell Wall Inhibitors",q:"Beta-lactamase enzymes inactivate penicillin by breaking which bond?",options:["The beta-lactam ring amide bond","The peptidoglycan side chain bond","The lactone ring","The PBP active site bond"],answer:0,explanation:"Beta-lactamase enzymes hydrolyze the amide bond within the beta-lactam ring, opening the ring and inactivating the antibiotic before it can bind to penicillin-binding proteins (PBPs). This is the most common mechanism of penicillin resistance."},
  {id:"final247",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which tetracycline derivative acts as an ADH antagonist at the renal collecting duct, making it useful for SIADH?",options:["Doxycycline","Minocycline","Demeclocycline","Tetracycline"],answer:2,explanation:"Demeclocycline uniquely blocks the action of ADH (antidiuretic hormone) at the renal collecting duct, causing a nephrogenic diabetes insipidus-like effect. This makes it useful in treating SIADH (syndrome of inappropriate ADH secretion). It also inhibits protein synthesis like all tetracyclines."},
  {id:"final248",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A drug inhibits protein synthesis by reversibly binding to the 30S ribosomal subunit and blocking attachment of aminoacyl-tRNA to the A site. Which drug is this?",options:["Tetracycline","Chloramphenicol","Erythromycin","Gentamicin"],answer:0,explanation:"Tetracyclines reversibly bind to the 30S ribosomal subunit (specifically 16S rRNA), blocking attachment of aminoacyl-tRNA to the A site, preventing protein elongation. This produces a bacteriostatic effect. Aminoglycosides also bind 30S but do so irreversibly and cause mRNA misreading."},
  {id:"final249",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Tobramycin mechanism of action is best described as:",options:["Misreading of the mRNA codon","Inhibition of the 70S initiation complex formation","Inhibition of translocation","Reversible binding to the 50S subunit"],answer:0,explanation:"Tobramycin (aminoglycoside) binds irreversibly to the 30S ribosomal subunit and causes misreading of the mRNA codons, leading to insertion of wrong amino acids and production of non-functional or toxic proteins. This bactericidal mechanism is shared by all aminoglycosides."},
  {id:"final250",exam:"final",lecture:"Cell Wall Inhibitors",q:"A 60-year-old female with suspected bacterial meningitis needs immediate empirical antibiotic treatment while awaiting culture results. Which single agent best covers drug-resistant pneumococcal meningitis?",options:["Ceftriaxone","Meropenem","Aztreonam","Vancomycin"],answer:3,explanation:"For suspected bacterial meningitis where penicillin-resistant or cephalosporin-resistant S. pneumoniae is possible, vancomycin is added as empirical therapy. Vancomycin covers MRSA and penicillin-resistant S. pneumoniae. Standard empirical therapy for bacterial meningitis is vancomycin PLUS a third-generation cephalosporin."},
  {id:"final251",exam:"final",lecture:"Antifungal Drugs",q:"Which of the following drugs causes dose-dependent hepatotoxicity in addition to its well-known nephrotoxicity?",options:["Clonidine","Vancomycin","Amphotericin B","Fluconazole"],answer:2,explanation:"Amphotericin B causes both dose-dependent nephrotoxicity (most significant, affecting up to 80% of patients) and hepatotoxicity (elevated liver enzymes). Among the options provided, amphotericin B is the correct answer. Ketoconazole is also well known for hepatotoxicity but is not listed here."},
  {id:"final252",exam:"final",lecture:"Cell Wall Inhibitors",q:"The most effective way gram-negative bacteria use to resist antibiotics via their outer membrane is:",options:["Altering porin channels","Increasing beta-lactamase production","Increasing efflux pump expression","Modifying penicillin-binding proteins"],answer:0,explanation:"Gram-negative bacteria have an outer membrane with porin channels that control drug entry. Altering or reducing these porins decreases antibiotic permeability — this is the most unique resistance mechanism specific to gram-negative bacteria. Beta-lactamase production and efflux pumps also contribute but are shared with gram-positives."},
  {id:"final253",exam:"final",lecture:"Cell Wall Inhibitors",q:"A boy with pneumonia did not respond to his initial antibiotic. The most appropriate next antibiotic is:",options:["Amoxicillin","Ampicillin","Floxacillin","Vancomycin"],answer:3,explanation:"If standard beta-lactam therapy fails for pneumonia, the most likely cause is MRSA or penicillin-resistant S. pneumoniae. Vancomycin is the drug of choice in this scenario as it covers both MRSA and highly penicillin-resistant pneumococci."},
  {id:"final254",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"The fluoroquinolone with the LEAST effective activity against Pseudomonas aeruginosa is:",options:["Moxifloxacin","Ciprofloxacin","Levofloxacin","Norfloxacin"],answer:0,explanation:"Moxifloxacin (4th generation fluoroquinolone) has excellent gram-positive and atypical organism coverage but POOR anti-pseudomonal activity. Ciprofloxacin has the best Pseudomonas activity among fluoroquinolones. Moxifloxacin should not be used to treat Pseudomonas infections."},
  {id:"final255",exam:"final",lecture:"Antifungal Drugs",q:"A patient receiving antibiotics for bacterial, fungal, and protozoal infections develops renal dysfunction. Which drug most likely caused this?",options:["Amphotericin B","Metronidazole","Ciprofloxacin","Azithromycin"],answer:0,explanation:"Amphotericin B is the most nephrotoxic antimicrobial agent — it binds cholesterol in renal tubular cell membranes causing proximal tubular necrosis, decreased GFR, azotemia, and hypokalemia. Among all antimicrobials, amphotericin B is the classic cause of severe drug-induced renal dysfunction."},
  {id:"final256",exam:"final",lecture:"Cell Wall Inhibitors",q:"A lumbar puncture from a patient with gram-negative pneumonia reveals bacteria in the CSF. Which antibiotic will be most effective?",options:["A third-generation cephalosporin","A second-generation cephalosporin","A first-generation cephalosporin","Azithromycin"],answer:0,explanation:"Third-generation cephalosporins (cefotaxime, ceftriaxone, ceftazidime) both penetrate the blood-brain barrier/CSF and have broad gram-negative coverage. First and second-generation cephalosporins do not achieve adequate CSF levels and are not appropriate for bacterial meningitis."},
  {id:"final257",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"A patient is given a drug that targets dihydropteroate synthase. What are the most common adverse effects?",options:["Skin rash only","Kernicterus in neonates only","Both skin rash and kernicterus in neonates","Neither — it is generally well tolerated"],answer:2,explanation:"Sulfonamides (dihydropteroate synthase inhibitors) commonly cause: (1) Skin reactions — rashes, Stevens-Johnson syndrome, and (2) Kernicterus — displacement of bilirubin from albumin in neonates causing brain damage. Both are well-documented adverse effects of this drug class."},
  {id:"final258",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Sulfasalazine is a prodrug combination of which two components?",options:["5-aminosalicylate and sulfapyridine","Trimethoprim and sulfamethoxazole","Sulfadiazine and pyrimethamine","5-aminosalicylate and clavulanic acid"],answer:0,explanation:"Sulfasalazine is a prodrug consisting of 5-aminosalicylic acid (5-ASA, the active anti-inflammatory component) linked to sulfapyridine (the sulfonamide carrier). Colonic bacteria cleave the azo bond releasing 5-ASA locally in the colon where it inhibits prostaglandin synthesis."},
  {id:"final259",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which drug is the classic first-line treatment for mild-to-moderate ulcerative colitis?",options:["Sulfasalazine","Ciprofloxacin","Doxycycline","Trimethoprim-sulfamethoxazole"],answer:0,explanation:"Sulfasalazine is the classic first-line drug for mild-to-moderate ulcerative colitis and Crohn's disease. The 5-ASA component acts locally in the colon to inhibit prostaglandin synthesis and reduce inflammation. It is not used for systemic bacterial infections."},
  {id:"final260",exam:"final",lecture:"Anticancer Drugs",q:"An anticancer drug used for treating Wilms tumor (nephroblastoma) caused areflexia (loss of deep tendon reflexes) in a child. Which drug is responsible?",options:["Vincristine","Cyclophosphamide","Doxorubicin","Methotrexate"],answer:0,explanation:"Vincristine (vinca alkaloid) is used in treatment of Wilms tumor and its major dose-limiting toxicity is peripheral neuropathy — causing areflexia (loss of deep tendon reflexes), muscle weakness, constipation (autonomic neuropathy), and paresthesias. Unlike most cytotoxics, it causes minimal myelosuppression."},
  {id:"final261",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which oral aminoglycoside is given pre-operatively to reduce colonic bacterial load before bowel surgery?",options:["Neomycin","Gentamicin","Tobramycin","Amikacin"],answer:0,explanation:"Neomycin (oral aminoglycoside, not absorbed from the GIT) is given pre-operatively to reduce colonic bacterial flora before bowel surgery. It acts locally to kill gut bacteria. Gentamicin, tobramycin, and amikacin are only used parenterally for systemic infections due to poor oral bioavailability."},
  {id:"final262",exam:"final",lecture:"Antiviral Drugs",q:"A pregnant woman needs prophylaxis against influenza A. Which M2 inhibitor is preferred to minimize CNS adverse effects?",options:["Amantadine","Rimantadine","Oseltamivir","Zanamivir"],answer:1,explanation:"Rimantadine is preferred over amantadine because it has fewer CNS side effects (amantadine causes hallucinations, confusion, and other neuropsychiatric effects at therapeutic doses). Rimantadine achieves lower CNS concentrations than amantadine. Note: both drugs cover only influenza A."},
  {id:"final263",exam:"final",lecture:"Cell Wall Inhibitors",q:"A critically ill patient with unknown infection needs immediate empirical antibiotic therapy while awaiting culture results. Which antibiotic has the broadest antibacterial spectrum?",options:["Meropenem","Ampicillin","Ciprofloxacin","Vancomycin"],answer:0,explanation:"Meropenem (carbapenem) has one of the broadest antibacterial spectra of any injectable antibiotic, covering gram-positive cocci, gram-negative bacilli (including Pseudomonas aeruginosa), and anaerobes. It is ideal for empirical therapy in critically ill patients before culture results are available."},
  {id:"final264",exam:"final",lecture:"Antifungal Drugs",q:"A male patient taking a systemic antifungal develops gynecomastia and decreased libido. Which drug most likely caused this?",options:["Ketoconazole","Fluconazole","Itraconazole","Amphotericin B"],answer:0,explanation:"Ketoconazole inhibits adrenal and gonadal steroid synthesis (CYP17, CYP11A), reducing testosterone production and leading to gynecomastia and decreased libido in males. It also inhibits hepatic CYP3A4 causing multiple drug interactions. This effect is unique to ketoconazole among systemic antifungals."},
  {id:"final265",exam:"final",lecture:"Cell Wall Inhibitors",q:"Antibiotics may have high plasma levels but are ineffective against brain tissue infections. The most likely reason is:",options:["Low lipid solubility","High protein binding","Large molecular size","Active transport out of the CNS"],answer:0,explanation:"The blood-brain barrier requires drugs to be lipid-soluble to cross by passive diffusion. Aminoglycosides, vancomycin, and penicillins are hydrophilic (low lipid solubility) and cannot penetrate the CNS despite high plasma levels. Chloramphenicol (highly lipophilic) easily crosses the BBB."},
  {id:"final266",exam:"final",lecture:"Cell Wall Inhibitors",q:"Which statement about the biodisposition of beta-lactam antibiotics is NOT accurate?",options:["First-generation cephalosporins do not cross the BBB even when meninges are inflamed","Lability of penicillins in gastric acid can limit their oral absorption","Nafcillin and ceftriaxone are eliminated mainly via biliary secretion","Procaine penicillin G is used via intramuscular injection","The renal tubular reabsorption of amoxicillin is inhibited by probenecid"],answer:4,explanation:"Probenecid inhibits SECRETION (not reabsorption) of penicillins and cephalosporins by blocking OAT (organic anion transporters) in the renal proximal tubule, thereby increasing plasma drug levels and prolonging duration of action. All other statements are accurate."},
  {id:"final267",exam:"final",lecture:"Cell Wall Inhibitors",q:"The primary mechanism of antibacterial action of penicillins involves inhibition of which reaction in cell wall synthesis?",options:["Beta-lactamase activity","Cell membrane synthesis","N-acetylmuramic acid synthesis","Transpeptidation","Transglycosylation"],answer:3,explanation:"Penicillins bind covalently to penicillin-binding proteins (PBPs) that catalyze transpeptidation — the final cross-linking step of peptidoglycan chain synthesis. This prevents cell wall cross-linking, leading to osmotic instability and cell lysis."},
  {id:"final268",exam:"final",lecture:"Cell Wall Inhibitors",q:"An elderly debilitated patient has fever and extensive skin lesions with gram-positive cocci. The most appropriate drug is:",options:["Amoxicillin","Aztreonam","Cefoxitin","Nafcillin","Penicillin G"],answer:3,explanation:"Gram-positive cocci in skin lesions in an elderly patient most likely represents penicillinase-producing Staphylococcus aureus (MSSA). Nafcillin is an antistaphylococcal (penicillinase-resistant) penicillin effective against MSSA. Aztreonam only covers gram-negatives; penicillin G and amoxicillin are destroyed by staphylococcal beta-lactamase."},
  {id:"final269",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which adverse effect limits prolonged use of linezolid?",options:["Nephrotoxicity","Ototoxicity","Myelosuppression (thrombocytopenia, anemia)","Hepatotoxicity","Peripheral neuropathy only at first dose"],answer:2,explanation:"Linezolid (oxazolidinone) causes myelosuppression with prolonged use (>2 weeks): thrombocytopenia is most common, followed by anemia and neutropenia. Weekly CBC monitoring is required. It also inhibits MAO → serotonin syndrome risk with SSRIs/SNRIs. Linezolid does NOT cause significant nephrotoxicity or ototoxicity (unlike aminoglycosides/vancomycin)."},
  {id:"final270",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"The mechanism of antibacterial action of doxycycline involves:",options:["Antagonism of binding of aminoacyl-tRNA to bacterial ribosomes","Binding to a component of the 50S ribosomal subunit","Inhibition of DNA-dependent RNA polymerase","Interference with bacterial translocase activity","Selective inhibition of ribosomal peptidyl transferase"],answer:0,explanation:"Doxycycline (tetracycline) binds to the 30S ribosomal subunit (16S rRNA) at the A site and blocks the binding of aminoacyl-tRNA to the acceptor site, preventing protein chain elongation. This produces a bacteriostatic effect. Active transport by bacterial cells concentrates the drug intracellularly."},
  {id:"final271",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 24-year-old woman with primary syphilis and penicillin hypersensitivity is treated with tetracycline. Which statement about this treatment is accurate?",options:["Antacids do not affect the absorption of tetracycline","Azithromycin would not be effective in this patient","Yogurt consumption will prevent intestinal candidiasis","Tetracycline must be taken for 15 days for full effectiveness","Tetracycline is a potent inhibitor of hepatic drug-metabolizing enzymes"],answer:3,explanation:"Treatment of primary syphilis with tetracycline (or doxycycline) requires a 15-day course. Antacids DO reduce tetracycline absorption by chelation with divalent cations. Azithromycin CAN be used for early syphilis as an alternative. Tetracycline does not significantly inhibit CYP enzymes."},
  {id:"final272",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"The major advantage of clarithromycin over erythromycin is that clarithromycin:",options:["Does not inhibit hepatic drug-metabolizing enzymes","Eradicates mycoplasmal infections in a single dose","Has greater activity against H. pylori","Is active against methicillin-resistant staphylococci","Is active against erythromycin-resistant streptococci"],answer:2,explanation:"Clarithromycin is the macrolide of choice in H. pylori eradication triple therapy (PPI + clarithromycin + amoxicillin or metronidazole) due to superior activity against H. pylori compared to erythromycin. Both clarithromycin and erythromycin inhibit CYP3A4."},
  {id:"final273",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"The primary mechanism of resistance of gram-positive organisms to macrolide antibiotics is:",options:["Decreased activity of uptake mechanisms","Decreased drug permeability of the cytoplasmic membrane","Formation of drug-inactivating acetyltransferases","Formation of esterases that hydrolyze the lactone ring","Methylation of binding sites on the 50S ribosomal subunit"],answer:4,explanation:"The primary macrolide resistance mechanism in gram-positive organisms is MLSB resistance — ribosomal methylation by erm genes (erythromycin ribosome methylase). This methylates adenine residues on 23S rRNA of the 50S subunit, blocking macrolide, lincosamide, and streptogramin B binding."},
  {id:"final274",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 26-year-old woman treated for gonorrhea with spectinomycin returns 2 weeks later with mucopurulent cervicitis (she did not fill her doxycycline prescription). The best treatment now is:",options:["Delay treatment until infecting organism is identified","Rewrite the original prescription for oral doxycycline","Treat with single oral dose of cefixime","Treat with single oral dose of azithromycin","Write prescription for oral erythromycin for 7 days"],answer:3,explanation:"Mucopurulent cervicitis is now most likely Chlamydia trachomatis (spectinomycin treats gonorrhea but NOT chlamydia). Azithromycin 1g single oral dose is the treatment of choice for C. trachomatis and provides excellent patient compliance due to its long half-life."},
  {id:"final275",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 55-year-old patient with a prosthetic heart valve and severe penicillin allergy (anaphylaxis) undergoes a periodontal procedure. The most appropriate oral prophylaxis is:",options:["Amoxicillin 10 min before the procedure","Clindamycin 1 hour before the procedure","Erythromycin 1 hour before and 4 hours after","Vancomycin 15 min before the procedure","No prophylaxis is needed"],answer:1,explanation:"AHA guidelines for endocarditis prophylaxis in penicillin-allergic patients: clindamycin 600mg orally 30-60 minutes before dental procedures. Vancomycin is IV-only and impractical for outpatient prophylaxis. Erythromycin is no longer recommended for this indication. Severe penicillin allergy (anaphylaxis) contraindicates amoxicillin."},
  {id:"final276",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 24-year-old healthy woman with community-acquired pneumonia — which drug is most suitable?",options:["Amoxicillin","Clindamycin","Doxycycline","Linezolid","Vancomycin"],answer:2,explanation:"For mild community-acquired pneumonia in a young healthy adult without comorbidities, doxycycline or azithromycin are first-line — they cover atypical organisms (Mycoplasma, Chlamydia pneumoniae, Legionella) which are common in this age group. Amoxicillin alone does not cover atypical organisms."},
  {id:"final277",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"If the CAP patient in the previous question were treated with erythromycin, she should:",options:["Avoid exposure to sunlight","Avoid taking supplementary iron tablets","Decrease her intake of caffeinated beverages","Have plasma urea nitrogen and creatinine checked before treatment","Temporarily avoid antihistamine medications"],answer:2,explanation:"Erythromycin inhibits CYP1A2, the enzyme primarily responsible for caffeine metabolism, causing caffeine accumulation leading to palpitations, agitation, and insomnia. Patients should reduce caffeine intake during erythromycin therapy. Tetracyclines (not erythromycin) interact with iron and require sun avoidance."},
  {id:"final278",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 5-day course for community-acquired pneumonia with little risk of drug interactions is best achieved with:",options:["Ampicillin","Azithromycin","Chloramphenicol","Tetracycline","Vancomycin"],answer:1,explanation:"Azithromycin has an extremely long tissue half-life (~68 hours) allowing effective 5-day courses for CAP, covers atypical organisms, and unlike erythromycin and clarithromycin is NOT a significant CYP3A4 inhibitor, resulting in minimal drug-drug interactions."},
  {id:"final279",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Enterococcal bacteremia failed to respond to vancomycin (VRE). Which drug is most likely to be effective?",options:["Azithromycin","Clindamycin","Doxycycline","Linezolid","Minocycline"],answer:3,explanation:"Linezolid (oxazolidinone) is effective against VRE (vancomycin-resistant Enterococcus) and MRSA. It inhibits protein synthesis by binding to 23S rRNA of the 50S subunit, preventing formation of the 70S initiation complex. Major adverse effect with prolonged use is myelosuppression (thrombocytopenia)."},
  {id:"final280",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which statement about doxycycline is accurate?",options:["It is bactericidal","It is excreted mainly in the urine","It has an elimination half-life of less than 2 hours","It is more active than tetracycline against H. pylori","It is effective in Lyme disease"],answer:4,explanation:"Doxycycline is the drug of choice for Lyme disease (Borrelia burgdorferi) in adults and children over 8 years. It is bacteriostatic (not bactericidal), eliminated mainly via bile/feces (not urine), has a half-life of 18-22 hours, and clarithromycin has better H. pylori activity than doxycycline."},
  {id:"final281",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Concerning quinupristin-dalfopristin, which statement is accurate?",options:["Active in treatment of infections caused by E. faecalis","Bacteriostatic against VRE faecium","Is safe to use in patients with hepatic impairment without dose adjustment","Induces formation of hepatic drug-metabolizing enzymes","Used in management of infections caused by multidrug-resistant gram-positive organisms"],answer:4,explanation:"Quinupristin/dalfopristin (Synercid) is used for VRE faecium (NOT E. faecalis — it lacks intrinsic activity against E. faecalis) and MRSA. It is bactericidal against streptococci but bacteriostatic against E. faecium VRE. It is a potent CYP3A4 INHIBITOR (not inducer) and causes hyperbilirubinemia/hepatotoxicity — NOT safe without caution in liver impairment. Option E is the only clearly accurate statement."},
  {id:"final282",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Regarding the mechanism of action of aminoglycosides, these drugs:",options:["Are bacteriostatic","Bind to the 50S ribosomal subunit","Cause misreading of the mRNA template","Inhibit peptidyl transferase","Stabilize polysomes"],answer:2,explanation:"Aminoglycosides bind irreversibly to the 30S ribosomal subunit (16S rRNA), causing misreading of mRNA codons and incorporation of wrong amino acids into proteins. The resulting non-functional or toxic proteins cause bacterial cell death. Aminoglycosides are bactericidal, not bacteriostatic."},
  {id:"final283",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 72-kg patient with CrCl of 80 mL/min receives amikacin 360mg q8h. After 2 days, CrCl drops to 40 mL/min. The most appropriate dose adjustment is:",options:["Administer 5 mg/kg every 12 hours","Decrease the dosage to 180 mg every 8 hours","Decrease the total daily dose to 200 mg","Discontinue amikacin and switch to gentamicin","Maintain current dosage and test auditory function"],answer:1,explanation:"When CrCl drops by 50% (80 to 40 mL/min), the aminoglycoside dose should be halved while maintaining the same interval (180 mg q8h). Alternatively, the interval can be extended while maintaining the dose. Switching to gentamicin does not help as both aminoglycosides are equally nephrotoxic."},
  {id:"final284",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"All statements about clinical uses of aminoglycosides are accurate EXCEPT:",options:["They are effective in treatment of infections caused by Bacteroides fragilis","Often used in combination with cephalosporins in empiric treatment of life-threatening infections","Gentamicin used with ampicillin provides synergistic effects in enterococcal endocarditis","Netilmycin is more likely effective than streptomycin for hospital-acquired Serratia infection","Owing to their polar nature, aminoglycosides are not absorbed after oral administration"],answer:0,explanation:"Aminoglycosides require oxygen-dependent electron transport for uptake into bacterial cells, making them INACTIVE against anaerobes including Bacteroides fragilis. Metronidazole or clindamycin is used for B. fragilis infections. All other statements about aminoglycoside clinical use are accurate."},
  {id:"final285",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which statement about bacterial resistance to aminoglycosides is accurate?",options:["Resistance is due to alterations in folic acid synthesis","Emergence of resistance during treatment is common","Resistance is due to induced formation of peptidyl transferase","Resistance occurs mainly through plasmid-mediated formation of group transferase enzymes","MRSA strains are usually sensitive to aminoglycosides"],answer:3,explanation:"The primary mechanism of aminoglycoside resistance is plasmid-encoded acetyltransferases, phosphotransferases, and adenylyltransferases that chemically modify the drug, reducing its ability to bind the 30S ribosomal subunit. Unlike many antibiotics, resistance emergence during therapy is uncommon with aminoglycosides."},
  {id:"final286",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which antibiotic is most effective in treating enterococcal endocarditis when used in combination with penicillin G?",options:["Amikacin","Gentamicin","Spectinomycin","Streptomycin","Tobramycin"],answer:1,explanation:"Gentamicin is the first-line aminoglycoside for synergistic treatment of enterococcal endocarditis (combined with penicillin/ampicillin). Penicillin disrupts the cell wall → aminoglycoside enters → inhibits 30S ribosome → bactericidal synergy. Streptomycin is used as an alternative when high-level gentamicin resistance (HLGR) is present. Amikacin and tobramycin do NOT provide reliable synergy against enterococci."},
  {id:"final287",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which statement is accurate regarding the antibacterial action of gentamicin?",options:["Antibacterial activity is often reduced by concurrent cell wall synthesis inhibitors","Antibacterial action is not concentration-dependent","Antibacterial action is time-dependent like beta-lactams","Efficacy is proportional to duration that plasma level exceeds the MIC","Gentamicin continues to exert antibacterial effects even after plasma levels fall below detectable levels"],answer:4,explanation:"Aminoglycosides exhibit a significant post-antibiotic effect (PAE) — bacteria continue to be suppressed for hours after drug concentrations fall below the MIC. This supports once-daily dosing regimens. Gentamicin is concentration-dependent (not time-dependent), so efficacy correlates with peak:MIC ratio, not time above MIC."},
  {id:"final288",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which drug is most likely effective against multidrug-resistant Mycobacterium tuberculosis including strains resistant to streptomycin?",options:["Amikacin","Clarithromycin","Gentamicin","Meropenem","Spectinomycin"],answer:0,explanation:"Amikacin has fewer modifiable sites for aminoglycoside-modifying enzymes than gentamicin or tobramycin, making it active against many streptomycin-resistant MDR-TB strains. It is an important second-line anti-TB drug used in MDR-TB regimens along with other agents."},
  {id:"final289",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 67-year-old diabetic male presents with pain behind the ear, edema of the external auditory canal with purulent discharge, and facial muscle weakness. Gram stain shows gram-negative rods. Most appropriate management is:",options:["Prescribe analgesics and withhold antibiotics pending culture results","Oral cefaclor plus analgesics and send home","Spectinomycin IM and send home","Hospitalize and start IV imipenem-cilastatin","Hospitalize and start gentamicin plus ticarcillin"],answer:4,explanation:"This is malignant (necrotizing) otitis externa in a diabetic — caused by Pseudomonas aeruginosa. It is life-threatening (cranial nerve involvement, osteomyelitis of skull base). Requires hospitalization and IV anti-pseudomonal therapy: aminoglycoside (gentamicin) plus antipseudomonal penicillin (ticarcillin/piperacillin)."},
  {id:"final290",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Regarding toxicity of gentamicin, which statement is accurate?",options:["Gentamicin is more likely to cause ototoxic effects than renal damage","Ototoxicity due to gentamicin includes vestibular dysfunction which is often irreversible","Ototoxicity is reduced if loop diuretics are used to facilitate drug excretion","Systemic neomycin is usually safer than gentamicin","Earliest sign of nephrotoxicity is reduced blood creatinine"],answer:1,explanation:"Aminoglycoside ototoxicity involves both cochlear (hearing loss — predominant with amikacin) and vestibular damage (balance — predominant with gentamicin and tobramycin). Vestibular damage from gentamicin is often IRREVERSIBLE. Loop diuretics (furosemide) INCREASE ototoxicity through synergistic effect. Nephrotoxicity manifests as INCREASED serum creatinine."},
  {id:"final291",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which statement about neomycin is accurate?",options:["Commonly used adjunctively in treatment of tuberculosis","Drug of choice in Rocky Mountain spotted fever","Least nephrotoxic of the aminoglycosides","Metabolized by hepatic enzymes","Used in hepatic coma to reduce ammonia-producing intestinal bacteria"],answer:4,explanation:"Oral neomycin (not absorbed from GIT) is used in hepatic encephalopathy (hepatic coma) to reduce intestinal bacteria that produce ammonia, lowering blood ammonia levels. Neomycin is actually the MOST nephrotoxic aminoglycoside when given systemically, which is why it is only used topically or orally (non-absorbed)."},
  {id:"final292",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which aminoglycoside has characteristics almost identical to gentamicin but has poor synergism with penicillin against enterococci?",options:["Amikacin","Erythromycin","Netilmycin","Spectinomycin","Tobramycin"],answer:4,explanation:"Tobramycin has an almost identical spectrum to gentamicin (both cover Pseudomonas aeruginosa well), but tobramycin does NOT provide synergism with penicillin against enterococci, unlike gentamicin or streptomycin. This distinction is clinically important for enterococcal endocarditis treatment."},
  {id:"final293",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"A 23-year-old pregnant woman with gonorrhea has a history of anaphylaxis to amoxicillin. You want single-dose treatment. Which drug is safest?",options:["Ceftriaxone","Ciprofloxacin","Doxycycline","Erythromycin","Spectinomycin"],answer:4,explanation:"In pregnancy with gonorrhea AND severe penicillin/beta-lactam allergy (anaphylaxis — high cross-reactivity risk with cephalosporins): spectinomycin single IM dose is safe in pregnancy. Ciprofloxacin is contraindicated in pregnancy (cartilage effects on fetus). Doxycycline is contraindicated in pregnancy (fetal bone/tooth effects). Ceftriaxone carries cross-reactivity risk with severe penicillin allergy."},
  {id:"final294",exam:"final",lecture:"Protein Synthesis Inhibitors",q:"Which statement about once-daily aminoglycoside dosing is NOT accurate?",options:["Dosage adjustment is less important in patients with renal insufficiency","It is convenient for outpatient therapy","It is often less toxic than conventional multiple-daily dosing","Less nursing time is required for drug administration","Underdosing is less of a problem with once-daily dosing"],answer:0,explanation:"Dosage adjustment is STILL REQUIRED with once-daily aminoglycoside dosing in patients with renal insufficiency, as drug still accumulates in renal failure regardless of dosing interval. Monitoring of drug levels and renal function remains essential. All other statements about once-daily dosing advantages are accurate."},
  {id:"final295",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which statement about sulfonamides is accurate?",options:["Cross-allergenicity occurs between sulfonamides and penicillins","Crystalluria due to sulfonamides is most likely to occur at high urinary pH","Kernicterus may occur in the newborn if sulfonamides are given late in pregnancy","Sulfonamides are bactericidal","Sulfonamides inhibit bacterial dihydrofolate reductase"],answer:2,explanation:"Sulfonamides displace bilirubin from albumin binding sites. The free bilirubin crosses the immature neonatal blood-brain barrier and deposits in basal ganglia causing kernicterus. Sulfonamides are BACTERIOSTATIC, inhibit dihydropteroate synthase (NOT dihydrofolate reductase — that is trimethoprim). Crystalluria occurs at LOW (acidic) pH. No cross-allergenicity with penicillins."},
  {id:"final296",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Trimethoprim-sulfamethoxazole is effective against which opportunistic infection in the AIDS patient?",options:["Disseminated herpes simplex","Cryptococcal meningitis","Oral candidiasis","Toxoplasmosis","Tuberculosis"],answer:3,explanation:"TMP-SMZ (co-trimoxazole) is used for both treatment and prophylaxis of Toxoplasma gondii encephalitis in AIDS patients. It is also first-line for PCP (Pneumocystis jiroveci pneumonia). Cryptococcal meningitis is treated with fluconazole; herpes simplex with acyclovir; candidiasis with fluconazole or nystatin; TB with RIPE regimen."},
  {id:"final297",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"A 24-year-old woman returns from vacation with traveler's diarrhea that has not responded to antidiarrheal drugs. A pathogenic gram-negative bacillus is suspected. Which drug is most likely effective?",options:["Amoxicillin","Ciprofloxacin","Sulfacetamide","Trimethoprim","Vancomycin"],answer:1,explanation:"Traveler's diarrhea (most commonly E. coli, Salmonella, Campylobacter, Shigella) that fails antidiarrheal therapy requires antibiotics. Ciprofloxacin is first-line (3-day course). TMP-SMX was previously standard but resistance is now widespread. Vancomycin is only active against gram-positive organisms and is not absorbed from the gut."},
  {id:"final298",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which statement about the clinical use of sulfonamides is FALSE?",options:["Effective in Rocky Mountain spotted fever in patients allergic to tetracyclines","Not effective as sole agents in the treatment of prostatitis","Resistance can occur because of increased production of PABA","Some resistant bacterial strains exhibit decreased intracellular accumulation of sulfonamides","Sulfonamides have activity against C. trachomatis and can be used topically for chlamydial eye infections"],answer:0,explanation:"Sulfonamides are NOT effective against Rickettsia (Rocky Mountain spotted fever) — they are actually contraindicated and may worsen rickettsial disease. Tetracyclines (doxycycline) are the treatment of choice; chloramphenicol is the alternative for severe cases or pregnancy."},
  {id:"final299",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"A 31-year-old man with gonorrhea and G6PD deficiency has possible accompanying C. trachomatis. Which drug is reliably effective against BOTH gonococci and C. trachomatis AND safe in G6PD deficiency?",options:["Cefixime","Ciprofloxacin","Spectinomycin","Sulfamethoxazole-trimethoprim","None of the above"],answer:4,explanation:"Cefixime covers gonococci but NOT chlamydia. Ciprofloxacin is not reliable for C. trachomatis. Spectinomycin covers gonococci but NOT chlamydia. TMP-SMZ is contraindicated in G6PD deficiency (causes hemolytic anemia). The correct dual therapy would be ceftriaxone plus azithromycin — but neither option in the list covers both organisms safely."},
  {id:"final300",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which statement about the fluoroquinolones is accurate?",options:["Antacids increase the oral bioavailability of fluoroquinolones","Gonococcal resistance to fluoroquinolones may involve changes in DNA gyrase","Modification of moxifloxacin dosage is required when CrCl is below 50 mL/min","A fluoroquinolone is the drug of choice for UTI in a 7-year-old girl","Fluoroquinolones are contraindicated in patients with hepatic dysfunction"],answer:1,explanation:"Fluoroquinolone resistance in N. gonorrhoeae occurs primarily through mutations in gyrA (DNA gyrase subunit A) and parC (topoisomerase IV). Antacids DECREASE fluoroquinolone absorption by chelation. Moxifloxacin is hepatically eliminated so no renal dose adjustment is needed. Fluoroquinolones are contraindicated in children due to arthropathy risk (not due to hepatic dysfunction)."},
  {id:"final301",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which statement about TMP-SMZ is FALSE?",options:["Fever and pancytopenia occur frequently in AIDS patients taking it","It is an alternative to ampicillin in treatment of listeriosis","It is effective in treatment of pneumonia caused by Pneumocystis jiroveci","The two drugs produce a sequential blockade of folic acid synthesis","TMP-SMZ is the drug combination of choice for community-acquired pneumonia"],answer:4,explanation:"TMP-SMZ is NOT the drug of choice for community-acquired pneumonia (CAP). CAP is treated with macrolides (azithromycin, clarithromycin) or respiratory fluoroquinolones (levofloxacin) as first-line agents. TMP-SMZ is used for PCP, UTIs, toxoplasmosis, and nocardiosis. All other statements are accurate."},
  {id:"final302",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which adverse effect is most likely to occur with sulfonamides?",options:["Fanconi's aminoaciduria syndrome","Hematuria","Kernicterus in the newborn","Neurologic dysfunction","Skin reactions"],answer:4,explanation:"The most COMMON adverse effects of sulfonamides are skin reactions — maculopapular rash, urticaria, photosensitivity, and rarely Stevens-Johnson syndrome. While crystalluria and kernicterus are significant adverse effects, skin reactions are the most frequently encountered in clinical practice."},
  {id:"final303",exam:"final",lecture:"Inhibitors of Nucleic Acid Synthesis",q:"Which drug is effective against nocardiosis and, combined with pyrimethamine, provides treatment and prophylaxis against toxoplasmosis in AIDS patients?",options:["Amoxicillin","Erythromycin","Levofloxacin","Sulfadiazine","Trimethoprim"],answer:3,explanation:"Sulfadiazine is a sulfonamide used for nocardiosis treatment and, combined with pyrimethamine, is the treatment for toxoplasmosis (Toxoplasma gondii encephalitis) in AIDS patients. Sulfadiazine blocks dihydropteroate synthase while pyrimethamine blocks dihydrofolate reductase, producing sequential folate pathway blockade."},
  {id:"final304",exam:"final",lecture:"Antifungal Drugs",q:"Which statement about fluconazole is accurate?",options:["It is an inducer of hepatic drug-metabolizing enzymes","It does not penetrate the blood-brain barrier","It is highly effective in treatment of aspergillosis","It has the least effect of all azoles on hepatic drug metabolism","Oral bioavailability is less than that of ketoconazole"],answer:3,explanation:"Among the azoles, fluconazole inhibits CYP2C9 and CYP3A4 but to a LESSER degree than ketoconazole (the most potent CYP inhibitor). Fluconazole has excellent oral bioavailability (~90%) and DOES penetrate the CSF well. It is NOT effective against Aspergillus (voriconazole is first-line for aspergillosis)."},
  {id:"final305",exam:"final",lecture:"Antifungal Drugs",q:"Both blood and urine cultures from a hospitalized patient grew Candida albicans. The best course of action is:",options:["Continue current antibiotics and start amphotericin B","Continue current antibiotics and start flucytosine","Continue current antibiotics and start griseofulvin","Stop current antibiotics and start amphotericin B","Stop current antibiotics and start ketoconazole"],answer:3,explanation:"Candidemia (Candida in bloodstream) requires: (1) removal of predisposing factors — stop unnecessary broad-spectrum antibiotics that promote fungal overgrowth, and (2) systemic antifungal therapy — IV amphotericin B (or fluconazole/echinocandin). Both blood AND urine cultures positive indicates systemic candidiasis."},
  {id:"final306",exam:"final",lecture:"Antifungal Drugs",q:"Before administering an amphotericin B infusion, the patient should be pre-medicated with:",options:["Diphenhydramine only","Ibuprofen only","Prednisone only","Any or all of the above","None of the above"],answer:3,explanation:"Amphotericin B infusion-related reactions (fever, chills, nausea, hypotension, rigors) are common. Pre-medication regimen includes: acetaminophen or ibuprofen (antipyretic/anti-inflammatory), diphenhydramine (antihistamine), and hydrocortisone or prednisone (for severe reactions). All listed agents are used in pre-medication protocols."},
  {id:"final307",exam:"final",lecture:"Antifungal Drugs",q:"Candida is a major cause of nosocomial bloodstream infection. In most patients, this opportunistic fungal infection could best have been prevented by:",options:["Caspofungin prophylaxis","Fluconazole prophylaxis","Nystatin prophylaxis","Posaconazole prophylaxis","None of the above"],answer:4,explanation:"Antifungal prophylaxis for candidemia is not universally recommended in general hospitalized patients. The most effective prevention of candidemia is reduction of risk factors (central venous catheters, broad-spectrum antibiotics, immunosuppression) rather than antifungal prophylaxis, which is reserved for specific high-risk populations."},
  {id:"final308",exam:"final",lecture:"Antifungal Drugs",q:"A patient with newly diagnosed coccidioidomycosis should be treated immediately with:",options:["Amphotericin B","Caspofungin","Itraconazole","Terbinafine","None of these drugs"],answer:4,explanation:"Mild pulmonary coccidioidomycosis in an immunocompetent patient is typically SELF-LIMITED and does not require immediate treatment — the infection resolves spontaneously in most cases. Treatment is only indicated for severe, disseminated, or progressive disease. Itraconazole or fluconazole are used when treatment IS indicated."},
  {id:"final309",exam:"final",lecture:"Antifungal Drugs",q:"Which is the drug of choice for persistent lung lesions or disseminated disease caused by Coccidioides immitis?",options:["Amphotericin B","Itraconazole","Ketoconazole","Micafungin","Terbinafine"],answer:1,explanation:"For non-meningeal disseminated coccidioidomycosis (persistent pulmonary lesions, bone/joint), itraconazole is a first-line option (along with fluconazole). Itraconazole is preferred for skeletal and soft tissue disease. Fluconazole is preferred for coccidioidal meningitis (better CNS penetration). Amphotericin B is reserved for severe/rapidly progressive disease. Ketoconazole, micafungin, and terbinafine are not used for coccidioidomycosis."},
  {id:"final310",exam:"final",lecture:"Antifungal Drugs",q:"Which statement about flucytosine is accurate?",options:["It is bioactivated by fungal cytosine deaminase","It does not cross the blood-brain barrier","It inhibits cytochrome P450 enzymes","It is useful as a sole agent in esophageal candidiasis","It has a wide spectrum of antifungal activity"],answer:0,explanation:"Flucytosine is a prodrug: fungal cytosine deaminase converts it to 5-fluorouracil (5-FU), then to FdUMP, which inhibits thymidylate synthase and blocks DNA synthesis. This activation occurs ONLY in fungal cells (mammalian cells lack cytosine deaminase). Flucytosine has a NARROW spectrum (mainly Candida and Cryptococcus) and excellent CNS penetration."},
  {id:"final311",exam:"final",lecture:"Antifungal Drugs",q:"Serious cardiac effects (QT prolongation, torsades de pointes) have occurred when which antifungal was taken with antihistamines astemizole or terfenadine?",options:["Amphotericin B","Griseofulvin","Ketoconazole","Terbinafine","Voriconazole"],answer:2,explanation:"Ketoconazole is a potent CYP3A4 inhibitor that inhibits metabolism of terfenadine and astemizole, causing these antihistamines to accumulate and block cardiac hERG potassium channels, leading to QT prolongation and potentially fatal torsades de pointes. This interaction contributed to the withdrawal of terfenadine and astemizole from many markets."},
  {id:"final312",exam:"final",lecture:"Antifungal Drugs",q:"Which drug is most appropriate for oral use in treatment of vaginal candidiasis?",options:["Clotrimazole","Griseofulvin","Fluconazole","Flucytosine","Nystatin"],answer:2,explanation:"Oral fluconazole (150 mg single dose) is the drug of choice for vaginal candidiasis — highly effective, convenient single oral dose, and well absorbed. Clotrimazole and nystatin are topical preparations. Griseofulvin has no antifungal activity against Candida (only dermatophytes). Flucytosine alone causes rapid resistance development."}
];
const ALL_Q = [...MID1_QUESTIONS, ...MID2_QUESTIONS, ...FINAL_QUESTIONS];

/* ── Helpers ── */

/** Remove parenthetical hints from option display text */
function stripHint(s: string): string {
  return s.replace(/\s*\([^)]+\)\s*/g, " ").replace(/\s+/g, " ").trim();
}

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function getPool(f: Filter): Question[] {
  if (f === "all")   return ALL_Q;
  if (f === "mid1")  return MID1_QUESTIONS;
  if (f === "mid2")  return MID2_QUESTIONS;
  return FINAL_QUESTIONS;
}

function getLectures(pool: Question[]): string[] {
  const seen = new Set<string>();
  const out: string[] = [];
  for (const q of pool) {
    if (!seen.has(q.lecture)) { seen.add(q.lecture); out.push(q.lecture); }
  }
  return out;
}

/* ── localStorage ── */
const LS_SEEN = "pharma_seen_ids";
const LS_HIST = "pharma_history";

function loadSeen(): Set<string> {
  try { return new Set(JSON.parse(localStorage.getItem(LS_SEEN) || "[]")); }
  catch { return new Set(); }
}
function saveSeen(s: Set<string>) {
  try { localStorage.setItem(LS_SEEN, JSON.stringify([...s])); } catch {}
}

type HistoryEntry = {
  date: string; score: number; total: number; pct: number; label: string;
};
function loadHistory(): HistoryEntry[] {
  try { return JSON.parse(localStorage.getItem(LS_HIST) || "[]"); } catch { return []; }
}
function saveHistory(h: HistoryEntry[]) {
  try { localStorage.setItem(LS_HIST, JSON.stringify(h.slice(-100))); } catch {}
}

